	&lt;TD class="tr13 td30"&gt;&lt;SPAN class="p70 ft15"&gt;3.2&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr13 td31"&gt;&lt;SPAN class="p20 ft15"&gt;Politiska utgångspunkter&lt;/SPAN&gt; &lt;/TD&gt;
