	&lt;TD class="tr14 td29"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD colspan=2 class="tr14 td32"&gt;&lt;SPAN class="p70 ft17"&gt;Förändrat medielandskap – nya villkor för radio och tv i allmän-&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD class="tr7 td29"&gt;&lt;SPAN class="p18 ft18"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD colspan=2 class="tr7 td32"&gt;&lt;SPAN class="p70 ft19"&gt;hetens tjänst&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD class="tr15 td29"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD colspan=2 class="tr15 td32"&gt;&lt;SPAN class="p70 ft2"&gt;Medielandskapet är under stark förändring. Tillgången till medier är&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD class="tr6 td29"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD colspan=2 class="tr6 td32"&gt;&lt;SPAN class="p70 ft5"&gt;avsevärt större än tidigare, och utvecklingen drivs konstant framåt av&lt;/SPAN&gt; &lt;/TD&gt;
