	&lt;TD class="tr2 td35"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr2 td36"&gt;&lt;SPAN class="p96 ft2"&gt;och &lt;NOBR&gt;tv-lagen.&lt;/NOBR&gt; I dessa förarbeten angavs som exempel på villkor som&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
