	&lt;TD rowspan=2 class="tr11 td35"&gt;&lt;SPAN class="p98 ft2"&gt;18&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr6 td36"&gt;&lt;SPAN class="p96 ft2"&gt;visning eller uppbyggnad av lokalredaktioner. Det kan enligt utskottets&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD class="tr12 td36"&gt;&lt;SPAN class="p18 ft16"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
