&lt;TR&gt;
	&lt;TD colspan=2 class="tr6 td52"&gt;&lt;SPAN class="p131 ft5"&gt;användning av olika distributionsformer samt publikens tillgång till&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr6 td47"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD colspan=2 class="tr2 td52"&gt;&lt;SPAN class="p131 ft2"&gt;utrustning för att tillgodogöra sig utbudet. Kärnverksamheten och den&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr2 td47"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD colspan=2 class="tr2 td52"&gt;&lt;SPAN class="p131 ft2"&gt;kompletterande verksamheten ska kunna tas emot av allmänheten i&lt;/SPAN&gt; &lt;/TD&gt;
