	&lt;TD class="tr2 td36"&gt;&lt;SPAN class="p18 ft2"&gt;regeringen beslutade om fördelning av sändningsutrymme för digital&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr2 td44"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD class="tr2 td36"&gt;&lt;SPAN class="p18 ft2"&gt;ljudradio. SR inledde då digitala sändningar i &lt;NOBR&gt;T-DAB.&lt;/NOBR&gt; De kommersiella&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr2 td44"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD class="tr6 td36"&gt;&lt;SPAN class="p18 ft2"&gt;programföretagen valde att inte sända digital radio eftersom de inte&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr6 td44"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
