&lt;TR&gt;
	&lt;TD colspan=2 class="tr6 td56"&gt;&lt;SPAN class="p18 ft5"&gt;Kommittén föreslår även att resultatet av arbetet ska följas upp efter&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr6 td47"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD colspan=2 class="tr2 td56"&gt;&lt;SPAN class="p18 ft2"&gt;halva tillståndsperioden.&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr2 td47"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
