	&lt;TD colspan=2 class="tr2 td56"&gt;&lt;SPAN class="p72 ft3"&gt;&lt;SPAN class="ft17"&gt;Remissinstanserna: &lt;/SPAN&gt;Statskontoret&lt;SPAN class="ft2"&gt;, &lt;/SPAN&gt;Stockholms universitet&lt;SPAN class="ft2"&gt;, &lt;/SPAN&gt;Institutet&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr2 td47"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
