	&lt;TD colspan=2 class="tr6 td56"&gt;&lt;SPAN class="p18 ft3"&gt;för språk och folkminnen&lt;SPAN class="ft2"&gt;, &lt;/SPAN&gt;Public servicerådet &lt;SPAN class="ft2"&gt;och &lt;/SPAN&gt;Bonnier AB &lt;SPAN class="ft2"&gt;tillstyrker&lt;/SPAN&gt;&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr6 td47"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
