	&lt;TD colspan=2 class="tr2 td56"&gt;&lt;SPAN class="p18 ft2"&gt;förslaget. &lt;NOBR&gt;&lt;SPAN class="ft3"&gt;Film&amp;TV-Producenterna&lt;/SPAN&gt;&lt;/NOBR&gt;&lt;SPAN class="ft3"&gt; &lt;/SPAN&gt;är positiva till en tydligare redovis-&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr2 td47"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
