	&lt;TD colspan=2 class="tr2 td56"&gt;&lt;SPAN class="p18 ft2"&gt;ning och en större öppenhet kring SVT:s intäkter, och understryker&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr2 td47"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD colspan=2 class="tr6 td56"&gt;&lt;SPAN class="p18 ft5"&gt;behovet av att andelen extern utveckling redovisas. &lt;SPAN class="ft21"&gt;TV4 AB &lt;/SPAN&gt;anser att&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr6 td47"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
