	&lt;TD colspan=5 class="tr15 td36"&gt;&lt;SPAN class="p18 ft2"&gt;Granskningsnämnden för radio och tv – som är ett särskilt beslutsorgan&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr15 td44"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD colspan=5 class="tr6 td36"&gt;&lt;SPAN class="p18 ft2"&gt;inom Myndigheten för radio och tv – har som sin centrala uppgift att&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr6 td44"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
