	&lt;TD class="tr31 td83"&gt;&lt;SPAN class="p18 ft2"&gt;eller tv&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD colspan=3 class="tr31 td85"&gt;&lt;SPAN class="p18 ft2"&gt;eller tillhandahållits i &lt;NOBR&gt;beställ-tv&lt;/NOBR&gt; överensstämmer&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr31 td79"&gt;&lt;SPAN class="p194 ft2"&gt;med före-&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr31 td44"&gt;&lt;SPAN class="p19 ft2"&gt;99&lt;/SPAN&gt; &lt;/TD&gt;
