	&lt;TD class="tr2 td34"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD class="tr2 td33"&gt;&lt;SPAN class="p18 ft2"&gt;följningen av programföretagens utbud på internet är, enligt vår bedöm-&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr2 td34"&gt;&lt;SPAN class="p18 ft6"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
