							&lt;span style="font-family:'Verdana'; font-size:16pt; -aw-sdt-tag:ccRiksmote; -aw-sdt-title:'riksmote Dokumentegenskap'"&gt;2017/18&lt;/span&gt;&lt;span style="font-family:'Verdana'; font-size:16pt; -aw-sdt-tag:ccKolon; -aw-sdt-title:Kolon"&gt;:&lt;/span&gt;&lt;a name="Utskottebeteckning"&gt;&lt;/a&gt;&lt;span style="font-family:'Verdana'; font-size:16pt"&gt;KU33&lt;/span&gt;
