			&lt;p class="DokumentRubrik" style="-aw-sdt-tag:ccDokumentrubrik; -aw-sdt-title:'dokumentrubrik Dokumentegenskap'"&gt;
				&lt;span&gt;Kommunala och regionala frågor&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Sammanfattning"&gt;
				&lt;span class="tSidrubrikJA"&gt;Sammanfattning&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet föreslår ett tillkännagivande om kommunernas roll i det brottsföre&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;byggande arbetet. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet föreslår att riksdagen avslår övriga motionsyrkanden som gäller frågor om lokaliseringsprincipen, kommunal samverkan, representation i styrelsen, nämnder och utskott, byte av partitillhörighet, ersättare i full&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;mäktige, villkoren för förtroendevalda, partistöd, fullmäktigesammanträden på måndagar, medborgerlig förslagsrätt, budgetprocessen, revision, kommun&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;indelning, regionalisering, en likvärdig välfärd i hela landet, kommunala bidrag till trossamfund, lokalt brottsförebyggande arbete och pensionärsråd.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I betänkandet finns sex reservationer (SD, C, KD&lt;/span&gt;&lt;span&gt;, -&lt;/span&gt;&lt;span&gt;).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span style="font-style:italic"&gt;Behandlade förslag&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Cirka 40 motionsyrkanden från allmänna motionstiden &lt;/span&gt;&lt;span&gt;2016/17&lt;/span&gt;&lt;span&gt; och &lt;/span&gt;&lt;span&gt;2017/18&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent" style="text-indent:0pt"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Innehllsfrteckning"&gt;
