			&lt;p class="Avsnittsrubrik"&gt;
				&lt;a name="_Toc510603136"&gt;&lt;/a&gt;&lt;a name="SlutUtskottsForslag"&gt;&lt;/a&gt;&lt;span class="tSidrubrikJA"&gt;Redogörelse för ärendet&lt;/span&gt;&lt;span style="-aw-bookmark-end:_Toc510603136"&gt;&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2&gt;
				&lt;a name="_Toc510603137"&gt;&lt;span&gt;Ärendet och dess beredning&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;p&gt;
				&lt;span&gt;I betänkandet behandlar utskottet&lt;/span&gt;&lt;span&gt; ca 40 motionsyrkanden &lt;/span&gt;&lt;span&gt;om kommunala och regionala frågor från allmänna motions&lt;/span&gt;&lt;span&gt;tiden &lt;/span&gt;&lt;span&gt;2016/17&lt;/span&gt;&lt;span&gt; och &lt;/span&gt;&lt;span&gt;2017/18&lt;/span&gt;&lt;span&gt;. Motions&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;yrkandena gäller frågor om&lt;/span&gt;&lt;span&gt; lokaliseringsprincipen, kommunal samverkan, representation i styrelsen, nämnder&lt;/span&gt;&lt;span&gt; och utskott, byte av partitill&lt;/span&gt;&lt;span&gt;hörighet, ersättare i fullmäktige, villkoren för förtroendevalda, partistöd, fullmäktige&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;sammanträden på måndagar, me&lt;/span&gt;&lt;span&gt;dborgerlig förslagsrätt, budget&lt;/span&gt;&lt;span&gt;processen, revision, kommunindelning, regionalisering, en likvärdig välfärd i hela landet, kommunala bidrag till trossamfund, lokalt brottsförebyggande arbete och pensionärsråd.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Avsnittsrubrik"&gt;
				&lt;a name="_Toc510603138"&gt;&lt;span class="tSidrubrikJA"&gt;Utskottets överväganden&lt;/span&gt;&lt;/a&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:bee567e9-7a30-46e4-b367-686f9c8a000f/förslagsrutor/1484841431/1515681690625; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603139"&gt;&lt;span&gt;Lokaliseringsprincipen och kommunal samverkan&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603139"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;avslår motionsyrkanden om kommunal samverkan&lt;/span&gt;&lt;span&gt; och om undantag från lokaliserings&lt;/span&gt;&lt;span&gt;principen för att möjliggöra ut&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;byggnad av bredband över kommun&lt;/span&gt;&lt;span&gt;gränser.&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalrutaindrag" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt; -aw-sdt-tag:'bee567e9-7a30-46e4-b367-686f9c8a000f/förslagsrutor reservations text/1471183922/1521719753755'; -aw-sdt-title:'förslagsrutor reservations text'"&gt;
					&lt;span&gt;Jämför reservation 1 (KD).&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="R3" style="margin-bottom:0pt"&gt;
				&lt;span&gt;Motionerna&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;I flera motioner begärs ändringar i kommunallagen så att lokaliserings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;principen inte hindrar utbyggnaden av bredband över kommungränser. Sådana yrkanden f&lt;/span&gt;&lt;span&gt;inns i &lt;/span&gt;&lt;span&gt;kommittémotion 2017/18:3766 av Robert Halef m.fl. (KD) yrkande 58&lt;/span&gt;&lt;span&gt; och &lt;/span&gt;&lt;span&gt;motionerna 2017/18:2256&lt;/span&gt;&lt;span&gt; av Anette Åkesson m.fl. (M)&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;yrkande 4, 2017/18:3672 av Camilla Waltersson Grönvall och Maria St&lt;/span&gt;&lt;span&gt;ockhaus &lt;/span&gt;&lt;span&gt;(båda M)&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;samt&lt;/span&gt;&lt;span&gt; 2017/18:1413 av Johanna Haraldsson m.fl. (S).&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Motionärerna anför att samhället blir alltmer beroende av goda uppkopplings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;möjlighete&lt;/span&gt;&lt;span&gt;r. Kommunallagens lokaliserings&lt;/span&gt;&lt;span&gt;princip hindrar fiberutbyggnad över kommungränser&lt;/span&gt;&lt;span&gt;na, med ökade kost&lt;/span&gt;&lt;span&gt;nader eller utebliven utbyggnad som följd.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I &lt;/span&gt;&lt;span&gt;kommittém&lt;/span&gt;&lt;span&gt;otion 2017/18:3855 av Eskil Erlandsson m.fl. (C) &lt;/span&gt;&lt;span&gt;yrkande 20&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;begärs att nya former av kommunala samarbeten ska underlättas för att förbättra invånarnas service och stärka det demokra&lt;/span&gt;&lt;span&gt;tiska inflytandet för medborgarna&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Lokaliseringsprincipen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Av 2 kap. 1 § kommunallagen (&lt;/span&gt;&lt;span&gt;2017:725&lt;/span&gt;&lt;span&gt;) följer att en kommuns eller ett landstings åtgärd måste vara knuten till kommunens respektive landstingets eget område eller dess medlemmar (l&lt;/span&gt;&lt;span&gt;okaliseringsprincipen).&lt;/span&gt;&lt;span&gt; Enligt&lt;/span&gt;&lt;span&gt; 2 § i samma kapitel &lt;/span&gt;&lt;span&gt;får&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;kommuner och landsting inte &lt;/span&gt;&lt;span&gt;ha hand om sådana angelägen&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;heter som enbart staten, en annan kommun, ett annat landsting eller någon annan ska ha hand om.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Lokaliseringsprincipen &lt;/span&gt;&lt;span&gt;syftar bl.a. till att hindra kommuner och landsting från att konkurrera&lt;/span&gt;&lt;span&gt; med verksamhet utanför det egna området&lt;/span&gt;&lt;span&gt; genom att sälja&lt;/span&gt;&lt;span&gt; tjänster till andra kommuner eller landsting.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Lokaliseringsprincipen är inte absolut utan måste bedömas från fall till&lt;/span&gt;&lt;span&gt; fall. Detta hänger samman med att faktorer som befolkningens rörlighet och ofullkomligheter i kommunindel&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;ningen innebär att en åtgärd kan ha anknytning till medlemmarna även om åtgär&lt;/span&gt;&lt;span&gt;den som sådan inte vidtas&lt;/span&gt;&lt;span&gt; i kommunen. Det finns alltså inget förbud mot att en kommun eller ett landsting engagerar sig i markinnehav och anläggningar inom en annan kommuns eller landstings område förutsatt att dessa anordningar behövs för den egna kommunen eller landstinget (p&lt;/span&gt;&lt;span&gt;rop. 2016/17:171&lt;/span&gt;&lt;span&gt; s. 299 f.). U&lt;/span&gt;&lt;span&gt;ndantag från lokaliseringsprincipen &lt;/span&gt;&lt;span&gt;finns också &lt;/span&gt;&lt;span&gt;i speciallagstiftning, t.ex. &lt;/span&gt;&lt;span&gt;i 7 kap. 1 § ellagen (1997:857) som anger att bl.a. kommu&lt;/span&gt;&lt;span&gt;nala energibolag utan hinder av &lt;/span&gt;&lt;span&gt;lokaliseringsprincipen får bedriva elproduktion och e&lt;/span&gt;&lt;span&gt;lhandel samt viss &lt;/span&gt;&lt;span&gt;nätverksamhet&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Kommunal samverkan&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Kommunal samverkan kan i dag förekomma i offentligrättslig form genom kommunalförbund och gemensamma nämnder, samt i privaträttslig form genom olika former av samverkansavtal. En stor översyn av möjligheterna till kommunal samverkan gjordes i mitten av 1990-talet (prop. 1996/97:105). Genom denna reform skapades bl.a. möjligheten till gemensamma nämnder. Kommunalförbundsreglerna förenklades, och bestämmelserna om kommunal&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;förbund togs in i kommunallagen. Frågan om samverkan har därefter utretts vid flera tillfällen utan att det resulterat i några lagändringar (se SOU 2007:72 och SOU 2012:30). Statskontoret har på regeringens uppdrag analyserat behovet av ytterligare samverkan genom avtal inom kommunsektorn. Uppdraget redovisas i rapporten Kommunal avtalssamverkan (2016:23).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Kommunutredningen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Regeringen gav i februari 2017 en parlamentarisk kommitté i uppdrag att utarbeta en strategi för att stärka kommunernas kapacitet att fullgöra sina uppgifter och möta de utmaningar som följer bl.a. av den demografiska utvecklingen och den snabba urbaniseringstakten (Fi 2017:02, dir. 2017:13). &lt;/span&gt;&lt;span&gt;Kommittén&lt;/span&gt;&lt;span&gt;, &lt;/span&gt;&lt;span&gt;som har antagit namnet Kommunutredningen,&lt;/span&gt;&lt;span&gt; ska utifrån kommunernas varierande förutsättningar dels identifiera och analysera de utmaningar som väntas ha särskilt stor påverkan&lt;/span&gt;&lt;span&gt; på kommunern&lt;/span&gt;&lt;span&gt;as förmåga att klara av &lt;/span&gt;&lt;span&gt;sina uppgifter, dels analysera i vilken utsträckning som &lt;/span&gt;&lt;span&gt;bl.a. kommunal samverkan&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;kan bidra till att stärka kommunern&lt;/span&gt;&lt;span&gt;as förmåga att möta samhällsutvecklingen. &lt;/span&gt;&lt;span&gt;Kommittén fick även i uppdrag att utreda förutsätt&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;ningarna för att ge kommunerna generella möjligheter att avtalssamverka. &lt;/span&gt;&lt;span&gt;Uppdraget ska slutredovisas senast den 15&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;oktober 2019.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Den del av uppdraget&lt;/span&gt;&lt;span&gt; som avser avtalssamverkan&lt;/span&gt;&lt;span&gt; redovisades i oktober 2017 i delbetänkandet En generell rätt till kommunal avtalssamverkan (SOU 2017:77). Kommittén föreslår att det i kommunallagen ska in&lt;/span&gt;&lt;span&gt;föras en generell möjlighet att&lt;/span&gt;&lt;span&gt; avtalss&lt;/span&gt;&lt;span&gt;amverka&lt;/span&gt;&lt;span&gt;. Den nya bestämmelsen&lt;/span&gt;&lt;span&gt; innebär att en kommun eller ett landsting får träffa avtal om att dess uppgifter helt eller delvis ska utföras av en annan kommun eller ett annat landsting. Genom ett sådant avtal får en kommun eller ett landsting utföra uppgifter åt en annan kommun eller ett landsting utan hinder av lokaliseringsprincipen. Denna rätt innebär alltså ett generellt undantag från lokaliseringsprincipen för kommunala samverkans&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;avtal. Några ändringar av övriga regler som styr de kommunala befogen&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;heterna föreslås inte. Det som kommuner och landsting vill samverka kring måste därför även fortsättningsvis falla inom befogenheten för samtliga samverkande kommuner och landsting.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Regeringen fö&lt;/span&gt;&lt;span&gt;reslår i proposition 2017/18:&lt;/span&gt;&lt;span&gt;151&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;En generell rätt till kommunal avtalssamverkan&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;att en kommun eller ett landsting ska få ingå avtal om att dess uppgifter helt eller delvis ska utföras av en annan kommun eller ett a&lt;/span&gt;&lt;span&gt;nnat landsting&lt;/span&gt;&lt;span&gt;. Genom ett sådant avtal får en&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;kommun eller ett landsting utföra uppgifter åt en annan kommun eller&lt;/span&gt;&lt;span&gt; ett annat landsting&lt;/span&gt;&lt;span&gt; utan &lt;/span&gt;&lt;span&gt;hinder av &lt;/span&gt;&lt;span&gt;lo&lt;/span&gt;&lt;span&gt;kaliseringsprincipen&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; Ändringarna föreslås träda i kraft den 1 juli 2018.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utredningen om utvärdering av bredbandsstrategin&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Frågan om lokaliseringsprincipen och ett eventuellt behov av undantag för att underlätta utbyggnaden av fiberinfrastruktur berördes av Utredningen om utvärdering av bredbandsstrategin i betänkandet Bredband för Sverige in i framtiden (SOU 2014:21). Utredningen anser att utbyggnaden av bredbands-infrastruktur med hög överföringshastighet behöver stimuleras om regeringens bredbandsmål ska nås. Det skulle enligt utredningen eventuellt kunna gynna utbyggnaden om ett undantag från lokaliseringsprincipen införs i lagen &lt;/span&gt;&lt;span&gt;(2009:47)&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;om vissa kommunala befogenheter. Eftersom utredningen inte&lt;/span&gt;&lt;span&gt; har&lt;/span&gt;&lt;span&gt; haft möjlighet att utreda alla de frågeställningar som behöver besvaras för att bedöma alla konsekvenser av ett sådant undantag anser den att regeringen skyndsamt ska ta initiativ till att utreda möjligheterna och konsekvenserna av att göra ett undantag från lokaliseringsprincipen för kommuner vad gäller ut&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;byggnad av infrastruktur för bredband m&lt;/span&gt;&lt;span&gt;ed hög överföringshastighet (s.&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;144).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Regeringens bredbandsstrategi&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Regeringen presenterade i december 2016 en ny bredbandsstrategi: Sverige helt uppkopplat 2025 – en bredbandsstrategi. Målet för tillgången till snabbt bredband i hela Sverige innebär att 95 procent av alla hushåll senast 2020 bör ha tillgång till bredband om minst 100 Mbit/s. På något längre sikt innebär målet att senast 2025 bör 98 procent av hushållen ha tillgång till bredband om&lt;/span&gt;&lt;span&gt; minst 1 Gbit/s, 1,9 procent ha tillgång till minst 100 Mbit/s och 0,1 procent tillgång till minst 30 Mbit/s.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;För att uppnå målen behövs enligt regeringen nya aktiviteter på flera områden. Det behöver bli tydligare hur olika aktörer på bredbandsmarknaden bör förhålla sig till varandra och hur bredbandsutbyggnaden påverkas av deras inbördes förhållande. Utbyggnaden måste göras smidigare och underlättas på flera sätt för att skapa förutsättningar för en ökad kostnadseffektivitet. Det måste skapas förutsättningar för att utbyggnaden ska kunna nå allt fler människor och saker där dessa befinner sig.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Regeringen gav den 8 juni 2017 &lt;/span&gt;&lt;span&gt;Post- och telestyrelsen i uppdrag att, inom ramen för ett uppdrag som gäller kommunernas roll i arbetet med utbyggnaden av bredbandsnäten, se över möjligheterna till undantag från lokaliserings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;principen.&lt;/span&gt;&lt;span&gt; Uppdraget &lt;/span&gt;&lt;span&gt;ska redovisas senast den 30 juni 2018&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Kommunutredningen &lt;/span&gt;&lt;span&gt;föreslår&lt;/span&gt;&lt;span&gt;, som &lt;/span&gt;&lt;span&gt;framgår ovan&lt;/span&gt;&lt;span&gt;, a&lt;/span&gt;&lt;span&gt;tt kommuner och landsting ska få en generell möjlighet att &lt;/span&gt;&lt;span&gt;avtalssamverka. F&lt;/span&gt;&lt;span&gt;örslag&lt;/span&gt;&lt;span&gt;et&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;omfattar även bredbandsutbyggnad. &lt;/span&gt;&lt;span&gt;Utredningen konstaterar &lt;/span&gt;&lt;span&gt;att den större frågan &lt;/span&gt;&lt;span&gt;om lokaliseringsprincipen generellt bör undantas för bredbandsutbyggnad, dvs. utan att det sker genom samverkan i avtalsform, &lt;/span&gt;&lt;span&gt;är föremål för utredning &lt;/span&gt;&lt;span&gt;av Post- och telestyrelsen&lt;/span&gt;&lt;span&gt; (SOU 2017:77 s. 224)&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Riksrevisionen har i rapporten Bredband i världsklass? – Regeringens insatser för att uppfylla det bredbandspolitiska målet (RiR 2017:13) bl.a. gjort &lt;/span&gt;&lt;span&gt;iakttagelsen att Sverige är ett av de länder i världen där hushåll och företag har högst tillgå&lt;/span&gt;&lt;span&gt;ng till internet&lt;/span&gt;&lt;span&gt; via bred&lt;/span&gt;&lt;span&gt;band, men att det finns skillnader mellan stad och landsbygd.&lt;/span&gt;&lt;span&gt; Av regeringens skrivelse 2017/18:54 Riksrevisionens rapport om regeringens insatser för att uppfylla det bredbandspolitiska målet framgår att&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;r&lt;/span&gt;&lt;span&gt;egeringen instämmer i Riksrevisionens iakttagelse. Regeringen &lt;/span&gt;&lt;span&gt;redogör för vissa&lt;/span&gt;&lt;span&gt; åtgärder som vidtagits efter det att Riksrevisionen inlett sin granskning&lt;/span&gt;&lt;span&gt;, bl.a. det &lt;/span&gt;&lt;span&gt;ovan&lt;/span&gt;&lt;span&gt;nämnda uppdraget till &lt;/span&gt;&lt;span&gt;Post- och telestyrelsen&lt;/span&gt;&lt;span&gt;, och anger att den avser att avvakta resultaten av &lt;/span&gt;&lt;span&gt;åtgärderna&lt;/span&gt;&lt;span&gt; för att sedan utvärdera behovet av ytterligare åtgärder.&lt;/span&gt;&lt;span&gt; Skrivelsen behandlas av trafikutskottet i&lt;/span&gt;&lt;span&gt; betänkande 2017/18:TU9&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;T&lt;/span&gt;&lt;span&gt;idigare behandling&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Trafikutskottet har tidigare berett ett flertal motionsyrkanden&lt;/span&gt;&lt;span&gt; om &lt;/span&gt;&lt;span&gt;undantag&lt;/span&gt;&lt;span&gt; från lokaliseringsprincipen vid&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;bredbandsutbyggnad&lt;/span&gt;&lt;span&gt;. Trafikutskottet kon&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;staterade senast (bet. 2015/16:TU19 s. 36) att frågan om ett undantag från lokaliseringsprincipen för att underlätta utbyggnaden av kommunal fiber&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;infrastruktur behandlats av den nämnda Utredningen om utvärdering av bredbandsstrategin och att&lt;/span&gt;&lt;span&gt; utred&lt;/span&gt;&lt;span&gt;ningens förslag bereddes inom Regerings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;kansliet. Trafikutskottet fann det angeläget att så många hushåll som möjligt får tillgång till någon form av fiberanslutning och förutsatte att frågan&lt;/span&gt;&lt;span&gt; om undantag från lokaliserings&lt;/span&gt;&lt;span&gt;principen beaktades noggrant av regeringen i översynen av politiken på området för att bestämmelsen inte ska få verka som hämsko för den fortsatta utbyggnaden av kommunala fibernät. Trafikutskottet konstaterade också att utredningen påpekat att det redan finns u&lt;/span&gt;&lt;span&gt;ndantag för de kommunala energi&lt;/span&gt;&lt;span&gt;bolagen som skulle kunna utsträckas till de kommunala stadsnäten.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Motionsyrkandena avstyrktes. &lt;/span&gt;&lt;span&gt;En reservation lämnades (M, C, L, KD)&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Liknande motionsyrkanden behandlades även av konstitutionsutskottet i betänkande &lt;/span&gt;&lt;span&gt;2016/17:KU17&lt;/span&gt;&lt;span&gt;. U&lt;/span&gt;&lt;span&gt;tskottet &lt;/span&gt;&lt;span&gt;uttalade då att det är &lt;/span&gt;&lt;span&gt;mycket angeläget att så många hushåll som möjligt har tillgång till snabbt bredband&lt;/span&gt;&lt;span&gt; och att det &lt;/span&gt;&lt;span&gt;krävs ett flertal olika åtgärder&lt;/span&gt;&lt;span&gt; f&lt;/span&gt;&lt;span&gt;ör att bredbandsstrategin ska uppnås&lt;/span&gt;&lt;span&gt;. Utskottet konstaterade&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;även &lt;/span&gt;&lt;span&gt;att regeringen beslutat att ge Post- och telestyrelsen i uppdrag att se över förutsättningarna för undantag från lokaliseringsprincipen vid bredbandsutbyggnad. Motionsyrkandena&lt;/span&gt;&lt;span&gt; avstyrktes med hänvisning till att de i huvudsak fick&lt;/span&gt;&lt;span&gt; anses tillgodosed&lt;/span&gt;&lt;span&gt;da genom detta uppdrag&lt;/span&gt;&lt;span&gt; (s. 13)&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Även frågan om &lt;/span&gt;&lt;span&gt;nya former av kommunala samarbeten&lt;/span&gt;&lt;span&gt; har tidigare behandlats av konstitutionsutskottet, senast i &lt;/span&gt;&lt;span&gt;samband med behandlingen av &lt;/span&gt;&lt;span&gt;regeringens proposition 2016/17:171 En ny kommunallag&lt;/span&gt;&lt;span&gt;. Utskottet ansåg &lt;/span&gt;&lt;span&gt;att det pågående utredningsarbetet om avtalssamverkan inte borde föregripas och avstyrkte motionsyrkandena&lt;/span&gt;&lt;span&gt; (bet. &lt;/span&gt;&lt;span&gt;2016/17:KU30&lt;/span&gt;&lt;span&gt; s&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; 60).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Regeringen&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;föreslår &lt;/span&gt;&lt;span&gt;i proposition 2017/18:151&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;att det i kommunallagen ska införas en generell möjlighet att avtalssamverka&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;I K&lt;/span&gt;&lt;span&gt;ommunutredningens fortsatta &lt;/span&gt;&lt;span&gt;arbete &lt;/span&gt;&lt;span&gt;ingår också&lt;/span&gt;&lt;span&gt; att &lt;/span&gt;&lt;span&gt;analysera i vilken utsträckning som bl.a. kommunal samverkan kan bidra till att stärka kommunernas förmåga att möta samhällsutvecklingen&lt;/span&gt;&lt;span&gt;. Mot denna bakgrund anser utskottet att det &lt;/span&gt;&lt;span&gt;inte finns skäl till &lt;/span&gt;&lt;span&gt;något tillkännagivande till regeringen &lt;/span&gt;&lt;span&gt;med anledning av motion &lt;/span&gt;&lt;span&gt;2017/18:3855&lt;/span&gt;&lt;span&gt; yrkande 20&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Motionen avstyrks.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet vidhåller sitt tidigare ställningstagande &lt;/span&gt;&lt;span&gt;när det gäller &lt;/span&gt;&lt;span&gt;undantag från lokaliseringsprincipen för att möjliggöra utbyggnad av bredband.&lt;/span&gt;&lt;span&gt; Utskottet noterar också att &lt;/span&gt;&lt;span&gt;förslag&lt;/span&gt;&lt;span&gt;et&lt;/span&gt;&lt;span&gt; om kommunal avtalssamverkan innebär att kommuner ska kunna avtalssamverka om de allmänna befogenheterna, däribland sådan bredbandsverksamhet som bedöms vara kompetensenlig. Utskottet &lt;/span&gt;&lt;span style="font-family:TimesNewRomanPSMT"&gt;avstyrker &lt;/span&gt;&lt;span style="font-family:TimesNewRomanPSMT"&gt;mot denna bakgrund&lt;/span&gt;&lt;span style="font-family:TimesNewRomanPSMT"&gt; &lt;/span&gt;&lt;span&gt;motionerna &lt;/span&gt;&lt;span&gt;201&lt;/span&gt;&lt;span&gt;7/18:3766&lt;/span&gt;&lt;span&gt; yrkande 58&lt;/span&gt;&lt;span&gt;,&lt;/span&gt;&lt;span&gt; 2017&lt;/span&gt;&lt;span&gt;/18:2256&lt;/span&gt;&lt;span&gt; yrkande 4, 2017/18:3672&lt;/span&gt;&lt;span&gt; och&lt;/span&gt;&lt;span&gt; 2017/18:1413&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:ce104638-1b97-4b32-a8f5-3565eb8d8405/förslagsrutor/546720193/1516177180391; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603140"&gt;&lt;span&gt;Representation i styrelsen, nämnder och utskott&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603140"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;avslår en motion om att alla partier med representation i en folkvald försam&lt;/span&gt;&lt;span&gt;ling också ska&lt;/span&gt;&lt;span&gt; ges representation i dess nämnder, utskott och styrelse&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalrutaindrag" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt; -aw-sdt-tag:'ce104638-1b97-4b32-a8f5-3565eb8d8405/förslagsrutor reservations text/509911320/1522238107730'; -aw-sdt-title:'förslagsrutor reservations text'"&gt;
					&lt;span&gt;Jämför reservation 2 (SD, -).&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;I motion 2017/18:3845 av Paula Bieler och Markus Wiechel (båda SD) begärs att alla partier med representation i en folkvald församling också ska ges representation i dess nämnder, &lt;/span&gt;&lt;span&gt;utskott och styrelse. Motionärerna&lt;/span&gt;&lt;span&gt; anför att fördelningen av platser i nämnder, utskott och styrelse ofta innebär att mindre partier blir utan representation i dessa organ. För att säkerställa att väljarnas förtroende förvaltas på bästa sätt bör det införas en lagreglering om att alla partier i en folkvald församling också ska ha en representant närvarande med yttranderätt, men inte nödvändigtvis rösträt&lt;/span&gt;&lt;span&gt;t, i församlingens alla nämnder och&lt;/span&gt;&lt;span&gt; utskott och i styrelsen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Gällande ordning&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;I varje kommun och i varje landsting finns det en beslutande församling, ett fullmäktige.&lt;/span&gt;&lt;span&gt; Av 3 kap. 3 § k&lt;/span&gt;&lt;span&gt;ommunallag&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt; (2017:725)&lt;/span&gt;&lt;span&gt;, &lt;/span&gt;&lt;span&gt;förkortad &lt;/span&gt;&lt;span&gt;KL,&lt;/span&gt;&lt;span&gt; följer att f&lt;/span&gt;&lt;span&gt;ullmäktige ska tillsätta en styrelse.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Fullmäktige ska &lt;/span&gt;&lt;span&gt;också, enligt 3 kap. 4&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;§, &lt;/span&gt;&lt;span&gt;tillsätta de nämnder som utöver styrelsen behövs för att fullgöra kommunens eller landstingets uppgifter&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Val av ledamöter och ersättare i bl&lt;/span&gt;&lt;span&gt;.a. nämnder ska enligt 5 kap. 58&lt;/span&gt;&lt;span&gt; § KL&lt;/span&gt;&lt;span&gt; vara proportionella under de förutsättningar som anges i 2 § lagen (1992:339) om proportionellt valsätt. Detta innebär att om ett visst antal ledamöter begär det, ska ledamöter i bl.a. s&lt;/span&gt;&lt;span&gt;tyrelser och nämnder i kommuner och&lt;/span&gt;&lt;span&gt; landsting utses proportionel&lt;/span&gt;&lt;span&gt;lt i enlighet med mandat&lt;/span&gt;&lt;span&gt;ställningen i fullmäktige. Bestäm&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;melserna om proportionella val syftar till att säkerställa att även en politisk minoritet ska kunna få platser i nämnder och styrelser. Detta innebär att en minoritetsgrupp i fullmäktige kan driva igenom proportionella val och därmed få möjlighet till representation i den kommunala nämndorganisationen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Ledamöter och ersättare i en nämnd väljs av fullmäktige till det antal som fullmäktige bestämmer (6 kap. 16 § KL). I styrelsen ska antalet ledamöter och antalet ersättare vara minst fem. Om ersättarna inte väljs proportionellt, ska fullmäktige bestämma i vilken ordning de ska tjänstgöra. Har ersättarna valts proportionellt, ska de tjänstgöra enligt den turordning som anges i 25 § lagen om proportionellt valsätt.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Tidigare utredningar&lt;/span&gt;&lt;span&gt; m.m.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Kommittén för en förstärkning av den kommunala demokratins funktionssätt och Utredningen om en kommunallag för framtiden föreslog båda att det införs en möjlighet för kommuner och landsting att besluta om en försöksverksamhet med majoritetsstyre under mandatperioden 2018–2022 (SOU 2012:30 och SOU 2015:24). För försöksverksamheten föreslogs att minoriteten skulle garanteras viss information om och insyn i styrelsens ärenden.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Regeringen gjorde i proposition &lt;/span&gt;&lt;span&gt;2016/17:171&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;En ny kommunallag (s.&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;16&lt;/span&gt;&lt;span&gt;8&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;f.) bedömningen att det&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;inte finns något behov av att genomföra en försöksverksamhet med majoritetsstyre.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Regeringen anför&lt;/span&gt;&lt;span&gt;de&lt;/span&gt;&lt;span&gt; att utred&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;ningarnas förslag är förknippade med en rad&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;problem, såsom svårigheter med att garantera oppositionen insyn och&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;arbetsförutsättningar och risken för konflikter mellan styrelsen och övriga&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;nämnder om den politiska samman&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;sättningen i styrelsen och de övriga&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;nämnderna skiljer sig alltför mycket åt. Den avgörande invändningen är enligt&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;regeringen härutöver att det är oklart på vilket sätt en försöksverksamhet med&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;majoritetsstyre skulle vitalisera den kommunala demokratin. Regeringen&lt;/span&gt;&lt;span&gt; föreslog&lt;/span&gt;&lt;span&gt; mot denna bakgrund inte någon lagstiftning.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;2017 års kommunallag, som trädde i kraft den 1 januari 2018, innehåller &lt;/span&gt;&lt;span&gt;inte några ändringar i sak &lt;/span&gt;&lt;span&gt;som &lt;/span&gt;&lt;span&gt;gäl&lt;/span&gt;&lt;span&gt;ler&lt;/span&gt;&lt;span&gt; bestämmelserna om tillsättande av nämnder&lt;/span&gt;&lt;span&gt; eller v&lt;/span&gt;&lt;span&gt;al av ledamöter och ersättare i &lt;/span&gt;&lt;span&gt;nämnder.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Tidigare behandling&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet har tidigare behandlat motioner i samma fråga. Utskottet har då&lt;/span&gt;&lt;span&gt; avstyrkt motionerna och anfört att reglerna om proportionella val medför att en minoritetsgrupp i fullmäktige kan driva igenom proportionella val och därmed få möjlighet till representation i den kommunala nämndorganisationen&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;(bet. 2012/13:KU22, 2013/14:KU12 och 2014/15:KU18). &lt;/span&gt;&lt;span&gt;I det sistnämnda betänkandet konstaterade utskottet&lt;/span&gt;&lt;span&gt; även&lt;/span&gt;&lt;span&gt; att det fanns&lt;/span&gt;&lt;span&gt; utredningsförslag om försöksverksamhet med majoritetsstyrelse som, om det genomfördes, skulle få betydelse för frågan om representation i kommun- och landstingsstyrelser&lt;/span&gt;&lt;span&gt; (&lt;/span&gt;&lt;span&gt;bet. &lt;/span&gt;&lt;span&gt;2014/15:KU18 s. &lt;/span&gt;&lt;span&gt;12)&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;En reservation lämnades&lt;/span&gt;&lt;span&gt; (SD).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Motionsyrkanden om representation i styrelsen, nämnder och utskott behandlades senast av utskottet i samband med behandlingen av &lt;/span&gt;&lt;span&gt;regeringens proposition &lt;/span&gt;&lt;span&gt;2016/17:171 En ny kommunallag&lt;/span&gt;&lt;span&gt;. Utskottet notera&lt;/span&gt;&lt;span&gt;de &lt;/span&gt;&lt;span&gt;det utred&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;ningsarbete som hade gjorts och såg inte skäl att förespråka ytterligare utredning (bet. &lt;/span&gt;&lt;span&gt;2016/17:KU30&lt;/span&gt;&lt;span&gt; s. 29).&lt;/span&gt;&lt;span&gt; Motionsyrkandena avstyrktes. &lt;/span&gt;&lt;span&gt;En reservation lämnades &lt;/span&gt;&lt;span&gt;(&lt;/span&gt;&lt;span&gt;SD&lt;/span&gt;&lt;span&gt;, -).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet vidhåller sitt tidigare ställningstagande och avstyrker motionen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:4c9d8c0f-446c-459f-ab6d-5d5240b8daec/förslagsrutor/-2037795987/1516196043106; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603141"&gt;&lt;span&gt;Byte av partitillhörighet&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603141"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;avslår motionsyrkanden&lt;/span&gt;&lt;span&gt; om ökat partiinflytande när en förtroendevald byter partitillhörighet.&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalrutaindrag" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt; -aw-sdt-tag:'4c9d8c0f-446c-459f-ab6d-5d5240b8daec/förslagsrutor reservations text/313397815/1522238107730'; -aw-sdt-title:'förslagsrutor reservations text'"&gt;
					&lt;span&gt;Jämför reservation 3 (SD, -).&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionerna&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Markus Wiechel (SD) yrkar i motion 2017/18:2089 att kommunallagen ska ändras så att de politiska partierna kan styra över vilka ledamöter och ersättare som ska vara partiets representanter i nämnder, styrelser m.m. i kommuner och landsting. Motionären anför att om ett parti förlorar förtroendet för e&lt;/span&gt;&lt;span&gt;n ledamot på grund av hans eller hennes&lt;/span&gt;&lt;span&gt; misskötsamhet borde partiet få byta ut representanten. Skulle det dessutom gå så långt att ledamoten lämnar partiet och blir s.k. politisk vilde uppstår ett demokratiskt problem, eftersom väljare riskerar att sakna representation.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Även Peter Persson (S) anser i motion 2017/18:1096 &lt;/span&gt;&lt;span&gt;att &lt;/span&gt;&lt;span&gt;ett parti bör kunna tvinga &lt;/span&gt;&lt;span&gt;en förtroendevald som byter partitillhörighet&lt;/span&gt;&lt;span&gt; att lämna ett&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;uppdrag &lt;/span&gt;&lt;span&gt;som tilldelats honom eller henne&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;genom&lt;/span&gt;&lt;span&gt; indirekta val. &lt;/span&gt;&lt;span&gt;Motionären framhåller att &lt;/span&gt;&lt;span&gt;d&lt;/span&gt;&lt;span&gt;en förtroendevald&lt;/span&gt;&lt;span&gt;e&lt;/span&gt;&lt;span&gt; har blivit nominerad &lt;/span&gt;&lt;span&gt;till uppdraget &lt;/span&gt;&lt;span&gt;av ett &lt;/span&gt;&lt;span&gt;visst &lt;/span&gt;&lt;span&gt;parti och att han eller hon därmed representerar det partiet. &lt;/span&gt;&lt;span&gt;De&lt;/span&gt;&lt;span&gt;n förtroendevald&lt;/span&gt;&lt;span&gt;e&lt;/span&gt;&lt;span&gt; bör därför skiljas från uppdrag&lt;/span&gt;&lt;span&gt;et&lt;/span&gt;&lt;span&gt; om han eller hon lämnar partiet.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Gällande ordning&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Beslutanderätten i kommuner och landsting utövas av valda församlingar&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;(fullmäktige) som utses av röstberättigade medlemmar i allmänna val. Enligt&lt;/span&gt;&lt;span&gt; 4 kap. 3 § kommunallagen (2017:725), &lt;/span&gt;&lt;span&gt;förkortad &lt;/span&gt;&lt;span&gt;KL,&lt;/span&gt;&lt;span&gt; väljs ledamöter och ersättare i fullmäktige bland dem som har&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;röstr&lt;/span&gt;&lt;span&gt;ätt. Av 1 kap. 7&lt;/span&gt;&lt;span&gt; §&lt;/span&gt;&lt;span&gt; KL&lt;/span&gt;&lt;span&gt; framgår att rösträtt vid val av ledamöter och ersättare i&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;kommunfullmäktige har den som är folkbokförd i kommunen, senast på&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;valdagen fyller 18 år och är medborgare i Sverige eller i någon annan av&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Europeiska unionens medlems&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;stater (unionsmedborgare), är medborgare i&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Island eller Norge, eller för det fall de är andra utlänningar, har varit folkbokförda&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;i Sverige tre år i följd före valdagen. Rösträtt vid val till landstingsfullmäktige&lt;/span&gt;&lt;span&gt; har enligt 1 kap. 8&lt;/span&gt;&lt;span&gt; § KL den som är röstberättigad vid val till&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;kommunfullmäktig&lt;/span&gt;&lt;span&gt;e i en kommun inom landstinget.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Vid val av andra förtroendevalda än till fullmäktige gäller &lt;/span&gt;&lt;span&gt;i huvudsak &lt;/span&gt;&lt;span&gt;samma valbarhetskriterier (4 kap. 3 § KL). Bedömningen av valbarheten &lt;/span&gt;&lt;span&gt;ska dock göras vid varje valtillfälle oberoende av vad som framgår av gällande röstlängd. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Bestämmelser om upphörande av up&lt;/span&gt;&lt;span&gt;pdraget för förtroendevalda&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;finns i 4&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;kap. 6–10 §§ KL&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Fullmäktige får enligt 9&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;§ återkalla uppdraget för en förtroendevald som har valts av fullmäktige, om den förtroendevalde har vägrats ansvarsfrihet. Uppdraget får även återkallas &lt;/span&gt;&lt;span&gt;om &lt;/span&gt;&lt;span&gt;den &lt;/span&gt;&lt;span&gt;förtroendevalde &lt;/span&gt;&lt;span&gt;har dömts för ett brott av viss svårhetsgrad. &lt;/span&gt;&lt;span&gt;Enligt &lt;/span&gt;&lt;span&gt;10 &lt;/span&gt;&lt;span&gt;§ får fullmäktige återkalla uppdragen för samtliga förtroendevalda&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;i en nämnd bl.a. när den politiska majoriteten i nämnden inte längre&lt;/span&gt;&lt;span&gt; är densamma som i fullmäktige.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Tidigare behandling&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;M&lt;/span&gt;&lt;span&gt;otioner om &lt;/span&gt;&lt;span&gt;ökat partiinflytande när en förtroendevald under en pågående mandatperiod byter partitillhörighet &lt;/span&gt;&lt;span&gt;har &lt;/span&gt;&lt;span&gt;flera gånger &lt;/span&gt;&lt;span&gt;t&lt;/span&gt;&lt;span&gt;idigare behandlats av utskottet. &lt;/span&gt;&lt;span&gt;Motionsyrkandena har då ofta gällt &lt;/span&gt;&lt;span&gt;förtroendeuppdrag i fullmäktige och &lt;/span&gt;&lt;span&gt;i &lt;/span&gt;&lt;span&gt;riksdagen&lt;/span&gt;&lt;span&gt;. För en mer utförlig redogörelse av gällande ordning i fråga om riksdagsledamöter och ledamöter i fullmäktige kan hänvisas till betänkande 2016/17:KU30 s. 20 f.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Under riksmötet 2001/02 behandlade utskottet en motion om partibytares rätt i förhållande till de up&lt;/span&gt;&lt;span&gt;pdrag de innehar (bet. 2001/02:&lt;/span&gt;&lt;span&gt;KU13). Utskottet instämde i vad som anfördes i motionen om att det kan uppkomma problem i den politiska beslutsprocessen om politiskt förtroendevalda under en pågående mandatperiod byter parti och ändå behåller uppdrag som det varit partigruppernas sak att besätta (s. 38). Denna problembild kunde enligt utskottet visserligen vara intressant att belysa. Utskottet såg dock stora svårigheter med att genom någon form av reglering finna en lösning på problemet. En sådan reglering skulle ovillkorligen innebära ingrepp i de grundläggande principer som det rådande valsystemet bygger på. Enligt utskottet borde ordningen alltjämt vara den att frågan om vem som ska inneha den typ av uppdrag som nu var aktuellt är upp till respektive partigrupp, och att eventuella personförändringar löses internt inom gruppen. Utskottet framhöll att en utgångspunkt i detta sammanhang är att varje enskild ledamot bär sitt mandat med det parlamentariska ansvar det innebär. Därmed var utskottet inte berett att föreslå att riksdagen skulle vidta någon &lt;/span&gt;&lt;span&gt;åtgärd med anledning av vad som anfördes i mo&lt;/span&gt;&lt;span&gt;tionen och avstyrkte den därför&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;(KD &lt;/span&gt;&lt;span&gt;reserverade sig&lt;/span&gt;&lt;span&gt;).&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Utskottet vidhöll detta ställningstagande våren 2004 vid behandling av en motion om förtroendevald&lt;/span&gt;&lt;span&gt;a&lt;/span&gt;&lt;span&gt; som lämnar sitt parti under mandatperioden och blir s.k. politisk&lt;/span&gt;&lt;span&gt;a vildar&lt;/span&gt;&lt;span&gt; (bet. 2003/04:KU9 s. 20).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Även våren 2007 avstyrkte utskottet en motion i frågan med hänvisning till&lt;/span&gt;&lt;span&gt; att varje ledamot bär sitt mandat med det parlamentariska ansvar detta innebär. Utskottet var inte berett att ställa sig bakom de begränsningar som föreslogs i detta avseende (bet. 2006/07:KU11 s. 26). Utskottet har därefter efter beredning i förenklad form avstyrkt motioner om partiernas inflytande vid partibyte (bet. 2007/08:KU14 och 2008/09:KU11). Våren 2010 behandlade utskottet regeringens proposition 2009/10:80 En reformerad grundlag (bet. 2009/10:KU19). I samband med det behandlades en motion om partiernas inflytande vid partibyte. Utskottet konstaterade att förslaget om extra val till fullmäktige kan – i den mån det politiska läget har sin grund i att en ledamot har bytt parti – vara en väg att undgå problem som kan uppkomma (s. 26). Utskottet var dock inte berett att frångå sina tidigare bedömningar där utgångspunkten varit att varje ledamot bär sitt mandat med det ansvar mot väljarna som det innebär. Utskottet uttalade vidare att det inte var berett att förorda en ordning som ger partiet ett avgörande inflytande i frågan om att en ledamot ska lämna partiet.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet vidhöll våren 2012 sina tidigare ställningstaganden om mandatets innebörd och avstyrkte två motioner i denna del (bet. 2011/12:KU15 s. 28).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Frågan om ökat partipolitiskt inflytande vid avsägelse av uppdrag behandlades&lt;/span&gt;&lt;span&gt; även i betänkande 2013&lt;/span&gt;&lt;span&gt;/14:KU18. Motionsyrkandet avstyrkte&lt;/span&gt;&lt;span&gt;s och utskottet förklarade att det stod fast vid sina tidigare ställningstaganden om mandatets innebörd&lt;/span&gt;&lt;span&gt; (s. 39)&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Våren 2017 behandlade utskottet regeringens proposition 2016/17:171 En ny kommunallag. I samband med det behandlades motioner om ökat parti&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;inflytande när en förtroendevald byter partitillhörighet&lt;/span&gt;&lt;span&gt; (bet. &lt;/span&gt;&lt;span&gt;2016/17:KU30&lt;/span&gt;&lt;span&gt; s.&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;24)&lt;/span&gt;&lt;span&gt;. Utskottet vidhöll sina tidigare ställningstaganden om mandatets innebörd &lt;/span&gt;&lt;span&gt;och avslog motionsyrkandena&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;En re&lt;/span&gt;&lt;span&gt;servation lämnades (&lt;/span&gt;&lt;span&gt;SD&lt;/span&gt;&lt;span&gt;, -).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent" style="text-indent:0pt"&gt;
				&lt;span&gt;Utskottet &lt;/span&gt;&lt;span&gt;delar motionärernas uppfattning att&lt;/span&gt;&lt;span&gt; det kan uppkomma problem i den politiska beslutsprocessen om &lt;/span&gt;&lt;span&gt;en förtroendevald&lt;/span&gt;&lt;span&gt; under pågående mandat&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;period byter parti och ändå behåller uppdrag som &lt;/span&gt;&lt;span&gt;har &lt;/span&gt;&lt;span&gt;tilldelats honom eller henne genom indirekta val&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;För att finna en lösning på problemet krävs &lt;/span&gt;&lt;span&gt;enligt utskottet &lt;/span&gt;&lt;span&gt;en &lt;/span&gt;&lt;span&gt;omfattande analys av regelverket. Eftersom kommunallagen nyligen har varit föremål för en reform är utskottet inte berett att nu ta &lt;/span&gt;&lt;span&gt;något &lt;/span&gt;&lt;span&gt;initiativ till en ny översyn.&lt;/span&gt;&lt;span&gt; Motionsyrkandena avstyrks.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:aac267a5-0a12-4fed-a447-e83c1b08cdb2/förslagsrutor/90291767/1516279596879; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603142"&gt;&lt;span&gt;Ersättare i fullmäktige&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603142"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;avslår &lt;/span&gt;&lt;span&gt;en motion om ersättare i fullmäktige.&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="Mellanrum"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Penilla Gunther och Larry Söder (båda KD)&lt;/span&gt;&lt;span&gt; anfö&lt;/span&gt;&lt;span&gt;r i motion &lt;/span&gt;&lt;span&gt;2017/18:3615&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;att &lt;/span&gt;&lt;span&gt;bestämmelserna i &lt;/span&gt;&lt;span&gt;5 kap. 8 § &lt;/span&gt;&lt;span&gt;andra stycket &lt;/span&gt;&lt;span&gt;kommunallagen &lt;/span&gt;&lt;span&gt;(2017:725) &lt;/span&gt;&lt;span&gt;om antalet ersättare i fullmäktige inte harmoniserar med &lt;/span&gt;&lt;span&gt;bestämmelserna i &lt;/span&gt;&lt;span&gt;vallagen&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;(2005:837) &lt;/span&gt;&lt;span&gt;om &lt;/span&gt;&lt;span&gt;hur ersättare i fullmäktige utses. &lt;/span&gt;&lt;span&gt;I kommunallagen anges att antalet ersättare ska utgöra en viss andel, dock högst hälften, av det antal platser som varje parti får i fullmäktige. I vallagen finns bestämmelser &lt;/span&gt;&lt;span&gt;om &lt;/span&gt;&lt;span&gt;hur ersättare utses. Enligt motionärerna tar vallagens mer detaljerade beskrivning inte hänsyn till kommun&lt;/span&gt;&lt;span&gt;al&lt;/span&gt;&lt;span&gt;lagens skrivning om ”högst hälften”. &lt;/span&gt;&lt;span&gt;Motionärerna&lt;/span&gt;&lt;span&gt; menar därför att &lt;/span&gt;&lt;span&gt;den nämnda bestämmelsen i &lt;/span&gt;&lt;span&gt;kommunallagen bör &lt;/span&gt;&lt;span&gt;ersättas med en hänvisning till att ersättare utses enligt 14 kap. 15–17 §§ vallagen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Gällande rätt&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;För ledamöter i fullmäktige ska det enligt 5 kap. 8 § kommunallagen (2017:725) finnas ersättare. &lt;/span&gt;&lt;span&gt;Av andra stycket framgår att f&lt;/span&gt;&lt;span&gt;ullmäktige bestämmer hur många ersättarna ska vara. Antalet ska utgöra en viss andel, dock högst hälften, av det antal platser som varje parti får i fullmäktige. Beslutet ska fattas före utgången av februari månad valåret. Länsstyrelsen ska genast underrättas om beslutet.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I 1991 års kommunallag fanns motsvarande bestämmelse i 5 kap. 4 §. Av den bestämmelsen framgick även att f&lt;/span&gt;&lt;span&gt;öreskrifter om att utse ersättare finns i vallagen (2005:837).&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;I den nya kommunallagen som trädde &lt;/span&gt;&lt;span&gt;i kraft den 1&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;januari 2018 har antalet hänvisningar till annan lagstiftning minimerats&lt;/span&gt;&lt;span&gt;,&lt;/span&gt;&lt;span&gt; och den aktuella hänvisningen till vallagen togs bort efter synpunkter från Lagrådet.&lt;/span&gt;&lt;span&gt; Någon ändring i sak gjordes emellertid inte.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;I propositionen om den nya kommun&lt;/span&gt;&lt;span&gt;al&lt;/span&gt;&lt;span&gt;lagen redovisades att av &lt;/span&gt;&lt;span&gt;14 kap. 17 § vallagen framgår att det för ett parti med en eller två ledamöter i kommunfullmäktige alltid kommer &lt;/span&gt;&lt;span&gt;att &lt;/span&gt;&lt;span&gt;utses två &lt;/span&gt;&lt;span&gt;ersättare (p&lt;/span&gt;&lt;span&gt;rop. 2016/17:171 s&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;332&lt;/span&gt;&lt;span&gt;).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Bestämmelser om f&lt;/span&gt;&lt;span&gt;ördelning av mandat&lt;/span&gt;&lt;span&gt; finns &lt;/span&gt;&lt;span&gt;sål&lt;/span&gt;&lt;span&gt;e&lt;/span&gt;&lt;span&gt;des &lt;/span&gt;&lt;span&gt;i 14 kap. vallagen. &lt;/span&gt;&lt;span&gt;I fråga om val till landsti&lt;/span&gt;&lt;span&gt;ngs- och kommunfullmäktige ska&lt;/span&gt;&lt;span&gt; länsstyrelsen fördela mandaten mellan partierna och för varje valkrets fastställa vilka kandidater som har valts till ledamöter och ersättare.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Ersättare i landstin&lt;/span&gt;&lt;span&gt;gsfullmäktige&lt;/span&gt;&lt;span&gt; utses &lt;/span&gt;&lt;span&gt;enligt 14 kap. 15 § &lt;/span&gt;&lt;span&gt;på motsvarande sätt som för riksdagsvalet.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Ersättare i kommunfullmäktige utses&lt;/span&gt;&lt;span&gt; enligt bestämmelser i 14 kap. 16 och 17 §§ vallagen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Kommunallagen har nyligen varit föremål för en översyn. &lt;/span&gt;&lt;span&gt;Utskottet är inte berett att nu föreslå några ändringar av bestämmelserna i kommunallagen om ersättare i fullmäktige. Motionsyrkandet avstyrks.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:21fc77dd-8ae8-45dc-bd95-485cc23327b5/förslagsrutor/-740566485/1515856763378; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603143"&gt;&lt;span&gt;Villkoren för förtroendevalda&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603143"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;avslår ett motionsyrkande om förtroendevaldas rätt till föräldraledighet.&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="Mellanrum"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Emma Carlsson Löfdahl (L) uppmärksammar i motion 2017/18:218 avhopp bland förtroendevalda för att det är svårt att få ihop uppdrag som fritids&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;politiker med att vara förälder. Motionären anser att det bör införas en möjlighet att vara föräldraledig från alla former av politiska uppdrag.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Gällande ordning&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;En arbetstagare som är anställd och som är förälder har enligt&lt;/span&gt;&lt;span&gt; föräldraledighetslagen (1995:584) rätt till olika former av föräldraledighet &lt;/span&gt;&lt;span&gt;(mammaledighet, föräldraledighet på hel- eller deltid med eller utan&lt;/span&gt;&lt;span&gt; föräldrapenning m.m.). Denna rätt gäller också vissa andra än föräldrar, t.ex. den som utan att vara förälder är rättslig vårdnadshavare och har vård om ett barn. Ledigheten kan tas ut sammanhängande eller delas upp på högst tre perioder varje kalenderår. Rätten till föräldrapenning under föräldraledigheten regleras i socialförsäkringsbalken (2010:110).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Förtroendevalda i kommuner och landsting fullgör ett förtroendeuppdrag&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;och har inte en anställning. Föräldraledighetslagens bestämmelser gäller&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;därför inte för de förtroendevalda.&lt;/span&gt;&lt;span&gt; Vissa kommuner, landsting och regioner har ändå valt att införa möjligheter till föräldraledighet genom bestämmelser i lokala reglementen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Genom 2017 års kommunallag&lt;/span&gt;&lt;span&gt;, som trädde i kraft den 1 januari 2018,&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;tydliggjordes &lt;/span&gt;&lt;span&gt;att kommuner och landsting kan besluta att ge kommunal- och landstingsråd möjlighet att vara t.ex. föräldralediga&lt;/span&gt;&lt;span&gt; (&lt;/span&gt;&lt;span&gt;prop. 2016/17:171, bet. 2016/17:KU30, rskr. 2016/17:335&lt;/span&gt;&lt;span&gt; och &lt;/span&gt;&lt;span&gt;2016/17:336&lt;/span&gt;&lt;span&gt;)&lt;/span&gt;&lt;span&gt;. Av 4 kap. 18 § k&lt;/span&gt;&lt;span&gt;ommunallag&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt; (2017:725)&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;följer att fullmäktige får bevilja kommunalråd, borgarråd, landstingsråd och oppositionsråd ekonomiska och andra förmåner i deras uppdrag, som svara&lt;/span&gt;&lt;span&gt;r mot de löne- och anställnings&lt;/span&gt;&lt;span&gt;villkor som gäller för kommunens eller landstingets anställda.&lt;/span&gt;&lt;span&gt; Reger&lt;/span&gt;&lt;span&gt;ingen anför i propositionen (s.&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;182) att en ordning för att möjliggöra för ett kommunal- och landstingsråd att vara föräldraledig eller sjukskriven är viktig för att underlätta en bred representation och goda villkor för de förtroendevalda. Att vara förtroendevald varken kan eller &lt;/span&gt;&lt;span&gt;bör dock jämställas med att &lt;/span&gt;&lt;span&gt;ha en anställning, enligt regeringens mening. Detta innebär att kommunal- och landstingsråd inte i lag ska ges sådana rättigheter till ledighet som gäller för anställda. Det finns enligt regeringen inte heller skäl att inordna regleringen för ledighet för förtroendevalda i socialförsäkringssystemet. Regeringen anser vidare att en reglering, i likhet med vad som tidigare gällt för regleringen av kommunal- och landstingsråd, ska ge ett stort utrymme för lokal anpassning.&lt;/span&gt;&lt;span&gt; De närmare villkoren som ska gälla kan bestämmas av fullmäktige i ett reglemente eller annat styrdokument. Ledigheten &lt;/span&gt;&lt;span&gt;kan &lt;/span&gt;&lt;span&gt;inte &lt;/span&gt;&lt;span&gt;avse en förtroendevalds plats i fullmäktige.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet ställde sig bakom förslaget i propositionen och &lt;/span&gt;&lt;span&gt;avstyrkte flera motionsyrkanden om förtroendevaldas möjlighet att ta ut föräldraledighet och annan tjänstledighet med hänvisning till att yrkandena&lt;/span&gt;&lt;span&gt; fick anses tillgodosedda (&lt;/span&gt;&lt;span&gt;bet.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;2016/17:KU30&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;s. 36).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;En ny kommunallag har nyligen trätt i kraft. &lt;/span&gt;&lt;span&gt;Genom &lt;/span&gt;&lt;span&gt;den nya lagen tydliggör&lt;/span&gt;&lt;span&gt;s&lt;/span&gt;&lt;span&gt; att kommuner och landsting kan besluta att ge kommunal- och landstingsråd möjlighet att vara t.ex. föräldralediga&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;Mot denna bakgrund &lt;/span&gt;&lt;span&gt;finner utskottet inte skäl att ta något initiativ till ändringar i de bestämmelser &lt;/span&gt;&lt;span&gt;i kommunallagen &lt;/span&gt;&lt;span&gt;som reglerar möjligheten till föräldraledighet för förtroendevalda. &lt;/span&gt;&lt;span&gt;Utskottet avstyrker motionen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:f7fd4c00-28ac-45a6-b5ce-95f55903870e/förslagsrutor/204142597/1515403155647; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603144"&gt;&lt;span&gt;Partistöd&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603144"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;avslår ett motionsyrkande om avräkning från det kommunala partistödet.&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalrutaindrag" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt; -aw-sdt-tag:'f7fd4c00-28ac-45a6-b5ce-95f55903870e/förslagsrutor reservations text/116884310/1522238107730'; -aw-sdt-title:'förslagsrutor reservations text'"&gt;
					&lt;span&gt;Jämför reservation 4 (SD, -).&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Fredrik Eriksson och Jonas Millard (båda SD) begär i motion 2017/18:3648 att ersättningar utöver det kommunala partistödet bör avräknas vid fördelning av partistödet. Motionärerna anför att de heltidspolitiker som dessutom är t.ex. ledamöter i nämndpresidier ofta får betydande extra ersättningar av kom&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;munen. Dessa personer tillhör ofta de största partierna. Det vore enligt motionärerna naivt att tro att de inte samtidigt engagerar sig i sitt partis interna angelägenheter, varför den extra ersättningen utgör ett indirekt partistöd. De stora partierna får därmed inte bara ett informationsövertag utan också avsevärda ekonomiska fördelar. De extra ersättningarna bör därför avräknas från respektive partis kommunala partistöd. Motsvarande bör också gälla om kommunerna bekostar politiska sekreterare.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Gällande ordning&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Enligt 4 kap. 29 § &lt;/span&gt;&lt;span&gt;kommunallagen (2017:725)&lt;/span&gt;&lt;span&gt;, &lt;/span&gt;&lt;span&gt;förkortad &lt;/span&gt;&lt;span&gt;KL, får kommuner och landsting ge ekonomiskt bidrag och annat stöd till politiska partier för att stärka deras ställning i den kommunala demokratin (partistöd). Fullmäktige ska enligt &lt;/span&gt;&lt;span&gt;4 kap. &lt;/span&gt;&lt;span&gt;30 § besluta om partistödets omfattning och formerna för det. Stödet får inte utformas så att det otillbörligt gynnar eller missgynnar ett parti.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Ett beslut om partistöd ska innehålla ett krav på att &lt;/span&gt;&lt;span&gt;mottagare&lt;/span&gt;&lt;span&gt;n&lt;/span&gt;&lt;span&gt; av partistöd&lt;/span&gt;&lt;span&gt;et&lt;/span&gt;&lt;span&gt; årligen ska lämna en&lt;/span&gt;&lt;span&gt; skriftlig redovisning som visar att partistödet har använts för det avsedda ändamålet. Mottagaren av partistödet ska också utse en &lt;/span&gt;&lt;span&gt;särskild &lt;/span&gt;&lt;span&gt;granskare som ska granska &lt;/span&gt;&lt;span&gt;om redovisningen ger en rättvisande bild av hur mottagaren har använt partistödet.&lt;/span&gt;&lt;span&gt; En gransk&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;ningsrapport ska bifogas &lt;/span&gt;&lt;span&gt;redovisningen (4 kap. 3&lt;/span&gt;&lt;span&gt;1 § första och andra styckena).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Fullmäktige får i ett fall besluta att partistöd inte ska betalas till ett parti.&lt;/span&gt;&lt;span&gt; Det gäller om partiet inte har lämnat en redovisning och en granskningsrapport &lt;/span&gt;&lt;span&gt;(4 kap. 3&lt;/span&gt;&lt;span&gt;1 § tredje stycket).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Det faktum att ett parti får utse politiska sekreterare ska inte anses utgöra&lt;/span&gt;&lt;span&gt; en form av partistöd (prop. 2013/14:5 s. 74 f.). Inte heller kommunalråd ska beaktas vid beräkningen av partistöd (RÅ 1994 ref. 104 II).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;En översyn av bestämmelserna om partistöd gjordes hösten&lt;/span&gt;&lt;span&gt; 2013 när vissa preciseringar av det s.k. representationskravet – som innebär att partistöd får ges endast till partier som är representerade i fullmäktige – gjordes i kommunallagen. Vidare infördes som ett nytt krav för att få lämna partistöd att fullmäktige måste besluta att mottagare av partistöd ska lämna en skriftlig redovisning som visar att stödet har använts för det nämnda&lt;/span&gt;&lt;span&gt; ändamålet. Redovisningen ska lämna&lt;/span&gt;&lt;span&gt;s in till fullmäktige och blir därigenom offentlig (prop. 2013/14:5, bet. 2013/14:KU7, rskr. 2013/14:71).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Lagen (2014:105) om insyn i finansiering av partier, insynslagen, trädde i kraft den 1 april 2014. Införandet av insynslagen markerade en övergång från en lång tradition bland riksdagspartier med endast frivilliga överenskom&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;melser om redovisning av intäkter till en tvingande reglering. &lt;/span&gt;&lt;span&gt;I samband med införandet av insynslagen beslutade riksdagen även om ändringar i lagen (1972:625) om statligt stöd till politiska partier (bet. 2013/14:KU35, rskr. 2013/14:163). &lt;/span&gt;&lt;span&gt;Genom riksdagens beslut kompletterades insynslagen med ett indirekt förbud mot anonyma bidrag&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I proposition 2017/18:55 &lt;/span&gt;&lt;span&gt;Ökad insyn i partiers finansiering – ett utbyggt regelverk &lt;/span&gt;&lt;span&gt;föreslår regeringen en ny lag om insyn i finansiering av partier. Genom den nya lagen utökas kravet på in&lt;/span&gt;&lt;span&gt;täkts&lt;/span&gt;&lt;span&gt;redovisning till att gälla &lt;/span&gt;&lt;span&gt;även för partier på regional och lokal nivå och för sidoorganisationer till&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;partier.&lt;/span&gt;&lt;span&gt; Det införs också ett förbud mot att ta emot anonyma bidrag vars värde överstiger 0,05 prisbasbelopp. Det nuvarande indirekta förbudet tas bort&lt;/span&gt;&lt;span&gt;,&lt;/span&gt;&lt;span&gt; och &lt;/span&gt;&lt;span&gt;lagen (2014:105) om insyn i finansiering av partier&lt;/span&gt;&lt;span&gt; upphävs&lt;/span&gt;&lt;span&gt;. För att förenkla för allmänheten &lt;/span&gt;&lt;span&gt;införs även en skyldighet för &lt;/span&gt;&lt;span&gt;landsting och kommuner &lt;/span&gt;&lt;span&gt;att &lt;/span&gt;&lt;span&gt;offentliggöra &lt;/span&gt;&lt;span&gt;vissa &lt;/span&gt;&lt;span&gt;uppgifter om &lt;/span&gt;&lt;span&gt;kommunalt &lt;/span&gt;&lt;span&gt;partistöd &lt;/span&gt;&lt;span&gt;på sina webbplatser&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;Lagändringarna föreslogs&lt;/span&gt;&lt;span&gt; träda i kraft den 1 april 2018&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Riksdagen antog regeringens lagförslag&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;(bet. 2017/18:KU19&lt;/span&gt;&lt;span&gt;, &lt;/span&gt;&lt;span&gt;rskr. 2017/18:153&lt;/span&gt;&lt;span&gt;).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Kommunal- och landstingsråd samt ledamöter av kommunala nämnder väljs av fullmäktige. Fullmäktige beslutar om arvode till kommunal- och landstingsråd och om ersättning till övri&lt;/span&gt;&lt;span&gt;ga ledamöter (4 kap. 12&lt;/span&gt;&lt;span&gt; och 16&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;§&lt;/span&gt;&lt;span&gt;§ &lt;/span&gt;&lt;span&gt;KL).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Tidigare behandling&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;M&lt;/span&gt;&lt;span&gt;otionsyrkanden om det kommunala partistödet &lt;/span&gt;&lt;span&gt;behandlades av utskottet i samband med beredningen&lt;/span&gt;&lt;span&gt; av &lt;/span&gt;&lt;span&gt;regeringens &lt;/span&gt;&lt;span&gt;proposition&lt;/span&gt;&lt;span&gt; 2016/17:171 En ny kommunallag&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;Någon förändring i sak som gällde partistödet föreslogs inte i propositionen. &lt;/span&gt;&lt;span&gt;Utskottet noterade det utredning&lt;/span&gt;&lt;span&gt;s&lt;/span&gt;&lt;span&gt;arbete som hade gjorts på området och fann inte skäl att förespråka nå&lt;/span&gt;&lt;span&gt;gon ytterligare utredning (&lt;/span&gt;&lt;span&gt;bet. 2016/17:KU30&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;s. 38&lt;/span&gt;&lt;span&gt;).&lt;/span&gt;&lt;span&gt; Motionerna avstyrktes&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;En reservation lämnades&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;(SD,&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;-&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;)&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet vidhåller sitt tidigare ställningstagande och avstyrker motionen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:0b7d94b4-30cd-4683-992f-ad7e05346195/förslagsrutor/199569546/1515402692688; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603145"&gt;&lt;span&gt;Fullmäktigesammanträden på måndagar&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603145"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;avslår en motion om att fullmäktigesammanträden ska äga rum på måndagar.&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="Mellanrum"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Johan Nissinen och Markus Wiechel (båda SD) anser i motion 2017/18:1632 att fullmäktigesammanträden i Sveriges samtliga kommuner bör hållas på måndagar. Motionärerna anför att ett flertal riksdagsledamöter också sitter i kommunfullmäktige runt om i landet, och att sammanträdena i dessa kommuner äger rum på olika dagar i veckan. För att riksdagsledamöter som också är fullmäktigeledamöter ska kunna närvara vid fullmäktigesamman&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;trädena och därmed behålla närheten till valkretsen och väljarna bör en harmoniserande ordning införas som innebär att alla kommunfullmäktige&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;sammanträden äger rum på måndagar.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Gällande ordning&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Av 5 kap. 12 § kommunallagen (2017:725) följer att fullmäktige bestämmer när ordinarie sammanträden ska hållas. Sammanträde ska hållas också om styrelsen eller minst en tredjedel av fullmäktiges ledamöter begär det eller om ordföranden anser att det behövs. Uppgifter om tid, plats och vilka ärenden som ska behandlas ska tillkännages på kommunens eller landstingets anslagstavla minst en vecka före sammanträdet (5 kap. 13 §).&lt;/span&gt;&lt;span&gt; &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Talmannen beslutar efter samråd med riksdagsstyrelsen om planeringen av arbetet i riksdagens kammare och om när kammaren ska sammanträda (6 kap. 2 § och tilläggsbestämmelse 6.2.1 i riksdagsordningen). Arbetsplenum i kammaren äger normalt inte rum på måndagar. Riksdagens utskott och EU-nämnden sammanträder när riksdagsarbetet kräver det (7 kap. 15 § riksdags&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;ordningen). Utskotten sammanträder i huvudsak på tisdagar och torsdagar och EU-nämnden på fredagar.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Tidigare behandling&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;M&lt;/span&gt;&lt;span&gt;otionsyrkanden om fullmäktigesammanträden på måndagar &lt;/span&gt;&lt;span&gt;behandlades av utskottet &lt;/span&gt;&lt;span&gt;i samband med beredning&lt;/span&gt;&lt;span&gt;en av regeringens proposition 2016/17:171 En ny kommunallag&lt;/span&gt;&lt;span&gt;. Utskottet fann inte skäl att ställa sig bakom yrkandena (bet. &lt;/span&gt;&lt;span&gt;2016/17:KU30&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;s. 39).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet vidhåller sitt tidigare ställningstagande och avstyrker motionen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:6c5a13de-551a-43cc-897d-7af59a6f86ca/förslagsrutor/1351056341/1515432589376; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603146"&gt;&lt;span&gt;Medborgerlig förslagsrätt&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603146"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;avslår motionsyrkanden om medborgerlig förslagsrätt.&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="Mellanrum"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionerna&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Robert Hannah (L) begär i motion 2017/18:445 att medborgerlig förslagsrätt i kommu&lt;/span&gt;&lt;span&gt;n- och landstingsfullmäktige bör&lt;/span&gt;&lt;span&gt; utredas och införas (&lt;/span&gt;&lt;span&gt;yrkande 1&lt;/span&gt;&lt;span&gt; i denna del&lt;/span&gt;&lt;span&gt;) samt att möjligheten till medborgarförslag avskaffas om medborgerlig förslagsrätt införs (yrkande 2). Motionären konstaterar att 2014 års demokratiutredning i betänkandet Låt fler forma framtiden! (SOU 2016:5) föreslagit att det införs en medborgerlig förslagsrätt till riksdagen samt till komm&lt;/span&gt;&lt;span&gt;un- och landstingsfullmäktige för&lt;/span&gt;&lt;span&gt; att vitalisera den svenska demokratin. Motionären anser att en sådan ordning bör införas i stället för dagens ordning med medborgarförslag. &lt;/span&gt;&lt;span&gt;Samma&lt;/span&gt;&lt;span&gt; yrkanden framställs av Robert Hannah (&lt;/span&gt;&lt;span&gt;L) i motion 2017/18:495 (&lt;/span&gt;&lt;span&gt;yrkande 1 &lt;/span&gt;&lt;span&gt;i denna del &lt;/span&gt;&lt;span&gt;och yrkande 2).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Gällande rätt&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Ärenden i kommun- eller landstingsfullmäktige får enligt 8 kap. 1 § &lt;/span&gt;&lt;span&gt;kommunallagen (2017:725)&lt;/span&gt;&lt;span&gt; väckas av den som är folkbokförd i kommunen eller i en kommun inom landstinget, om fullmäktige har beslutat om det (medborgarförslag). Fullmäktige får överlåta åt styrelsen eller en &lt;/span&gt;&lt;span&gt;annan &lt;/span&gt;&lt;span&gt;nämnd att besluta i ett ärende som har väckts genom medborgarförslag (5 kap. 23 §).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Möjligheten för kommuner och landsting att besluta att enskilda får väcka ärenden i fullmäktige infördes efter ett förslag av &lt;/span&gt;&lt;span&gt;Kommun&lt;/span&gt;&lt;span&gt;demokrati&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;kommittén&lt;/span&gt;&lt;span&gt; i betänkandet Att vara med på riktigt (SOU 2001:48). Syftet var att ge medborgarna ytterligare sätt att påverka politiken och att därigenom minska avståndet mellan väljare och förtroendevalda, öka medborgarnas lokal&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;politiska engagemang och ge upphov till fler politiska diskussioner mellan valen. Även barn och ungdomar samt personer med utländsk bakgrund som ännu inte fått rösträtt i kommuner och landsting skulle kunna lämna medborgarförslag. Förhoppningen var att införandet av möjligheten till medborgarförslag skulle stärka och vitalisera den lokala demokratin (prop. 2001/02:80 s. 53, bet. 2001/02:KU14, rskr. 2001/02:190).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Genom 2017 års kommunallag&lt;/span&gt;&lt;span&gt;, som trädde i kraft den 1 januari 2018,&lt;/span&gt;&lt;span&gt; utvidgades &lt;/span&gt;&lt;span&gt;rätten &lt;/span&gt;&lt;span&gt;att väcka medborgarförslag till att även &lt;/span&gt;&lt;span&gt;omfatta &lt;/span&gt;&lt;span&gt;unions&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;medborgare som är bosatt&lt;/span&gt;&lt;span&gt;a&lt;/span&gt;&lt;span&gt; i kommunen men som, enligt 5 § andra stycket folkbokf&lt;/span&gt;&lt;span&gt;öringslagen (1991:481), inte är&lt;/span&gt;&lt;span&gt; folkb&lt;/span&gt;&lt;span&gt;okförda&lt;/span&gt;&lt;span&gt; där&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;(prop. 2016/17:171, bet. 2016/17:KU30, rskr. 2016/17:335&lt;/span&gt;&lt;span&gt; och 2016/17:336&lt;/span&gt;&lt;span&gt;)&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Demokratiutredningen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;2014 års demokratiutredning hade bl.a. i uppdrag att utvärdera tillämpningen&lt;/span&gt;&lt;span&gt; av den medborgerliga förslagsrätten i kommun- och landstingsfullmäktige och att bedöma hur medborgarförslagen påverkat den lokala politikens utformning och den demokratiska delaktigheten i samhället. I uppdraget har också ingått att föreslå hur internet kan användas som ett redskap för att underlätta överlämnandet av medborgarförslag.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utredningen, som har genomfört en enkätundersökning med landets kommuner och landsting för att utvärdera tillämpningen av bestämmelserna om medborgarförslag och de&lt;/span&gt;&lt;span&gt;ras&lt;/span&gt;&lt;span&gt; effekter för den lokala demokratin, menar att medborgarförslaget har vissa positiva demokratieffekter eftersom det ger enskilda en möjlighet att på ett formaliserat sätt väcka frågor i den beslutsfattande processen. Utredningen anser emellertid också att medborgarförslagen har en begränsad effekt på det demokratiska samtalet och åsiktsbildningen, bl.a. eftersom de används i mycket begränsad omfattning och dessutom inte kan skapa en dialog mellan förtroendevalda å ena sidan och sammanslutningar av medborgare å den andra, &lt;/span&gt;&lt;span&gt;utan &lt;/span&gt;&lt;span&gt;enbart med enskilda medborgare. Medborgarförslagen ger heller inte en indikation på om det finns en stark opinion&lt;/span&gt;&lt;span&gt; i den fråga som väcks&lt;/span&gt;&lt;span&gt; utan har enligt utredningen främst använts som en ”förslagslåda” för frågor som uppfattas som klagomål eller mer &lt;/span&gt;&lt;span&gt;allmänna synpunkter (SOU 2016:5&lt;/span&gt;&lt;span&gt; s. 502 f.).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utredningen för&lt;/span&gt;&lt;span&gt;e&lt;/span&gt;&lt;span&gt;slår därför att ordningen med medborgarförslag ska ersättas med en möjlighet för de folkbokförda i en kommun eller ett landsting att väcka en folkmotion till kommun- eller landstingsfullmäktige. Ett ärende får enligt förslaget väckas om en folkmotion inom sex månader stöds av minst 1 procent av de folkbokförda i kommunen eller landstinget. Till skillnad från vad som är fallet med medborgarförslag, som är en frivillig möjlighet för kommun- och landstingsfullmäktige att införa, ska ordningen med folk&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;motion&lt;/span&gt;&lt;span&gt;er&lt;/span&gt;&lt;span&gt; vara tvingande, dvs. fullmäktige ska vara skyldig att ta emot en motion som har undertecknats av 1 procent av de folkbokförda.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Demokratiutredningens förslag bereds för närvarande inom Regerings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;kansliet.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Tidigare behandling&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;E&lt;/span&gt;&lt;span&gt;n likalydande motion &lt;/span&gt;&lt;span&gt;behandlade&lt;/span&gt;&lt;span&gt;s av&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;u&lt;/span&gt;&lt;span&gt;tskottet&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;i &lt;/span&gt;&lt;span&gt;samband med behandlingen av &lt;/span&gt;&lt;span&gt;regeringens proposition 2016/17:171 En ny kommunallag&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; Utskottet &lt;/span&gt;&lt;span&gt;konstaterade &lt;/span&gt;&lt;span&gt;att frågan om en förändring av dagens ordning med medborgar&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;förs&lt;/span&gt;&lt;span&gt;lag nyligen&lt;/span&gt;&lt;span&gt; varit föremål för utredning och att utredningen lämnat förslag om förändringar.&lt;/span&gt;&lt;span&gt; Utskottet, som ansåg att b&lt;/span&gt;&lt;span&gt;eredningen av utredningsförslagen inte &lt;/span&gt;&lt;span&gt;borde &lt;/span&gt;&lt;span&gt;föregripas, &lt;/span&gt;&lt;span&gt;avstyrkte motionen&lt;/span&gt;&lt;span&gt; (bet. &lt;/span&gt;&lt;span&gt;2016/17:KU30&lt;/span&gt;&lt;span&gt; s. 52)&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Punktlistabomb"&gt;
				&lt;span&gt;Demokratiutredningens förslag är fortfarande föremål för beredning. Utskottet vidhåller sitt tidigare ställningstagande &lt;/span&gt;&lt;span&gt;att beredningen av &lt;/span&gt;&lt;span&gt;förslag&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt; inte bör föregripas och avstyrker motionerna.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:912ae341-8ad1-4bff-a1ac-7cab333e0d5d/förslagsrutor/-690507373/1516022776061; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603147"&gt;&lt;span&gt;Budgetprocessen&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603147"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;avslår &lt;/span&gt;&lt;span&gt;motionsyrkande&lt;/span&gt;&lt;span&gt;n&lt;/span&gt;&lt;span&gt; om&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;kommunala budgetbeslut&lt;/span&gt;&lt;span&gt; och om &lt;/span&gt;&lt;span&gt;möjlighet &lt;/span&gt;&lt;span&gt;för enskilda skolor &lt;/span&gt;&lt;span&gt;att spara överskjutande medel.&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="Mellanrum"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionerna&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;I motion 2017/18:2389 begär Rasmus Ling (MP) att kommunallagen ändras så att beslut om kommunala budgetar tas i ett samlat beslut. Motionären anför att valresultaten i många kommuner, regioner och landsting har inneburit att det inte har bildats styrande majoriteter. I stället styrs kommunen, regionen eller landstinget av en minoritet. Med en hänvisning till hur riksdagen beslutar om statens budget menar motionären att kommunala budgetar bör tas i ett beslut så att inte budgeten splittras upp i budgetbeslut i olika delar.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Stefan Jakobsson (SD)&lt;/span&gt;&lt;span&gt; yrkar i motion &lt;/span&gt;&lt;span&gt;2017/18:2432&lt;/span&gt;&lt;span&gt; att&lt;/span&gt;&lt;span&gt; lagstiftningen ska ändras så att&lt;/span&gt;&lt;span&gt; enskilda skolor &lt;/span&gt;&lt;span&gt;får &lt;/span&gt;&lt;span&gt;möjlighet att spara överskjutande medel utan att det drabbar nästa &lt;/span&gt;&lt;span&gt;års budget. Om skolorna har pengar kvar i slutet av året är det enligt motionären vanligt att den ekonomiskt ansvarige ombeds att spendera pengarna på förbrukningsmaterial för att undvika att budgeten minskas till nästa år. &lt;/span&gt;&lt;span&gt;Orsaken till att pengarna inte använts under året kan vara vakanser som inte tillsatts eller elever som bytt skola. Det finns dock kommuner som tillåter enskilda skolor att behålla överskjutande medel. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Gällande ordning&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Budgetprocessen i kom&lt;/span&gt;&lt;span&gt;muner och landsting regleras i 11 kap. kommunallagen (2017:725)&lt;/span&gt;&lt;span&gt;. Kommuner&lt;/span&gt;&lt;span&gt; och landsting sk&lt;/span&gt;&lt;span&gt;a enligt 5&lt;/span&gt;&lt;span&gt; § varje år upprätta en budget för nästa kalenderår (budgetår). Budgeten ska upprättas så att intäkterna överstiger kostnaderna. &lt;/span&gt;&lt;span&gt;Av 8&lt;/span&gt;&lt;span&gt; § följer att ett förslag till budget ska upprättas av styrelsen före oktober månads utgång, eller, om det finns särskilda skäl, i november. &lt;/span&gt;&lt;span&gt;Budgeten fastställs enligt 10&lt;/span&gt;&lt;span&gt; § av fullmäktige före november månads utgång. Om budgeten av särskilda skäl inte kan fastställas före november månads utgång ska fullmäktige ändå fastställa bl.a. skattesatsen inom denna tid. Budgeten ska i sådana fall fastställas före &lt;/span&gt;&lt;span&gt;december månads utgång (11&lt;/span&gt;&lt;span&gt; §).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Sedan regeringen har lämnat &lt;/span&gt;&lt;span&gt;budget&lt;/span&gt;&lt;span&gt;propositionen beslutar riksdagen om stat&lt;/span&gt;&lt;span&gt;ens budget&lt;/span&gt;&lt;span&gt; i två steg enligt den s.k. rambeslutsmodellen (11 kap. 18 § riksdagsordningen). I det första steget beslutar riksdagen &lt;/span&gt;&lt;span&gt;om en beräkning av inkomsterna och utgifternas fördelning på &lt;/span&gt;&lt;span&gt;de 27 utgiftsområdena. I det andra steget beslutar riksdagen om de olika anslagens storlek inom respektive utgiftsområde.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Kommuner ska &lt;/span&gt;&lt;span&gt;enligt &lt;/span&gt;&lt;span&gt;2 kap. 8 a §&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;s&lt;/span&gt;&lt;span&gt;kollag&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt; (2010:800) &lt;/span&gt;&lt;span&gt;fördela resurser till utbildning inom skolväsendet efter barnens och elevernas olika förutsättningar och behov.&lt;/span&gt;&lt;span&gt; Kommunerna fördelar &lt;/span&gt;&lt;span&gt;resurser dels till sina egna förskole- och skolenheter, dels till andra huvudmän enligt särskilda bestämmelser om bidrag till fristående verksamheter, interkommunal ersättning och ersättning till statliga skolor.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Skolkostnadsutredningen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Skolkostnadsutredningen&lt;/span&gt;&lt;span&gt; har bl.a. haft i uppdrag att kartlägga hur budgetering och redovisning går till i kommuner och hos enskilda huvudmän för fristående skolor, med syftet att en jämförbar ekonomisk information på skolenhetsnivå ska kunna presenteras.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utredningen konstaterar i betänkandet Det stämmer! Ökad transparens och mer lika villkor (&lt;/span&gt;&lt;span&gt;SOU 2016:66&lt;/span&gt;&lt;span&gt;) att skolförfattningarna i dag endast reglerar bidragssystemet från kommuner till enskilda huvudmän. Kommuner har därmed, inom ramen för kommunallagens bestämmelser, ett stort utrymme att själva &lt;/span&gt;&lt;span&gt;bestämma hur man närmare ska fördela resurser till verksamhet i egen regi. Skolenheterna i egen regi ges en budget som genom den interna redovis&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;ningen följs upp löpande på det sätt som kommunen finner lämpligt&lt;/span&gt;&lt;span&gt; (s. 56)&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; Avsaknaden av regelverk &lt;/span&gt;&lt;span&gt;innebär &lt;/span&gt;&lt;span&gt;att den interna budgeteringen sker på olika sätt&lt;/span&gt;&lt;span&gt;. Vissa huvudmän har valt en modell där de olika enheterna ansvarar för sitt eget resultat och för med sig sina över- respektive underskott över åren. Andra har valt modeller där över- respektive underskott hanteras centralt&lt;/span&gt;&lt;span&gt; (se s. 111 f.).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utredningen föreslår bl.a. att ett krav på jämförbar ekonomisk redovisning på skolenhetsnivå ska införas för såväl kommunala som enskilda huvudmän. Redovisningen syftar till att öka öppenheten och insynen i hur offentliga medel används i verksamheten och ska även ligga till grund för den jämförbara information mellan skolenheter som ska publiceras av Statens skolverk.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Regeringen &lt;/span&gt;&lt;span&gt;anger&lt;/span&gt;&lt;span&gt; i budgetpropositionen för 2018 att den &lt;/span&gt;&lt;span&gt;under innevarande riksdagsår &lt;/span&gt;&lt;span&gt;avser att återkomma med förslag med&lt;/span&gt;&lt;span&gt; anledning av &lt;/span&gt;&lt;span&gt;de ovan&lt;/span&gt;&lt;span&gt;nämnda förslag&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt; från Skolkostn&lt;/span&gt;&lt;span&gt;adsutredningen (prop. 2017/18:1&lt;/span&gt;&lt;span&gt; utg.omr. 16 s. 193).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Tidigare behandling&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet har tidigare behandlat motionsyrkanden om utformningen av kommunala budgetbeslut&lt;/span&gt;&lt;span&gt;,&lt;/span&gt;&lt;span&gt; senast i &lt;/span&gt;&lt;span&gt;samband med behandlingen av &lt;/span&gt;&lt;span&gt;regeringens proposition 2016/17:171 En ny kommunallag&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Utskottet fann&lt;/span&gt;&lt;span&gt; inte skäl att ställa sig bakom&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;yrkandet och avstyrkte motionen&lt;/span&gt;&lt;span&gt; (bet. &lt;/span&gt;&lt;span&gt;2016/17:KU30&lt;/span&gt;&lt;span&gt; s. 63).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet finner inte skäl att ställa sig bakom det som yrkas i motion &lt;/span&gt;&lt;span&gt;2017/18:2389&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;om kommunala budgetbeslut. Motionen avstyrks.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet är inte heller berett att ställa sig bakom det som anförs &lt;/span&gt;&lt;span&gt;i motion 2017/18:2432&lt;/span&gt;&lt;span&gt; om &lt;/span&gt;&lt;span&gt;möjlighet för enskilda skolor att spara överskjutande medel.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Motionen avstyrks.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:a6966399-3a04-4bae-bca2-9b7a2a362afd/förslagsrutor/-196142085/1516088728383; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603148"&gt;&lt;span&gt;Revision&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603148"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;avslår motionsyrkanden om den kommunala revisionen.&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalrutaindrag" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt; -aw-sdt-tag:'a6966399-3a04-4bae-bca2-9b7a2a362afd/förslagsrutor reservations text/-79629195/1522238107730'; -aw-sdt-title:'förslagsrutor reservations text'"&gt;
					&lt;span&gt;Jämför reservation 5 (SD, -).&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionerna&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Niklas Wykman (M) &lt;/span&gt;&lt;span&gt;anser i motion 2017/18:1291 att det finns ett &lt;/span&gt;&lt;span&gt;beh&lt;/span&gt;&lt;span&gt;ov&lt;/span&gt;&lt;span&gt; av &lt;/span&gt;&lt;span&gt;en förstärkning&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;av den kommunala &lt;/span&gt;&lt;span&gt;revision&lt;/span&gt;&lt;span&gt;en. Motionären menar att sakkunniga revisorer bör stå för den huvudsakliga granskningen och föredra revisions&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;resultatet för kommun- respektive landstingsfullmäktige. Revisorerna på kommunal nivå bör enligt motionären &lt;/span&gt;&lt;span&gt;också &lt;/span&gt;&lt;span&gt;ges verktyg som motsvarar de som Riksrevisionen har på statlig nivå.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Ida Drougge (M)&lt;/span&gt;&lt;span&gt; begär i motion 2017/18:2798 att en &lt;/span&gt;&lt;span&gt;oberoende, förslagsvis statlig, kommunrevision bestående av professionella revisorer&lt;/span&gt;&lt;span&gt; ska införas (yrkande 1). &lt;/span&gt;&lt;span&gt;En sådan myndighet&lt;/span&gt;&lt;span&gt; bör enligt motionären bl.a. kunna granska chef&lt;/span&gt;&lt;span&gt;s&lt;/span&gt;&lt;span&gt;tjänstemäns anställningsavtal för att hitta och möjliggöra omförhandling av orimliga villkor, fallskärmar och bonusar (yrkande 2). Ett nationellt prickningssystem för politiker och tjänstemän bör också införas (yrkande 3).&lt;/span&gt;&lt;span&gt; Dagens system med politiker som granskar politiker är enligt motionären varken rättssäkert, likvärdigt eller effektivt. Det behövs en professionell och oberoende revision som även har möjlighet att göra kvalitativa granskningar. Den nya oberoende revisionen bör &lt;/span&gt;&lt;span&gt;enligt motionären &lt;/span&gt;&lt;span&gt;kunna föreslå ett bredare s&lt;/span&gt;&lt;span&gt;pektrum&lt;/span&gt;&lt;span&gt; av åtgärder, t.ex. ett nationellt prickningssystem&lt;/span&gt;&lt;span&gt; som visar på när politiker och tjänstemän har gjort fel&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;Det bör även vara möjligt att göra &lt;/span&gt;&lt;span&gt;tematiska granskningar av samtliga kommuner&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; En nationell revisor skulle t.ex. kunna granska samtliga kommuners anställningsavtal som gäller högre tjänstemän.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Även Markus Wiechel och Paula Bieler (båda SD) efterfrågar i motion 2017/18:3843 &lt;/span&gt;&lt;span&gt;yrkande 1 &lt;/span&gt;&lt;span&gt;e&lt;/span&gt;&lt;span&gt;n översyn av &lt;/span&gt;&lt;span&gt;den kommunala &lt;/span&gt;&lt;span&gt;revisionen.&lt;/span&gt;&lt;span&gt; Det bör enligt motionärerna ifrågasättas att kommunpolitikerna kan välja &lt;/span&gt;&lt;span&gt;sina&lt;/span&gt;&lt;span&gt; partivänner för&lt;/span&gt;&lt;span&gt; granskning av den egna verksamheten&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Jan Lindholm (MP) &lt;/span&gt;&lt;span&gt;framhåller &lt;/span&gt;&lt;span&gt;i motion 2017/18:1712 svagheterna med den kommunala revisionens självständighet (yrkande 1), behovet av en översyn när det gäller uppföljning och revision (yrkande 2) och behovet av att inrätta självständiga regionala kommunrevisio&lt;/span&gt;&lt;span&gt;nsverk (yrkande 3). Motionären&lt;/span&gt;&lt;span&gt; anser bl.a. att granskningen alltför ofta missar brister i maktutövning och oklara motiv till beslut trots att det normalt är oppositionens politiker som leder revisionsarbetet. Det är enligt motionären uppenbart att de åtgärder som &lt;/span&gt;&lt;span&gt;vidtagits inte räcker, och han anför att det förmodligen är tid för en helt oberoende, eller åtminstone moderniserad, kommunal revision. Motionären anser att den demokratiska beslutsstr&lt;/span&gt;&lt;span&gt;ukturen m.m. förmodligen kan stärkas&lt;/span&gt;&lt;span&gt; genom en utvecklad reglering av revisionen i kommunallagen samt att en utredning med detta syfte bör tillsättas. En fråga som bör övervägas i en sådan utredning är om det vore lämpligt att inrätta regionala kommunrevisionsverk som har till uppgift att stödja sina kommuner och landsting med helt självständiga revisioner.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Bakgrund och gällande ordning&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Den kommunala revisionen har varit föremål för ett återkommande reform&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;arbete,&lt;/span&gt;&lt;span&gt; som bl.a. inneburit ett krav på att revisorerna ska biträdas av sakkunniga, att fullmäktige ska motivera sitt förslag till beslut i ansvars&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;frihetsfrågan och att fullmäktigeledamöter inte kan väljas till revisorer. Genom 2017 års kommunallag&lt;/span&gt;&lt;span&gt;, som trädde i kraft den 1 januari 2018,&lt;/span&gt;&lt;span&gt; infördes ett krav på att revisorernas budget ska beredas av fullmäktiges presidium. De sakkunniga revisionsbitr&lt;/span&gt;&lt;span&gt;ädena fick&lt;/span&gt;&lt;span&gt; också rätt att yttra&lt;/span&gt;&lt;span&gt; sig i fullmäktige när revisionsberättelsen behandlas.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Det infördes även ett valbarhetshinder som innebä&lt;/span&gt;&lt;span&gt;r att den som är revisor inte kan väljas till ledamot eller ersättare i fullmäktige.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Enligt 3 kap. 10 § kommunallagen &lt;/span&gt;&lt;span&gt;(2017:725) &lt;/span&gt;&lt;span&gt;ska kommuner och landsting &lt;/span&gt;&lt;span&gt;utse revisorer för granskning av den kommunala verksamheten.&lt;/span&gt;&lt;span&gt; Revisorerna granskar enligt 12 kap. 1 § årligen i den omfattning som följer av god revisionssed all verksamhet som bedrivs inom nämndernas eller fullmäktige&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;beredningarnas verksamhetsområden. De granskar på samma sätt, genom de revisorer eller lekmannarevisorer som utsetts i &lt;/span&gt;&lt;span&gt;juridiska personer enligt 10&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;kap. 2–&lt;/span&gt;&lt;span&gt;6 §§, även verksamheten i de juridiska personerna. Revisorerna prövar om verksamheten sköts på ett ändamålsenligt och från ekonomisk synpunkt tillfredsställande sätt, om räkenskaperna är rättvisande och om den interna kontrollen som görs inom nämnderna är tillräcklig.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Enligt 12 kap. 4 § ska det&lt;/span&gt;&lt;span&gt; nyvald&lt;/span&gt;&lt;span&gt;a&lt;/span&gt;&lt;span&gt; fullmäktige under de år då val av fullmäktige har hållits i hela landet välja revisorer för granskning av verksamheten under de fyra följande åren. Vid en samlad revision av hela verksamheten ska minst fem revisorer väljas (12 kap. 5 §). &lt;/span&gt;&lt;span&gt;Vid en särskild revision för granskning av en viss eller vissa nämnders verksamhet ska minst fem revisorer väljas för varje nämnd eller grupp av nämnder.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Regeringen gjorde i förarbetena till 2017 års kommunallag bedömningen att den rådande ordningen med förtroendevalda revisorer som ansvarar för både förvaltnings- och redovisningsrevision &lt;/span&gt;&lt;span&gt;skulle&lt;/span&gt;&lt;span&gt; behållas &lt;/span&gt;&lt;span&gt;(&lt;/span&gt;&lt;span&gt;p&lt;/span&gt;&lt;span&gt;rop. 2016/17:171 &lt;/span&gt;&lt;span&gt;s. 240 f&lt;/span&gt;&lt;span&gt;.).&lt;/span&gt;&lt;span&gt; Regeringen anförde i huvudsak följande.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Den kommunala revisionen har varit föremål för flera reformer de senaste&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;decennierna. Många åtgärder har vidtagits för att stärka oberoendet och&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;professionaliteten. All verksamhet i kommuner bygger på nämndmodellen där&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;förtroendevalda är ansvariga. Inom en sådan modell är det inte anmärkningsvärt&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;att även fullmäktiges kontroll genom revision bedrivs på&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;motsvarande sätt. Om systemet med förtroendevalda revisorer avskaffades&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;skulle det innebära en förändring av kommunernas organisationsmodell och&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;ett ingrepp i det kommunala självstyret. Den kommunala förvaltnings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;revisionen&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;är till sin karaktär politisk&lt;/span&gt;&lt;span&gt;,&lt;/span&gt;&lt;span&gt; och de som granskas är till stor del förtroendevalda.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Granskningen ska därför ledas av förtroendevalda. De förtroendevalda&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;revisorerna har stor kompetens om hur kommunen eller landstinget är&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;organiserat och om lokala förhållanden. Det kan ifrågasättas om en helt&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;yrkesmässig revision kan upprätthålla motsvarande kunskap. Om revisionen&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;t.ex. ska upphandlas kan upparbetad kompetens förloras varje gång en ny&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;upphandling görs. Långsiktigheten i revisionsarbetet blir då lidande. Det bör&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;också uppmärksammas att den politiska minoritetens insyn i revisionen med&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;en sådan modell riskerar att försvinna. Det nuvarande systemet har också i allt&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;väsentligt fungerat väl.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Tidigare behandling&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet har tidigare &lt;/span&gt;&lt;span&gt;behandlat motioner &lt;/span&gt;&lt;span&gt;om en förstärkning av den kommunala revisionen. Motionerna har&lt;/span&gt;&lt;span&gt; avstyrkts av utskottet, i början av den förra mandatperioden med hänvisning till redan genomförda ändringar i kommunallagen som innebar en sådan för&lt;/span&gt;&lt;span&gt;stärkning (bet. 2010/11:KU24 s.&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;34&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;f.), och senare med hänvisning till den då pågående beredningen av de förslag som lämnats av Utredningen om en kommunallag för framtiden (bet. 2014/15:KU18 s. 10).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Frågan &lt;/span&gt;&lt;span&gt;om en förstärkning av den kommunala revisionen &lt;/span&gt;&lt;span&gt;behandlades även av utskottet i&lt;/span&gt;&lt;span&gt; samband med beredningen av regeringens propositio&lt;/span&gt;&lt;span&gt;n &lt;/span&gt;&lt;span&gt;2016/17:171 En ny kommunallag&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;(bet. 2016/17:KU30 s. 67)&lt;/span&gt;&lt;span&gt;. Utskottet delade regeringens uppfattning att den rådande ordningen med förtroendevalda revisorer som ansvarar för både förvaltnings- och &lt;/span&gt;&lt;span&gt;redovisningsrevision bord&lt;/span&gt;&lt;span&gt;e behållas. Utskottet konstaterade att regeringen &lt;/span&gt;&lt;span&gt;i propositionen dessutom lämnat&lt;/span&gt;&lt;span&gt; vissa förslag som ytterligare skulle förstärka revisionens oberoende. Det saknades därför enligt utskottet skäl att ställa sig bakom motionerna. Motionsyrkandena &lt;/span&gt;&lt;span&gt;avstyrkte&lt;/span&gt;&lt;span&gt;s&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;En reservation lämnades&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;(&lt;/span&gt;&lt;span&gt;SD, -)&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet vidhåller sitt tidigare ställningstag&lt;/span&gt;&lt;span&gt;ande och avstyrker motionerna&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:85f86d7a-eae0-40a7-8b8e-5eebcb4ad794/förslagsrutor/-365627555/1515573103306; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603149"&gt;&lt;span&gt;Kommunindelning&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603149"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;avslår motionsyrkan&lt;/span&gt;&lt;span&gt;den om kommunindelning.&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="Mellanrum"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionerna&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Lars-Arne Staxäng (M) anser i motion 2017/18:&lt;/span&gt;&lt;span&gt;463 &lt;/span&gt;&lt;span&gt;att en kommunreform bör övervägas &lt;/span&gt;&lt;span&gt;för att skapa &lt;/span&gt;&lt;span&gt;starkare kommuner som kan ge sina medborgare bättre service.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Christina Örnebjär och Emma Carlsson Löfdahl (båda L) &lt;/span&gt;&lt;span&gt;framhåller &lt;/span&gt;&lt;span&gt;i motion 2017/18:422 &lt;/span&gt;&lt;span&gt;yrkande 1 &lt;/span&gt;&lt;span&gt;att det behöver bli enklare för de kommuner som så önskar att slå sig samman.&lt;/span&gt;&lt;span&gt; Motionärerna&lt;/span&gt;&lt;span&gt; anför att Sveriges kommuner står inför stora utmaningar bl.a. som en följd av den demografiska utvecklingen&lt;/span&gt;&lt;span&gt; och att det &lt;/span&gt;&lt;span&gt;är &lt;/span&gt;&lt;span&gt;svårt för mindre kommuner &lt;/span&gt;&lt;span&gt;att klara av sina uppgifter.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Gällande regler&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Sverige är enligt 1 kap. 1 § kommunall&lt;/span&gt;&lt;span&gt;agen (2017:725&lt;/span&gt;&lt;span&gt;) indelat i kommuner och landsting. Enligt 1 kap. 1 § lagen (1979:411) om ändringar i Sveriges indelning i kommuner och landsting&lt;/span&gt;&lt;span&gt;, indelningslagen,&lt;/span&gt;&lt;span&gt; får regeringen besluta om ändringar i rikets indelning i kommuner, om ändringen kan antas medföra en bestående fördel för en kommun eller en del av en kommun eller andra&lt;/span&gt;&lt;span&gt; fördelar från allmän synpunkt. Vid en prövning av frågan om indelnings-ändring ska särskild hänsyn tas till önskemål och synpunkter från den eller de kommuner som närmast berörs av ändringen. Om en sådan kommun motsätter sig en indelningsändring, får beslut om ändringen fattas endast om det finns synnerliga skäl. Särskild hänsyn ska också tas till befolkningens önskemål och synpunkter.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Enligt 1 kap. 20 § indelningslagen kan en fråga om ändring i den kommunala indelningen väckas av en kommun eller medlem av en kommun som skulle beröras av ändringen. En ansökan om en sådan ändring ska lämnas in till Kammarkollegiet. Regeringen, Kammarkollegiet och länsstyrelsen kan ta upp en fråga om indelningsändring på eget initiativ.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I ärenden om sådana indelningsändringar som avses i bl.a. 1 § ska Kammarkollegiet, enligt 21 §, göra den utredning som behövs eller, när det bedöms lämpligt, överlämna åt länsstyrelsen att göra utredningen. Om det behövs med hänsyn till ärendets omfattning och beskaffenhet, får Kammar-kollegiet ge i uppdrag åt en särskild utredare&lt;/span&gt;&lt;span&gt; att göra utredningen. En utred&lt;/span&gt;&lt;span&gt;ning om en ändring i den kommunala indelningen ska, enligt 22 §, omfatta alla omständigheter som inverkar på frågan. Vid utredningen ska samråd ske med de kommuner som har intresse av frågan. När det finns skäl till det ska, enligt 24 §, en särskild undersökning göras om befolkningens inställning till en indelningsändring. Om en särskild utredare finner skäl till en &lt;/span&gt;&lt;span&gt;sådan undersök&lt;/span&gt;&lt;span&gt;ning, ska han eller hon anmäla detta till Kammarkollegiet, som beslutar i frågan.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Kommunutredningen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Regeringen gav i februari 2017&lt;/span&gt;&lt;span&gt; en parlamentarisk kommitté i&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;uppdrag att utarbeta en strategi för att stärka&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;kommunernas kapacitet att fullgöra sina&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;uppgifter och hantera &lt;/span&gt;&lt;span&gt;sina utmaningar&lt;/span&gt;&lt;span&gt; (&lt;/span&gt;&lt;span&gt;Fi 2017:02&lt;/span&gt;&lt;span&gt;, &lt;/span&gt;&lt;span&gt;dir.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;2017:13). Kommittén, som &lt;/span&gt;&lt;span&gt;har &lt;/span&gt;&lt;span&gt;antagit namnet&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Kommunutredningen, ska &lt;/span&gt;&lt;span&gt;utifrån kommunernas varierande förutsättningar dels identifiera och analysera de utmaningar som väntas ha särskilt st&lt;/span&gt;&lt;span&gt;or påverkan på kommunernas&lt;/span&gt;&lt;span&gt; förmåga att klara av sina uppgifter, dels analysera i vilken utsträckning som kommunal samverkan, kommunsammanläggningar, förändrade uppgifter, en asymmetrisk ansvars&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;fördelning och andra tänkbara åtgärder kan bidra till att stärka &lt;/span&gt;&lt;span&gt;kommunernas&lt;/span&gt;&lt;span&gt; förmåga att möta samhällsutvecklingen. Kommittén ska mot bakgrund av denna analys föreslå vilka åtgärder som bör vidtas &lt;/span&gt;&lt;span&gt;och hur genomförandet bör gå till.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Eventuella förslag om kommunsammanläggningar&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;ska vara frivilliga. Kommittén ska&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;lämna sitt slutbetänkande senast den 15 oktober&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;2019.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Delbetänkandet En generell rätt till kommunal avtalssamverkan&lt;/span&gt;&lt;span&gt; (&lt;/span&gt;&lt;span&gt;SOU 2017:77&lt;/span&gt;&lt;span&gt;) överlämnades i &lt;/span&gt;&lt;span&gt;oktober 2017&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Tidigare behandling&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet har tidigare behandlat motionsyrkanden om kommunal indelning och kommunal kompetens. Utskottet konstaterade att en fråga om ändring i den kommunala indelningen enligt indelningslagen kan initieras såväl av en kommun eller medlem av en kommun som skulle beröras av ändringen som av regeringen, Kammarkollegiet och länsstyrelsen, vilka kan ta upp en fråga om indelningsändring på eget initiativ. Utskottet fann därför inte anledning att ställa sig bakom motionerna (bet. 2014/15:KU18 s. 53).&lt;/span&gt;&lt;span&gt; &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet vidhöll i betänkande 2016/1&lt;/span&gt;&lt;span&gt;7:KU17 sitt tidigare ställnings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;tagande och avstyrkte motionsyrkanden om att utreda förutsättningarna för en ny kommunreform (s. 11).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Kommunutredningen har i uppdrag att &lt;/span&gt;&lt;span&gt;analysera bl.a. i vilken utsträckning som kommunsamman&lt;/span&gt;&lt;span&gt;läggningar och andra&lt;/span&gt;&lt;span&gt; åtgärder kan bidra till att stärka kommunernas förmåga att möta samhällsutvecklingen. &lt;/span&gt;&lt;span&gt;Utskottet anser inte att d&lt;/span&gt;&lt;span&gt;et pågående utredningsarbetet &lt;/span&gt;&lt;span&gt;bör föregripas, och avstyrker motions&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;yrkandena.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:f70fcdbf-ddfd-4fa2-8706-c1aa8ab1dcfe/förslagsrutor/124939788/1515688579822; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603150"&gt;&lt;span&gt;Regionalisering&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603150"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span&gt;Riksdagen&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;avslår motionsyrkanden om&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;bl.a. &lt;/span&gt;&lt;span&gt;lokal fö&lt;/span&gt;&lt;span&gt;rankring av beslut om regioner,&lt;/span&gt;&lt;span&gt; avskaffandet av länsstyrelser och en överföring av statliga uppgifter till &lt;/span&gt;&lt;span&gt;regioner med valda församlingar&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalrutaindrag" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt; -aw-sdt-tag:'f70fcdbf-ddfd-4fa2-8706-c1aa8ab1dcfe/förslagsrutor reservations text/-225047217/1521719753757'; -aw-sdt-title:'förslagsrutor reservations text'"&gt;
					&lt;span&gt;Jämför reservation 6 (C).&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionerna&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Boriana Åberg (M) &lt;/span&gt;&lt;span&gt;anser i motion 2017/18:2345 yrkande 1 att &lt;/span&gt;&lt;span&gt;länsstyrelserna &lt;/span&gt;&lt;span&gt;bör&lt;/span&gt;&lt;span&gt; avskaffas &lt;/span&gt;&lt;span&gt;och deras uppgifter &lt;/span&gt;&lt;span&gt;föras över &lt;/span&gt;&lt;span&gt;till lokala och regionala organ &lt;/span&gt;&lt;span&gt;eller &lt;/span&gt;&lt;span&gt;andra statliga myndigheter. &lt;/span&gt;&lt;span&gt;I yrkande 2 föreslås&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;att Skåne ska utses till&lt;/span&gt;&lt;span&gt; försöksregion för avskaffandet av länsstyrelserna.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Enligt &lt;/span&gt;&lt;span&gt;motionären &lt;/span&gt;&lt;span&gt;bör politiska frågor som berör respektive län först och främst beslutas och behandlas av politi&lt;/span&gt;&lt;span&gt;ska och demokratiskt valda före&lt;/span&gt;&lt;span&gt;trädare. Samtidigt bör &lt;/span&gt;&lt;span&gt;t.ex. &lt;/span&gt;&lt;span&gt;överklaganden hanteras av förvaltningsdomstolen i länet i stället för av länsstyrelsen. I Skåne har regionen redan tagit över det regionala utvecklings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;ansvaret och ansvaret för näringsli&lt;/span&gt;&lt;span&gt;vsfrågorna&lt;/span&gt;&lt;span&gt;. Detta gör Skåne särskilt lämplig&lt;/span&gt;&lt;span&gt;t&lt;/span&gt;&lt;span&gt; som försöksregion för avskaffande av länsstyrelsen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Eskil Erlandsson m.fl. (C) efterfrågar i kommittémotion 2017/18:3855 yrkande 24 &lt;/span&gt;&lt;span&gt;en regionaliseringsprocess där fler ansvarsområden decentraliseras från staten till regionerna. &lt;/span&gt;&lt;span&gt;Det bör enligt motionärerna utredas hur&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;funktion&lt;/span&gt;&lt;span&gt;, &lt;/span&gt;&lt;span&gt;ansvar och finansiering för &lt;/span&gt;&lt;span&gt;vissa &lt;/span&gt;&lt;span&gt;statliga uppgifter &lt;/span&gt;&lt;span&gt;som i dag utförs av länsstyrelsen och andra statliga myndigheter &lt;/span&gt;&lt;span&gt;kan &lt;/span&gt;&lt;span&gt;flyttas från central nivå till regioner med valda församlingar.&lt;/span&gt;&lt;span&gt; I yrkande 25 anförs att nya regioners gränser ska tillkomma på initiativ av de direkt berörda i de områden som omfattas av en regionbildning.&lt;/span&gt;&lt;span&gt; Frågan om lokalt stöd för bildandet av regioner tas upp även i motion 2017/18:3391 av Runar Filper (SD)&lt;/span&gt;&lt;span&gt; yrkande&lt;/span&gt;&lt;span&gt;na&lt;/span&gt;&lt;span&gt; 1 och 2&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Sveriges administrativa indelning&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Den svenska förvaltningen är organiserad på tre nivåer: central, regional och lokal. På lokal nivå är Sverige indelat i 290 kommuner. På regional nivå är landet indelat i dels 21 län, med en statlig myndighet (länsstyrelsen) i varj&lt;/span&gt;&lt;span&gt;e län, dels 20 landsting med &lt;/span&gt;&lt;span&gt;direktvald&lt;/span&gt;&lt;span&gt;a&lt;/span&gt;&lt;span&gt; fullmäktige. Varje landsting omfattar ett län, utom Gotlands län där kommunen ansvarar för de uppgifter som sköts av landstingen i andra län.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Enligt 14 kap. 6 § regeringsformen ska föreskrifter om grunderna för ändring i rikets indelning i kommuner meddelas i lag. Indelningen av kommuner och landsting regleras i lagen (1979:411) om ändringar i Sveriges indelning i kommuner och landsting&lt;/span&gt;&lt;span&gt;, indelningslagen&lt;/span&gt;&lt;span&gt;. Regeringen får besluta om en ändring i rikets indelning i landsting, om det inte finns hinder mot en ändring i länsindelni&lt;/span&gt;&lt;span&gt;ngen. Av kommunallagen (&lt;/span&gt;&lt;span&gt;2017:725&lt;/span&gt;&lt;span&gt;) framgår att varje landsting omfattar ett län, om inte någ&lt;/span&gt;&lt;span&gt;ot annat är särskilt beslutat&lt;/span&gt;&lt;span&gt;. En ändring i landstingsindelningen får ske bara om den kan antas medföra en bestående fördel för ett landsting eller en del av ett landsting eller andra fördelar från allmän synpunkt. I ett ärende om indelningsändring ska samråd ske med de kommuner och landsting som har intresse av frågan. En indelningsändring träder i kraft den 1 januari det år som bestäms i beslutet om ändringen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Länsstyrelsen &lt;/span&gt;&lt;span&gt;an&lt;/span&gt;&lt;span&gt;svar&lt;/span&gt;&lt;span&gt;ar enligt förordningen (&lt;/span&gt;&lt;span&gt;2017:868&lt;/span&gt;&lt;span&gt;) med länsstyrelse&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;instruktion för den statliga förvaltningen i respektive län, i den utsträckning inte någon annan myndighet har ansvaret för särskilda förvaltningsuppgifter. Länsstyrelsen ska bl.a. verka för att nationella mål får genomslag i länet samtidigt som &lt;/span&gt;&lt;span&gt;hänsyn ska tas till regionala förhållanden och förutsättningar. Länsstyrelsen ska samordna olika samhällsintressen och statliga myndigheters insatser, främja länets utveckling och noga följa tillståndet i länet.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I vissa län har landstinget ansvaret för det regionala utvecklingsarbetet i länet. Detta följer av lagen (2010:630) om regionalt utvecklingsansvar i vissa län. Det regionala utvecklingsansvaret omfattar vissa uppgifter i det regionala tillväxtarbetet och att utarbeta och fastställa en strategi för länets utveckling, samordna insatser för genomförandet av strategin samt upprätta och fastställa länsplaner för regional transportinfrastruktur.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Det förekommer också att kommunala beslutande församlingar bildar samverkansorgan inom ett län för att ansvara för regionala utvecklingsfrågor i länet. De kommuner och landsting som beslutar att bilda sådana samverkans-organ ska anmäla detta till regeringen, som beslutar från vilken tidpunkt organet ska ha det regionala utvecklingsansvaret (lagen [2002:34] om samverkansorgan i länen).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I promemorian Ett enhetligt regionalt utvecklingsansvar (Ds 2017:61) föreslås att lagen om regionalt utvecklingsansvar i vissa län ändras så att lagen omfattar samtliga län. Förslaget innebär även att landstingen får besluta att landstingsfullmäktige och landstingsstyrelsen i stället ska betecknas region&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;fullmäktige respektive regionstyrelse. Eftersom lagen kommer att omfatta samtliga län föreslås att rubriken ändras till lagen om regionalt utvecklings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;ansvar och att lagen om samverkansorgan i länen ska upphöra att gälla.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Lagändringarna föreslås träda i kraft den 1 januari 2019.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Den 1 mars 2018 fattade regeringen beslut om lagrådsremissen Ett enhetligt regionalt utvecklingsansvar&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Av regeringens propositionsförteckning för våren 2018 framgår att regeringen avser att lämna en proposition om &lt;/span&gt;&lt;span&gt;e&lt;/span&gt;&lt;span&gt;tt enhetligt regionalt utvecklingsansvar&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;den 12 april&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;2018.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Indelningskommittén&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Regeringen tillsatte i juli 2015 en kommitté med uppdrag att föreslå en ny regional indelning som innebär att Sverige delas &lt;/span&gt;&lt;span&gt;in &lt;/span&gt;&lt;span&gt;i väsentligt färre län och landsting (Fi 2015:09, dir. 2015:77).&lt;/span&gt;&lt;span&gt; Kommittén har antagit namnet Indel&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;nings&lt;/span&gt;&lt;span&gt;kommittén.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Enligt de ursprungliga direktiven ska kommittén föreslå en ny läns- och landstingsindelning. I uppdraget ingår även att föreslå en ändrad beteckning för kommuner på regional nivå, om det bedöms lämpligt. Kommittén ska vidare föreslå hur landstingen ska tilldelas det regionala utvecklingsansvaret, utreda vilka förvaltningsutgifter detta innebär och lämna förslag på finansiering.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I det ursprungliga uppdraget ingår även att analysera om den&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;nya länsindelningen motiverar en ändrad fördelning av de&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;verksamheter som i dag är koncentrerade till vissa länsstyrelser&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;och, om lämpligt, föreslå förändringar och analysera vilka eventuella&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;åtgärder som kan vidtas för att höja effektiviteten i&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;länsstyrelsernas verksamhet. Kommittén ska vidare beräkna&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;resursbehovet för den nya länsstyrelseorganisationen inom den&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;ekonomiska ram som finns för dagens länsstyrelseverksamhet.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Kommittén ska också analysera behovet av andra verksamhetsorter&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;än residensstaden för varje ny länsstyrelse.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Kommittén ska &lt;/span&gt;&lt;span&gt;dessutom &lt;/span&gt;&lt;span&gt;enligt de ursprungliga direktiven&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;analysera behovet av en samordnad regionindelning &lt;/span&gt;&lt;span&gt;i fråga om &lt;/span&gt;&lt;span&gt;vissa statliga myndig&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;heter, och, om ett sådant behov finns,&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;identifiera de statliga myndigheter för vilka en geografisk&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;samordning kan vara relevant för staten som helhet samt för&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;kommuner och landsting.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I juni 2016 lämnade kommittén delbetänkandet Regional indelning – tre nya län (SOU 2016:48), i vilket det föreslogs att t&lt;/span&gt;&lt;span&gt;re nya län skulle bildas&lt;/span&gt;&lt;span&gt; 2018 och att motsvarande&lt;/span&gt;&lt;span&gt; landsting skulle bildas&lt;/span&gt;&lt;span&gt; 2019. Delbetänkandet har remitterats. Regeringen har dock angett att den inte avser att fortsätta bereda förslagen i delbetänkandet.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Regeringen &lt;/span&gt;&lt;span&gt;beslutade den 22 juni 2017 &lt;/span&gt;&lt;span&gt;i tilläggsdirektiv till &lt;/span&gt;&lt;span&gt;Indelnings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;kommittén&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;att &lt;/span&gt;&lt;span&gt;uppdrag&lt;/span&gt;&lt;span&gt;et&lt;/span&gt;&lt;span&gt; att föreslå en ny regional indelning&lt;/span&gt;&lt;span&gt; och tillhörande delup&lt;/span&gt;&lt;span&gt;p&lt;/span&gt;&lt;span&gt;drag&lt;/span&gt;&lt;span&gt; ska utgå&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;(dir. 2017:72)&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Kommittén ska inte heller utreda länsstyrelsernas organisation eller lämna förslag till hur det regionala utvecklingsansvaret ska tilldelas landstingen. Kommittén behåller dock uppdragen i fråga om beteckningen för kommuner på regional nivå och statliga myndigheters regionala indelning. När det gäller det regionala utveck&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;lingsansvaret behåller &lt;/span&gt;&lt;span&gt;kommittén uppdraget som rör&lt;/span&gt;&lt;span&gt; finansiering av förvaltningsutgifter.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I tilläggsdirektivet förtydligas kommitténs uppdrag i fråga om statliga myndigheters regionala indelning. Kommittén ska föreslå en samordnad regional indelning för de statliga myndigheter för vilka en geografisk samordning är relevant för staten som helhet samt för kommuner och landsting. Vidare får kommittén i uppdrag att föreslå en reglering i indelningslagen om vilken hänsyn som ska tas till berörda landstings och kommuners samt befolkningens synpunkter vid ändringar i landstings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;indelningen. Kommittén får också i uppdrag att kartlägga landstingens samverkan och redogöra för hur landstingen ser på den framtida utvecklingen n&lt;/span&gt;&lt;span&gt;är det gäller samverkan.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Indelningskommittén&lt;/span&gt;&lt;span&gt; överlämnade den 1 mars 2018 betänkandet &lt;/span&gt;&lt;span&gt;Myndighetsgemensam indelning – samverkan på regional nivå&lt;/span&gt;&lt;span&gt; (&lt;/span&gt;&lt;span&gt;SOU 2018:10&lt;/span&gt;&lt;span&gt;). &lt;/span&gt;&lt;span&gt;I betänkandet föreslås en myndighetsgemensam regional indelning för tio statliga myndigheter. &lt;/span&gt;&lt;span&gt;En myndighetsgemensam indelning främjar enligt kommittén samverkan och samordning av staten på regional nivå. Det skulle vara till gagn för medborgare, näringsliv och det civila samhället samt gynna samverkan med kommuner och landsting. Med en gemensam geografisk struktur skulle förutsättningar skapas för att hantera samordni&lt;/span&gt;&lt;span&gt;ngsbehoven, på såväl&lt;/span&gt;&lt;span&gt; regional som lokal nivå. Den gemensamma geografin skulle enligt kommittén kunna fungera som en plattform för samverkan, där olika myndigheter kan analysera problem och behov av insatser. En myndighets&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;gemensam indelning på regional nivå skapar en tydligare regional struktur inom vilken också uppdrag som kräver samordning mellan flera aktörer kan hanteras, när länsnivån inte bedöms vara ändamålsenlig.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I&lt;/span&gt;&lt;span&gt; betänkandet föreslås även att r&lt;/span&gt;&lt;span&gt;egion blir ny beteckning på landstingen. &lt;/span&gt;&lt;span&gt;Indelningskommittén föreslår vidare en ny bestämmelse om att särskild hänsyn ska tas till önskemål och synpunkter från berörda landsting vid ändringar i landstingsindelningen. Det bör även krävas särskilda skäl för att besluta om en ändring mot ett berört landstings vilja. Det föreslås också att särskild hänsyn ska tas till önskemål och synpunkter från kommuner som berörs av en sådan ändring. När det gäller befolkningens önskemål och synpunkter är indelningsfrågors karaktär enligt kommittén sådana att dessa bör beaktas vid ändringar i landstingsindelningen. Därför föreslås att landstingen som ett led i beredningen av ett yttrande eller en ansökan om ändrad landstingsindelning ska inhämta befolkningens önskemål och synpunkter.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Indelningskommittén&lt;/span&gt;&lt;span&gt; konstaterar att det regionala utvecklingsansvaret fr.o.m. 2019 kommer att ligga hos landstingen i alla län utom Gotlands län, där kommunen har ansvaret, förutsatt att förslagen i Ett enhetligt regionalt utvecklingsansvar (Ds 2017:61) genomförs. Kommittén föreslår att de medel som i dag finansierar förvaltningsutgifterna för det regionala utvecklings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;ansvaret ska flyttas från länsstyrelsernas förvaltningsanslag.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Tidigare behandling&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet har i samband med behandlingen av regeringens proposition om ändringar i indelningslagen och i lagen (1992:339) om proportionellt valsätt föreslagit att riksdagen i ett tillkännagivande skulle begära att regeringen ska återkomma med förslag på bestämmelser av innebörden att befolkningens önskemål och synpunkter ska beaktas vid ändringar i landstingsindelningen&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;I en reservation (S, MP, V) föreslogs att riksdagen inte skulle göra något tillkännagivande. &lt;/span&gt;&lt;span&gt;Riksdagen beslutade i enlighet med utskottets förslag (&lt;/span&gt;&lt;span&gt;bet. 2015/16:KU25 s. 13 f., rskr. 2015/16:291).&lt;/span&gt;&lt;span&gt; I sammanhanget kan nämnas att det aktuella tillkännagivandet tas upp i tilläggsdirektiven till Indelnings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;kommittén som nämns ovan (dir. 2017:72).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Motionsyrkanden om &lt;/span&gt;&lt;span&gt;lokal förankring av beslut om regio&lt;/span&gt;&lt;span&gt;ner&lt;/span&gt;&lt;span&gt;, avskaffandet av länsstyrelser och en överföring av statliga u&lt;/span&gt;&lt;span&gt;ppgifter till lokala och regionala organ behandlades även av utskottet i betänkande &lt;/span&gt;&lt;span&gt;2016/17:KU17&lt;/span&gt;&lt;span&gt; (s. 30 f.)&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;När det gäller frågan om behovet av ett folkligt stöd för beslut &lt;/span&gt;&lt;span&gt;om regionaliseringar konstaterade&lt;/span&gt;&lt;span&gt; utskottet att riksdagen under riksmötet &lt;/span&gt;&lt;span&gt;2015/16 &lt;/span&gt;&lt;span&gt;genom ett tillkännagivande uppmanat regeringen att återkomma med förslag på bestämmelser med en sådan innebörd.&lt;/span&gt;&lt;span&gt; Motionsyrkandena avstyrktes. Övriga yrkanden om &lt;/span&gt;&lt;span&gt;regionalisering &lt;/span&gt;&lt;span&gt;avstyrktes med hänvisning till att &lt;/span&gt;&lt;span&gt;bered&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;ningen av Indelningskommitténs delbetän&lt;/span&gt;&lt;span&gt;kande och &lt;/span&gt;&lt;span&gt;kommitténs fortsatta utrednings&lt;/span&gt;&lt;span&gt;arbete inte borde&lt;/span&gt;&lt;span&gt; föregripas.&lt;/span&gt;&lt;span&gt; C&lt;/span&gt;&lt;span&gt;enterpartiet och Kristdemokraterna&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;reserverade sig i fråga om&lt;/span&gt;&lt;span&gt; vissa motionsyrkanden&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet noterar det arbete som pågår och finner inte skäl att &lt;/span&gt;&lt;span&gt;ta några initiativ med anledning av motionerna &lt;/span&gt;&lt;span&gt;2017/18:2345 yrkande&lt;/span&gt;&lt;span&gt;na&lt;/span&gt;&lt;span&gt; 1&lt;/span&gt;&lt;span&gt; och 2 eller &lt;/span&gt;&lt;span&gt;2017/18:3855 yrkande 24&lt;/span&gt;&lt;span&gt; om &lt;/span&gt;&lt;span&gt;en överföring av ansvaret för vissa statliga uppgifter från länsstyrelserna till andra statliga, lokala eller regionala myndigheter eller regioner med valda församlingar&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Motionerna avstyrks således.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet konstaterar &lt;/span&gt;&lt;span&gt;vidare &lt;/span&gt;&lt;span&gt;att &lt;/span&gt;&lt;span&gt;Indelningskommittén&lt;/span&gt;&lt;span&gt; lämnat förslag om&lt;/span&gt;&lt;span&gt; att särskild hänsyn ska tas till önskemål och synpunkter från berörda landsting och kommuner vid ändringar i landstingsindelningen samt att även befolkningens önskemål och synpunkter ska inhämtas. Beredningen av utredningsförslagen bör inte föregripas, varför motionerna &lt;/span&gt;&lt;span&gt;2017/18:3855 yrkande&lt;/span&gt;&lt;span&gt; 25 och &lt;/span&gt;&lt;span&gt;2017/18:3391 yrkande&lt;/span&gt;&lt;span&gt;na&lt;/span&gt;&lt;span&gt; 1 och 2&lt;/span&gt;&lt;span&gt; om&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;lokal förankring av beslut om regioner &lt;/span&gt;&lt;span&gt;bör avslås.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:6704c930-90c9-467c-aabb-4ae632946724/förslagsrutor/892095796/1515656242890; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603151"&gt;&lt;span&gt;En likvärdig välfärd i hela landet&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603151"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;avslår motioner om en likvärdig kommunal service över hela landet&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="Mellanrum"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionerna&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Christina Örnebjär och Emma Carlsson Löfdahl (båda L)&lt;/span&gt;&lt;span&gt; anför i motion 2017/18:422 yrkande 2 att en utredning bör tillsättas för att se över små kommuners bärkraft i framtiden och ta fram lösningar för att säkerställa en likvärdig kommunal service över hela landet.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Said Abdu (L) föreslår i motion 2017/18:133 en nationell standard för välfärdssystemet för att säkerställa en likvärdig offentlig service för alla människor, oavsett kommun. &lt;/span&gt;&lt;span&gt;Den nationella standarden kan förslagsv&lt;/span&gt;&lt;span&gt;is föras in i kommunallagen. Motionären&lt;/span&gt;&lt;span&gt; anför att kommunerna tar sig stora friheter vid budgetsättningen och att det vid kriser ofta spa&lt;/span&gt;&lt;span&gt;ras &lt;/span&gt;&lt;span&gt;in på skolor&lt;/span&gt;&lt;span&gt;, äldrevård och lik&lt;/span&gt;&lt;span&gt;nande för att kunna finansiera visionära stadsbyggnadsprojekt m.m.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Gällande regler&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;I&lt;/span&gt;&lt;span&gt; 1 kap. 1 § regeringsformen &lt;/span&gt;&lt;span&gt;anges att &lt;/span&gt;&lt;span&gt;den svenska folkstyrelsen &lt;/span&gt;&lt;span&gt;förverkligas &lt;/span&gt;&lt;span&gt;genom ett representativt och parlamentariskt &lt;/span&gt;&lt;span&gt;statsskick och&lt;/span&gt;&lt;span&gt; genom kommunal självstyrelse.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Beslutanderätten i kommunerna utövas av valda församlingar&lt;/span&gt;&lt;span&gt;,&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;och kommunerna sköter lokala och regionala angelägenheter av&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;allmänt intresse på den kommunala självstyrelsens grund (14&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;kap. 1 och 2 §§)&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;I 14&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;kap. 3 § finns en proportionalitetsprincip med innebörd att en inskränkning i den kommunala självstyrelsen inte bör gå utöver vad som är nödvändigt med hänsyn till de ändamål som har föranlett den. &lt;/span&gt;&lt;span&gt;Av 14 kap. 4 § följer att k&lt;/span&gt;&lt;span&gt;ommunerna &lt;/span&gt;&lt;span&gt;får &lt;/span&gt;&lt;span&gt;ta ut skatt för skötseln&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;av sina angelägenheter.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Kommunerna får i lag åläggas att bidra till kostnaden för andra kommuners angelägenheter, om det krävs för att uppnå likvärdiga ekonomiska förutsättningar&lt;/span&gt;&lt;span&gt; (14 kap. &lt;/span&gt;&lt;span&gt;5&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;§)&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I 2 kap. k&lt;/span&gt;&lt;span&gt;ommunallag&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt; (2017:725)&lt;/span&gt;&lt;span&gt; finns bestämm&lt;/span&gt;&lt;span&gt;elser och hänvisningar till bestämmelser som reglerar de kommunala befogenheterna och kommunala principer. I 2 kap. 9 § upplyses om att det på vissa områden finns särskilda bestämmelser om kommunernas och landstingens befogenheter och skyldig&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;heter, bl.a. i lagen (2009:47) om vissa kommunala befogenheter. På ett stort antal verksamhetsområden finns det i lag eller annan författning bestämmelser om befogenhet och skyldighet för kommuner och landsting att bedriva viss verksamhet. Sådana bestämmelser kan även innehålla reglering av hur verksamheten ska bedrivas eller undantag från de allmänna principerna för kommunal verksamhet. Exempel på reglering av sådana verksamhetsområden är skollagen (2010:800), socialtjänstlagen (2001:453) och hälso- och sjukvårdslagen (2017:30).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Kommunutredningen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Regeringen gav i februari 2017 en parlamentarisk kommitté i uppdrag att utarbeta en strategi för att stärka kommunernas kapacitet att fullgöra sina uppgifter och hantera sina utmaningar (&lt;/span&gt;&lt;span&gt;Fi 2017:02&lt;/span&gt;&lt;span&gt;,&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;dir. 2017:13). Kommittén, som &lt;/span&gt;&lt;span&gt;har &lt;/span&gt;&lt;span&gt;antagit namnet Kommunutredningen, ska utifrån k&lt;/span&gt;&lt;span&gt;ommunernas varierande förutsätt&lt;/span&gt;&lt;span&gt;ningar dels identifiera och analysera de utmaningar som väntas ha särskilt stor påverkan på kommunernas förmåga att klara av sina uppgifter, dels analysera i vilken utsträckning som kommunal samverkan, kommunsammanläggningar, förändrade uppgifter, en asymmetrisk ansvars&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;fördelning och andra tänkbara åtgärder kan bidra till att stärka kommunern&lt;/span&gt;&lt;span&gt;as förmåga att möta samhälls&lt;/span&gt;&lt;span&gt;utvecklingen. Kommittén ska mot bakgrund av denna analys föreslå vilka åtgärder som bör vidtas och hur genomförandet bör gå till. Kommittén ska lämna sitt slutbetänkande senast den 15 oktober 2019.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Kommunutredningen &lt;/span&gt;&lt;span&gt;har &lt;/span&gt;&lt;span&gt;även &lt;/span&gt;&lt;span&gt;haft &lt;/span&gt;&lt;span&gt;i uppdrag att utreda förutsättningarna för att ge kommu&lt;/span&gt;&lt;span&gt;nerna generella möjligheter att avtalssamverka&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Den del&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt; av uppdraget redovisades i oktober 2017 i delbetänkandet En generell rätt till kommunal avtalssamverkan (SOU 2017:77).&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Regeringen fö&lt;/span&gt;&lt;span&gt;reslår i proposition 2017/18:&lt;/span&gt;&lt;span&gt;151&lt;/span&gt;&lt;span&gt; En generell rätt till kommunal avtalssamverkan att en kommun eller ett landsting ska få ingå avtal om att dess uppgifter helt eller delvis ska utföras av en annan kommun eller ett annat landsting. Genom ett sådant avtal får en kommun eller ett landsting utföra uppgifter åt en annan kommun eller ett annat landsting utan hinder av lokaliseringsprincipen. Ändringarna föreslås träda i kraft den 1 juli 2018.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Regeringen anger i bu&lt;/span&gt;&lt;span&gt;dgetpropositionen för 2018 att K&lt;/span&gt;&lt;span&gt;ommunutredningen&lt;/span&gt;&lt;span&gt;s uppdrag ytterst handlar om att säkerställa att alla kommuner, oavsett förutsättningar, även i framtiden har kapacitet nog att hantera sina uppgifter och möta samhällsutvecklingen, och på så sätt säkerställa en likvärdig och kvalitativ välfärd öv&lt;/span&gt;&lt;span&gt;er hela landet (prop. 2017/18:1&lt;/span&gt;&lt;span&gt; utg.omr&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; 25&lt;/span&gt;&lt;span&gt; s. 24&lt;/span&gt;&lt;span&gt;).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Tidigare behandling&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Frågan om en nationell standard för välfärdssystemet behandlades av utskottet i betänkande 2014/15:KU18&lt;/span&gt;&lt;span&gt; (s. 47 f.)&lt;/span&gt;&lt;span&gt;. Om en nationell standard för ett visst område ska införas borde det enligt utskottet regleras i speciallagstiftning för det området, snarare än i kommunallagen. Utskottet uttalade vidare att en proportionalitetsprövning i så fall ska göras, eftersom en inskränkning i den kommunala självstyrelsen inte bör gå utöver vad som är nödvändigt med hänsyn till de ändamål som har föranlett den. Utskottet, som inte uttalade sig om i vad mån det för olika områden skulle kunna finnas anledning att överväga att införa&lt;/span&gt;&lt;span&gt; nationella standarder, föreslog&lt;/span&gt;&lt;span&gt; att riksdagen &lt;/span&gt;&lt;span&gt;skulle avslå&lt;/span&gt;&lt;span&gt; motione&lt;/span&gt;&lt;span&gt;n. &lt;/span&gt;&lt;span&gt;Riksdagen biföll utskottets förslag.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;M&lt;/span&gt;&lt;span&gt;otion&lt;/span&gt;&lt;span&gt;syrkanden&lt;/span&gt;&lt;span&gt; med samma &lt;/span&gt;&lt;span&gt;innehåll &lt;/span&gt;&lt;span&gt;var i betänkande 2016/17:KU17 föremål för förenklad beredning.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Regeringen har gett &lt;/span&gt;&lt;span&gt;en parlamentarisk kommitté i uppdrag att utarbeta en strategi för att stärka kommunernas kapacitet att fullgöra sina uppgifter och hantera sina utmaningar&lt;/span&gt;&lt;span&gt;. Genom detta uppdrag får &lt;/span&gt;&lt;span&gt;förslag&lt;/span&gt;&lt;span&gt;et i &lt;/span&gt;&lt;span&gt;motion 2017/18:422 yrkande 2&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;anses vara tillgodosett. Motionen avstyrks&lt;/span&gt;&lt;span&gt; därför&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet vidhåller sitt tidigare ställningstagande&lt;/span&gt;&lt;span&gt; i fråga&lt;/span&gt;&lt;span&gt; om en nationell standard för välfärdssystemet och a&lt;/span&gt;&lt;span&gt;vstyrker motion &lt;/span&gt;&lt;span&gt;2017/18:133.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:b532a29b-ea57-4e13-92c0-c5eee366b2fc/förslagsrutor/-544237515/1515779403837; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603152"&gt;&lt;span&gt;Kommunala bidrag till trossamfund&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603152"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;avslår&lt;/span&gt;&lt;span&gt; en motion om &lt;/span&gt;&lt;span&gt;kommunala bidrag till trossamfund&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="Mellanrum"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Markus Wiechel och Johan Nissinen (båda SD) begär i motion 2017/18:2042 &lt;/span&gt;&lt;span&gt;yrkande 1 &lt;/span&gt;&lt;span&gt;att samtliga kommunala bidrag till trossamfund ska tas bort, om bid&lt;/span&gt;&lt;span&gt;ragen inte är kopplade till &lt;/span&gt;&lt;span&gt;bevara&lt;/span&gt;&lt;span&gt;nde av&lt;/span&gt;&lt;span&gt; det svenska kulturarvet.&lt;/span&gt;&lt;span&gt; Motionärerna menar att religion är en privat angelägenhet som inte ska finansieras med offentliga medel.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Gällande ordning&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;D&lt;/span&gt;&lt;span&gt;en grundläggande kommunala kompetensen &lt;/span&gt;&lt;span style="font-family:TimesNewRomanPSMT; font-size:10pt"&gt;regleras&lt;/span&gt;&lt;span&gt; i&lt;/span&gt;&lt;span&gt; 2 kap. 1 § k&lt;/span&gt;&lt;span&gt;ommunal&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;lag&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt; (2017:725)&lt;/span&gt;&lt;span&gt;. I bestämmelsen anges&lt;/span&gt;&lt;span&gt; att k&lt;/span&gt;&lt;span&gt;ommuner och land&lt;/span&gt;&lt;span&gt;sting &lt;/span&gt;&lt;span&gt;själva &lt;/span&gt;&lt;span&gt;får &lt;/span&gt;&lt;span&gt;ha hand om angelägenheter av allmänt intresse som har anknytning till kommunens eller landstingets område eller deras medlemmar.&lt;/span&gt;&lt;span&gt; Allmänintresset förutsätter inte att det finns ett kvantitativt betydande behov&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;av det kommunala engagemanget&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;Vad som utgör en angelägenhet av allmänt intresse &lt;/span&gt;&lt;span&gt;får bedömas med utgångspunkt i om det är lämpligt, ändamålsenligt och skäligt att kommunen eller landstinget befattar sig med angelägenheten&lt;/span&gt;&lt;span&gt; (prop. &lt;/span&gt;&lt;span&gt;2016/17:171&lt;/span&gt;&lt;span&gt; s. 299).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Bidrag till olika föreningar och verksamheter inom kommunen ligger allmänt sett inom den kommunala kompetensen. &lt;/span&gt;&lt;span&gt;Kommunen ställer ofta &lt;/span&gt;&lt;span&gt;upp &lt;/span&gt;&lt;span&gt;olika&lt;/span&gt;&lt;span&gt; villkor för att &lt;/span&gt;&lt;span&gt;en förening&lt;/span&gt;&lt;span&gt; ska kunna ansöka om bidrag. Det kan handla om att föreningen ska ha ett visst an&lt;/span&gt;&lt;span&gt;tal medlemmar eller att d&lt;/span&gt;&lt;span&gt;en ska bedriva verksamhet för en speciell målgrupp. &lt;/span&gt;&lt;span&gt;Villkoren kan även handla om &lt;/span&gt;&lt;span&gt;att &lt;/span&gt;&lt;span&gt;föreningen ska ta ställning för demokratin som samhällssystem och&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;verka för jämställdhet, mång&lt;/span&gt;&lt;span&gt;fald och&lt;/span&gt;&lt;span&gt; alla människors lika värde&lt;/span&gt;&lt;span&gt; (se t.ex. &lt;/span&gt;&lt;span&gt;Stockholm&lt;/span&gt;&lt;span&gt;s&lt;/span&gt;&lt;span&gt; stads r&lt;/span&gt;&lt;span&gt;iktlinjer för bidrag till ideella föreningar&lt;/span&gt;&lt;span&gt; b&lt;/span&gt;&lt;span&gt;eslutade av socialnämnden &lt;/span&gt;&lt;span&gt;den 16 maj 2017&lt;/span&gt;&lt;span&gt;, d&lt;/span&gt;&lt;span&gt;nr 1.2.2-201/2017&lt;/span&gt;&lt;span&gt;). Vissa kommuner&lt;/span&gt;&lt;span&gt;, t.ex. Stockholms stad,&lt;/span&gt;&lt;span&gt; anger i &lt;/span&gt;&lt;span&gt;sina riktlinjer att &lt;/span&gt;&lt;span&gt;bidrag inte får avse religiös verksamhet.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utredning om statens stöd till trossamfunden&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Regeringen gav den 30 juni 2016 en särskild utredare i uppdrag att se över statens stöd till trossamfund (dir. 2016:62, Ku&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;2016:01). Syftet med översynen är att säkerställa att stödet på bästa sätt är anpassat till nutida och framtida behov. Utredaren ska bl.a. analysera det nuvarande stödets effekter för berörda trossamfund och samhället i stort. Utredaren ska föreslå mål för statens stöd till trossamfund med bred förankring bland riksdagspartierna och i övriga samhället. Utredaren ska också föreslå eventuella förändringar av statens nuvarande stöd till trossamfund. I uppdraget ingår också att föreslå ett förtydligat demokratikriterium som är i överensstämmelse med religions&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;friheten&lt;/span&gt;&lt;span&gt; och föreslå nödvändiga författningsändringar.&lt;/span&gt;&lt;span&gt; Enligt tilläggsdirektiv beslutade den &lt;/span&gt;&lt;span&gt;8 juni 2017 &lt;/span&gt;&lt;span&gt;(dir. 2017:63) &lt;/span&gt;&lt;span&gt;ska utredaren också bl.a. kartlägga utbudet &lt;/span&gt;&lt;span&gt;av &lt;/span&gt;&lt;span&gt;och efterfrågan på utbildning i Sverige som är riktad till trossam&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;fundens församlingsledare. Utredaren ska vid behov &lt;/span&gt;&lt;span&gt;även föreslå förändringar av befintligt stöd för att bättre kunna möta trossamfundens olika utbildnings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;behov inom befintliga ekonomiska ramar.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utredningen överlämnade i mars 2018 betänkandet &lt;/span&gt;&lt;span&gt;Statens stöd till trossamfund i ett mångreligiöst Sverige&lt;/span&gt;&lt;span&gt; (&lt;/span&gt;&lt;span&gt;SOU 2018:18&lt;/span&gt;&lt;span&gt;) till regeringen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet finner inte skäl at&lt;/span&gt;&lt;span&gt;t ställa sig bakom det som anförs&lt;/span&gt;&lt;span&gt; i motion&lt;/span&gt;&lt;span&gt;en &lt;/span&gt;&lt;span&gt;och föreslår att motionsyrkandet avslås.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:6a4e3483-8cac-4335-bc32-3973023fb43d/förslagsrutor/2045119754/1516434182183; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603153"&gt;&lt;span&gt;Lokalt brottsförebyggande arbete&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603153"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt"&gt;
					&lt;span&gt;Riksdagen ställer sig bakom det som utskottet anför om kom&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;munernas roll i det brottsförebyggande arbetet&lt;/span&gt;&lt;span&gt; och tillkännager detta för regeringen.&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="Mellanrum"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionerna&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Beatrice Ask m.fl. (M, KD) begär i kommittémotion 2017/18:3125 att &lt;/span&gt;&lt;span&gt;kommunernas roll i det brottsförebyggande arbetet ska utredas&lt;/span&gt;&lt;span&gt; och förtydligas&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;Målet är enligt motionärerna att skapa trygghet i alla kommuner och stads&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;delar. Det krävs därför att alla kommuner tar ett tydligt ansvar för att samordna och leda det lokala brottsförebyggande arbetet. Den kunskap och kompetens som finns hos kommunerna måste enligt motionärerna i högre grad ligga till grund för hur det brottsförebyggande arbetet bedrivs. Om samarbetet mellan kommunerna, civilsamhället och polisen ska bli effektivt finns det ett behov av att representanter på alla sidor har befogenheter att fatta beslut om nödvändiga åtgärder för att bekämpa och förebygga brott. Motionärerna framhåller att det bland landets kommuner finns vitt skilda uppfatt&lt;/span&gt;&lt;span&gt;ningar om vilket ansvar kommunerna&lt;/span&gt;&lt;span&gt; har för att förebygga brot&lt;/span&gt;&lt;span&gt;t&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;Kommunerna har inte heller något tydligt ansvar för att arbeta med livsstilskriminella eller återfallsförbrytare och förmå dem att byta inriktning i livet trots att det vore i hög grad brottsförebyggande.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Även Jan Björklund m.fl. (L) anser i partimotion &lt;/span&gt;&lt;span&gt;2017/18:3576&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;yrkande 20 &lt;/span&gt;&lt;span&gt;att &lt;/span&gt;&lt;span&gt;kommunernas brottsförebyggande ansvar&lt;/span&gt;&lt;span&gt; bör förtydligas. Kommunerna bör enligt motionärerna få en uttalad uppgift att arbeta brottsförebyggande i&lt;/span&gt;&lt;span&gt;nom&lt;/span&gt;&lt;span&gt; sina ansvarsområden.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Magnus Oscarsson m.fl. (KD)&lt;/span&gt;&lt;span&gt; efterfrågar i k&lt;/span&gt;&lt;span&gt;ommittémotion&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;2016/17:2659&lt;/span&gt;&lt;span&gt; yrkande 6 ökad samverkan mellan&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;polisen, kommunerna och lokalsamhället&lt;/span&gt;&lt;span&gt;. Motionärerna ser ett behov&lt;/span&gt;&lt;span&gt; av att utveckla det brottsförebyggande arbetet i kommunerna &lt;/span&gt;&lt;span&gt;och vill även se en utveckling av de samverkansavtal som i dag skrivs mellan polisen och kommunerna.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Gällande ordning&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Kommuner och landsting får&lt;/span&gt;&lt;span&gt; enligt 2 kap. 1 § k&lt;/span&gt;&lt;span&gt;ommunallag&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt; (2017:725) själva ha hand om angelägenheter av allmänt intresse som har anknytning till kommunens eller landstingets område eller deras medlemmar.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Allmänintresset förutsätter inte att det finns ett kvantitativt betydande behov av det kommunala engagemanget. Vad som utgör en angelägenhet av allmänt intresse får bedömas med utgångspunkt i om det är lämpligt, ändamålsenligt och skäligt att kommunen eller landstinget befattar sig med angelägenheten (prop. 2016/17:171 s. 299).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Varje kommun svarar enligt socialtjänstlagen (2001:453) för socialtjänsten inom sitt område och har det yttersta ansvaret för att enskilda får det stöd och den hjälp som de behöver. Socialtjänsten ansvarar bl.a. för att göra sig väl förtrogen med levnadsförhållandena i kommunen, att medverka i samhälls&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;planeringen och att samarbeta med andra&lt;/span&gt;&lt;span&gt; samhällsorgan, organisationer, &lt;/span&gt;&lt;span&gt;föreningar och enskilda för att främja goda miljöer i kommunen. Socialtjänsten ska även bedriva uppsökande verksamhet och på annat sätt främja förutsättningarna för goda levnadsförhållanden. När det är lämpligt ska samverkan ske med andra samhällsorgan och det civila samhällets organisationer. Socialtjänsten har ett särskilt ansvar för barn och unga och ska verka för att förhindra att barn och unga far illa. Socialtjänsten ansvarar också för att ge råd, stöd och annat bistånd till familjer och enskilda som behöver det. En sådan brottsförebyggande insats kan t.ex. vara att erbjuda stöd i föräldraskapet till föräldrar som begått brott eller vars barn begått brott. Till socialtjänstens uppgifter hör också att verka för att&lt;/span&gt;&lt;span&gt; den som utsatts för brott och hans eller h&lt;/span&gt;&lt;span&gt;ennes närstående får stöd och hjälp samt att särskilt beakta våldsutsatta kvinnors behov &lt;/span&gt;&lt;span&gt;av stöd och hjälp. Socialtjänsten&lt;/span&gt;&lt;span&gt; ska &lt;/span&gt;&lt;span&gt;även &lt;/span&gt;&lt;span&gt;arbeta för att förebygga och motverka missbruk av alkohol och andra beroende&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;framkallande medel&lt;/span&gt;&lt;span&gt; och&lt;/span&gt;&lt;span&gt; aktivt sörja &lt;/span&gt;&lt;span&gt;för att den enskilda missbrukaren får den hjälp och vård som han eller hon behöver för att komma ifrån &lt;/span&gt;&lt;span&gt;sitt missbruk&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Kommunerna har planmonopol, vilket innebär att kommunerna har ansvar för planering, utformning och utveckling av den fysiska miljön. Planarbetet ska &lt;/span&gt;&lt;span&gt;enligt p&lt;/span&gt;&lt;span&gt;lan- och bygglag&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt; (2010:900)&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;bidra till en från social synpunkt god livsmiljö. I detta ingår aspekter som trygghet och hälsa.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Kommunerna ansvar&lt;/span&gt;&lt;span&gt;ar&lt;/span&gt;&lt;span&gt; dessutom för den fysiska säkerheten i offentliga lokaler, lokala ordningsföreskrifter, alkoholtillsyn m.m.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;E&lt;/span&gt;&lt;span&gt;tt nationellt brottsförebyggande program&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Regeringen gav i september 2015 ett uppdrag till Brottsförebyggande rådet (Brå) att lämna förslag på hur det nationella stödet till det brottsförebyggande arbetet kan utvecklas. Av Brås redovisning i rapporten Förstärkt stöd till – och samordning av – det lokala brottsförebyggande arbetet (dnr Ju2015/09692/KRIM) framgår att det finns behov av dels bättre samverkan på alla nivåer, dels ett utvecklat nationellt stöd till lokala aktörer, inte minst kommuner. Brå &lt;/span&gt;&lt;span&gt;konstaterar &lt;/span&gt;&lt;span&gt;även &lt;/span&gt;&lt;span&gt;att många aktörer, både kommuner och statliga myndigheter, varken har tillräcklig kunskap eller prioriterar brottsförebyggande arbete i tillräckligt hög utsträckning. Det strategiska arbetet behöver utvecklas&lt;/span&gt;&lt;span&gt;,&lt;/span&gt;&lt;span&gt; och fler aktörer behöver involveras i arbetet.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I regeringens skrivelse 2016/17:126 Tillsammans mot brott – ett nationellt brottsförebyggande program presenterar regeringen ett nationellt program som syftar till att skapa förutsättningar för ett strukturerat och långsiktigt brotts&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;förebyggande arbete i hela samhället. Programmet ska också bidra till att stimulera och entusiasmera fler berörda aktörer att vidta brottsförebyggande åtgärder och att utveckla samverkan, såväl på nationell som på regional och lokal nivå. Det riktar sig till en bred målgrupp såsom myndigheter, landsting, kommuner, näringslivet och det civila samhällets organisationer.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Av skrivelsen framgår regeringens övergripande målsättningar med det brottsförebyggande arbetet. &lt;/span&gt;&lt;span&gt;Det&lt;/span&gt;&lt;span&gt; framgår &lt;/span&gt;&lt;span&gt;också &lt;/span&gt;&lt;span&gt;hur arbetet bör bedrivas för att målen ska uppnås och hur regeringen avser att verka för detta&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Till målsättningarna hör bl.a. ö&lt;/span&gt;&lt;span&gt;kad kunskap i det brottsförebyggande arbetet&lt;/span&gt;&lt;span&gt; och utvecklad samverkan på lokal, regional och nationell nivå. &lt;/span&gt;&lt;span&gt;Regeringen avser bl.a. &lt;/span&gt;&lt;span&gt;att verka för att det kunskapsbaserade brottsförebyggande arbetet utvecklas ytterligare hos kommuner och andra aktörer och att analyser av konsekvenserna för brottsligheten förbättras i samband med politiska beslut och reformer. Regeringen ska även verka för att samarbetet mellan berörda myndigheter på det brottsförebyggande området fördjupas och att fler aktörer i samhället aktivt bidrar till ett effektivt brottsförebyggande arbete.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Nedan beskrivs i korthet några av de delar av programmet som gäller det brottsförebyggande arbetet på lokal och regional nivå.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;En &lt;/span&gt;&lt;span&gt;nationell stöd- och samordningsstruktur&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Sedan &lt;/span&gt;&lt;span&gt;2017 finns en ny stöd- och samordningsstruktur för det brottsföre&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;byggande arbetet på nationell och regional nivå. &lt;/span&gt;&lt;span&gt;För att stödja samverkan mellan relevanta aktörer på olika nivåer och bidra till att det brottsföre&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;byggande arbetet utvecklas på ett effektivt sätt har regeringen bl.a. förstärkt Brås roll som nationell aktör. Brå stöder det lokala brottsförebyggande arbetet genom bl.a. olika skrifter och handböcker, konferensen Råd för framtiden och ekonomiskt stöd. &lt;/span&gt;&lt;span&gt;Vidare har l&lt;/span&gt;&lt;span&gt;äns&lt;/span&gt;&lt;span&gt;styrelserna &lt;/span&gt;&lt;span&gt;fått i uppgift att stödja och&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;bidra till regional samordning av brottsförebyggande arbete enligt&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;förordningen (2016:1258) om regional samordning inom det&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;brottsförebyggande området. &lt;/span&gt;&lt;span&gt;Länsst&lt;/span&gt;&lt;span&gt;yrelserna ska &lt;/span&gt;&lt;span&gt;bidra till förbättrad samverkan och erfarenhetsutbyte mellan berörda aktörer. Länsstyrelserna ska även stödja kompetensutveckling och gemensamma tvärsektoriella utbildningsinsatser inom det brottsföre&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;byggande området. &lt;/span&gt;&lt;span&gt;Länsstyrelserna&lt;/span&gt;&lt;span&gt; ska också verka för kommun&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;överskridande insatser, t.ex. behovsanpassade åtgärder vid geografiskt specifika brottsfenomen, något som särskilt små kommuner enligt regeringen kan ha svårt att ordna i egen regi. Den regionala nivån kan på detta sätt samordna och stödja utvecklingsarbetet så att det blir mer kunskapsbaserat och effektivt.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Sveri&lt;/span&gt;&lt;span&gt;ges Kommuner och Landsting&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Sveriges Kommuner och Landsting (SKL)&lt;/span&gt;&lt;span&gt; arbetar enligt regeringen aktivt inom det brottsförebyggande och trygghetsskapande området och stöttar kommunerna i att arbeta kunskapsbaserat med utgångspunkt i lokala problem&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;bilder. SKL har bl.a. tillsammans med Brå och Polismyndigheten tagit fram boken Samverkan i lokalt brottsförebyggande arbete som enligt regeringen fått stor spridning bland Sveriges kommuner. SKL har ett nätverk för kommuner som arbetar aktivt med brottsförebyggande frågor och som träffas regelbundet för att utbyta erfarenheter och diskutera aktuella frågor inom det brottsföre&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;byggande området.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Områdespoliser, kommunpoliser och medborgardialoger&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent" style="text-indent:0pt"&gt;
				&lt;span&gt;Regeringen anför att en utgångspunkt i den ombildning som Polismyndigheten genomförde 2015 bl.a. är att åstadkomma en mer lokalt förankrad polis, där beslut om verksamhetens inriktning till stora delar ska utgå från lokala problembilder. Som ett led i anpassningen till en lokalt förankrad polis har det inrättats två nya funktioner i Polismyndigheten, områdespolis och kommunpolis. Områdespolisernas uppdrag är att arbeta långsiktigt med kontaktskapande, brottsförebygga&lt;/span&gt;&lt;span&gt;nde och trygghetsskapande&lt;/span&gt;&lt;span&gt; utifrån den lokala problembilden. I varje lokalpolisområde ska det även finnas en samordningsfunktion, kommunpolis. Kommunpolisens uppdrag är att säkra kontinuitet i arbetet med samverkan med kommunerna och andra lokala aktörer utifrån behov. Huvuduppdraget är att driva och vara en motor i polisens brottsförebyggande och trygghetsskapande arbete.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;En annan utgångspunkt i ombildningen av polisen är &lt;/span&gt;&lt;span&gt;enligt regeringen &lt;/span&gt;&lt;span&gt;att medborgarna&lt;/span&gt;&lt;span&gt; på ett tydligare sätt än tidig&lt;/span&gt;&lt;span&gt;are ska komma till tals genom s.k.&lt;/span&gt;&lt;span&gt; medborgardialoger. En modell har skapats för att kunna omhänderta synpunkter från dialogerna och utifrån dessa utforma lokala medborgarlöften. Medborgarlöftena syftar till att säkerställa att den lokala problembilden beaktas vid prioriteringar och att polisen ska komma närmare medborgarna. De bidrar också till en närmare samverkan med kommunerna.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;L&lt;/span&gt;&lt;span&gt;okala brottsförebyggande råd&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;och annan lokal samverkan&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;I de flesta kommuner finns någon form av strategisk samverkansorganisation som hanterar brottsförebyggande frågor. Polismyndigheten deltar i princip alltid i denna samverkan. Sådan samverkan kan ha olika namn, exempelvis lokalt brottsförebyggande råd, trygghetsråd eller folkhälsoråd. De minsta lokala råden kan bestå av lokal polischef, kommunchef eller kommunalråd och en samordnare från kommunen. Råden kan också ha många fler representanter från andra delar av den&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;kommunala förvaltningen, myndigheter och i undantagsfall även från&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;andra organisationer eller näringslivet. Det finns också ofta andra mer&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;operativa samverkansgrupper som delvis arbetar brottsföre&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;byggande,&lt;/span&gt;&lt;span&gt; t.ex.&lt;/span&gt;&lt;span&gt; bostadsområdesgrupper&lt;/span&gt;&lt;span&gt; eller direkt individfokuserade&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;initiativ som sociala insatsgrupper där Polismyndigheten, socialtjänsten&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;m.fl. går samman och riktar stödjande insatser mot en enskild individ&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;som riskerar &lt;/span&gt;&lt;span&gt;att dras in i kriminalitet. Dessa samverkansformer kan vara&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;mer eller mindre knutna till brottsförebyggande råd eller motsvarande&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Samverkan förutsätter&lt;/span&gt;&lt;span&gt; enligt regeringen&lt;/span&gt;&lt;span&gt; att det finns en funktion som håller ihop och&lt;/span&gt;&lt;span&gt; driver på det lokala arbetet. Kommunpolisen har till uppgift att säkra kontinuitet i arbetet med samverkan med kommunerna och andra lokala aktörer utifrån behov. Regeringen framhåller vikten av att det även finns en kommunal samordnare som kan hålla ihop arbetet lokalt. De lokala råden bör &lt;/span&gt;&lt;span&gt;vidare &lt;/span&gt;&lt;span&gt;enligt regeringens mening inte enbart vara ett forum för informations&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;utbyte. Rådet och dess ledamöter bör också ha mandat från respektive organisation för att kunna driva på och utveckla det brottsförebyggande arbetet på lokal nivå så att det leder fram till konkreta brottsförebyggande aktiviteter.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Regeringen uppger att Brå vid studier av samverkan mellan kommuner och Polismyndigheten har konstaterat att det lokala arbetet vanligtvis fokuserar på sociala åtgärder som syftar till att påverka ungas motivation att begå brott. Åtgärder för att försvåra genomförandet av brott, dvs. situationellt brottsföre&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;byggande arbete, är däremot relativt ovanliga. Utifrån de lokala behov som identifierats bör samverkande parter därför enligt regeringen uppmuntras att överväga en breddning av arbetet till att omfatta även situationella aspekter av brottsförebyggande arbete. Fler aktörer kan då behöva involveras, exempelvis andra förvaltningar inom kommunerna som inte alltid har kunskap om hur deras verksamhet skulle kunna förebygga brott, eller i vissa fall riskerar att bidra till att det är lättare att begå brott.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Samverkansöverenskommelser&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Sedan 2008 samverkar Polismyndigheten med kommuner genom s.k. samverkansöverenskommelser där lokala problembilder och behov av brotts&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;förebyggande insatser identifieras. Det finns enligt regeringen sådana överenskommelser i närmare 90 procent av landets kommuner. Samverkans&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;överenskommelser ger förutsättningar för struktur och systematik och beskriver de brottsproblem som parterna har valt att samverka om. Enligt regeringen b&lt;/span&gt;&lt;span&gt;idrar överenskommelserna &lt;/span&gt;&lt;span&gt;till att ge ett helhetsperspektiv och skapa samsyn kring problembild&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt;, vilka åtgärder som behöver vidtas och arbetsfördelning&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Regeringen &lt;/span&gt;&lt;span&gt;avser att&lt;/span&gt;&lt;span&gt; verka för&lt;/span&gt;&lt;span&gt; att samverkansöverens&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;kommelserna utvecklas och i högre utsträckning utgår från lokala behov.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Statskontorets utvärdering av &lt;/span&gt;&lt;span&gt;ombildningen av polisen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Den 1 januari 2015 ombildades polisen till en sammanhållen myndighet, Polismyndigheten. Regeringen gav i april 2014 Statskontoret i uppdrag att u&lt;/span&gt;&lt;span&gt;tvärdera ombildningen&lt;/span&gt;&lt;span&gt; (Ju2014/2492/PO). Den första delrapporten av uppdraget re&lt;/span&gt;&lt;span&gt;dovisades till regeringen i&lt;/span&gt;&lt;span&gt; september 2016 oc&lt;/span&gt;&lt;span&gt;h den andra delrapporten i &lt;/span&gt;&lt;span&gt;september 2017. Slutredovisningen ska ske senast den 1 oktober 2018.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Av den andra delrapporten &lt;/span&gt;&lt;span&gt;Ombildningen till en sammanhållen polis&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;myndighet, Delrapport 2 – om den&lt;/span&gt;&lt;span&gt; nya organisationens genomslag fr&lt;/span&gt;&lt;span&gt;amgår bl.a. följande (s. 58 f.).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Omorganisationen av polisen är tänkt att främja det lokala brotts&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;förebyggande arbetet. Införande av kommunpolis, medborgarlöften och områdespolis ska förstärka samverkan lokalt och bidra till att polisen kommer närmare medborgarna. De samverkansöverenskommelser mellan polisen och kommunerna som redan tidigare fanns i en majoritet av kommunerna är ett viktigt ramverk för samverkan.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Kommunpolisen ska fungera som en kontaktväg till Polismyndigheten för samverkanspartner och allmänheten. Nästan alla kommuner har i dag tillgång till en kommunpolis. I de lokalpolisområden som har studerats närmare uppger både kommunpoliser och kommunföreträdare att kommunpoliserna har bidragit till att samverkan har blivit mer strukturerad. En majoritet av kommunernas ansvariga för övergripande samverkan med polisen anser att såväl polisens tillgänglighet för att arbeta med problemen i kommunen, polisens kännedom om lokala förhållanden som ansvarsförhållandena inom polisen har förbättrats till följd av omorganisationen. Däremot är det oklart om handläggningstiderna har förbättrats.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Som en del av polisreformen arbetar Polismyndigheten även med s.k. medborgarlöften. Medborgarlöften ska bidra till att polisen kommer närmare medborgarna, vilket är ett av målen för omorganisationen. Löftena ska utgå från den lokala lägesbilden och tas fram i samverkan med kommuner, polisens medarbetare och medborgare genom medborgardialoger. De ska ses som samverkansöverenskommelsernas publika del och vara utformade som specificerade åtgärder som polisen och kommunen lovar medborgarna att genomföra under innevarande år. Vid utgången av 2016 fanns det medborgarlöften i 275 av landets 290 kommuner. Statskontoret konstaterar att Polismyndigheten följer upp hur många medborgarlöften som har tagits fram. Däremot saknar myndigheten verktyg för att t.ex. följa upp arbetsmetoden medborgarlöften, den kommunikativa aspekten av dem och vilken påverkan löftena har på den upplevda tryggheten. På Brå pågår på uppdrag av Polismyndigheten ett flerårigt arbete med att utvärdera metodiken kring medborgarlöften.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Statskontoret anför vidare att Polissamordningen slog fast att det ska finnas områdespoliser i varje lokalpolisområde, men hur många de ska vara är det upp till regionerna att bedöma. Deras uppdrag är att långsiktigt arbeta brottsförebyggande, trygghetsskapande och kontaktskapande utifrån en lokal problembild. Områdespolisens uppdrag är inte definierat i arbetsordningen så som kommunpolisens uppdrag är. Enligt Polismyndig&lt;/span&gt;&lt;span&gt;heten fanns det &lt;/span&gt;&lt;span&gt;447 områdespoliser &lt;/span&gt;&lt;span&gt;i maj 2017&lt;/span&gt;&lt;span&gt;, fördelade på 63 lokalpolisområden.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Statskontorets slutsats är att det brottsförebyggande arbetet riskerar att inte få genomslag även om den övergripande samverkan har förbättrats. Bland annat beror detta enligt Statskontoret på att införandet av områdespoliser, som ska förstärka det brottsförebyggande arbetet, inte har varit strukturerat och att det brottsförebyggande arbetet har låg status inom polisen. En del av medborgarlöftena är vaga, och polisens uppföljning av dem är svag. Sammantaget riskerar detta&lt;/span&gt;&lt;span&gt; att&lt;/span&gt;&lt;span&gt; innebära att polisen inte kommer att nå målet om en förbättrad kontakt med medborgarna.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Budgetpropositionen för 2018&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Regeringen anför &lt;/span&gt;&lt;span&gt;i budgetpropositionen för 2018 (prop. 2017/18:1 utg.omr. 4 &lt;/span&gt;&lt;span&gt;s. 42) att &lt;/span&gt;&lt;span&gt;den &lt;/span&gt;&lt;span&gt;ser positivt på det utvecklingsarbete som pågår inom flera rättsvårdande myndigheter, bl.a. Polismyndighetens arbete för att säkerställa en lokalt förankrad polisverksamhet. Väl utarbetade lokala problembilder med konkreta och uppföljningsbara aktiviteter är enligt regeringen grunden för ett framgångsrikt brottsförebyggande och brottsbekämpande arbete. Regeringen ser även positivt på det utvecklingsarbete som Brå har påbörjat och som innebär förstärkta insatser för ett mer kunskapsbaserat, effektivt och samordnat brottsförebyggande arbete över hela landet. Lokal samverkan mellan såväl myndigheter som andra aktörer inom det brottsförebyggande arbetet är enligt regeringen nödvändigt (s. 24). En metod som har använts för att få en tydlig struktur i samverkan mellan bl.a. polisen och kommunerna är samverkansöverenskommelser. Vid utgången av 2016 hade Polismyndigheten tecknat sa&lt;/span&gt;&lt;span&gt;mverkans&lt;/span&gt;&lt;span&gt;överenskommelser i 250 av landets 290 kommuner.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Regeringen anser dock (s. 42) att det är nödvändigt att Polismyndigheten utvecklar metoder för att följa upp, utvärdera och redovisa resultaten av den förebyggande verksamhet&lt;/span&gt;&lt;span&gt;en. Detta gäller även tillämpningen&lt;/span&gt;&lt;span&gt; av samverkans&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;överenskommelser och medborgarlöften. Regeringen anför att det brottsföre&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;byggande arbetet måste fortsätta att utvecklas. Till exempel är aktörer utanför rättsväsendet i dag inte tillräckligt involverade, och det brottsförebyggande arbetet bedrivs generellt sett inte tillräckligt strukturerat på lokal, regional och nationell nivå.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Brottsförebyggande rådet&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Den 16 februari 2017 fick Brå i uppdrag att årligen beskriva det brottsföre&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;byggande arbetet i en årsrapport (Ju 0062/17).&lt;/span&gt;&lt;span&gt; Den första rapporten lämnades i mars 2017. I rapporten beskrivs&lt;/span&gt;&lt;span&gt; uppbyggnaden och utvecklandet av den verksamhet som Brå bedriver i form av stöd till lokalt brottsförebyggande arb&lt;/span&gt;&lt;span&gt;ete. I kommande &lt;/span&gt;&lt;span&gt;rapporter ska Brå ge&lt;/span&gt;&lt;span&gt; en mer utförlig beskrivning av verksamheten och organisationen av regionalt och lokalt&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;brottsförebyggande &lt;/span&gt;&lt;span&gt;arbete och göra&lt;/span&gt;&lt;span&gt; mer utförliga bedömningar av&lt;/span&gt;&lt;span&gt; utvecklingsbehoven&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;På Brås webbplats (&lt;/span&gt;&lt;a style="color:#000000" href="http://www.bra.se"&gt;&lt;span class="Hyperlink"&gt;www.bra.se&lt;/span&gt;&lt;/a&gt;&lt;span&gt;) presenteras &lt;/span&gt;&lt;span&gt;några av de projekt som Brå arbetar med inom det brottsförebyggande området.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Projektet &lt;/span&gt;&lt;span&gt;Stöd till regionalt brottsförebyggande arbete&lt;/span&gt;&lt;span&gt; grundar sig i att Brå s&lt;/span&gt;&lt;span&gt;edan början av 2017 h&lt;/span&gt;&lt;span&gt;ar&lt;/span&gt;&lt;span&gt; i uppdrag att stödja Sveriges länsstyrelser i deras brottsförebyggande arbete.&lt;/span&gt;&lt;span&gt; Brå s&lt;/span&gt;&lt;span&gt;ka bistå länsstyrelserna&lt;/span&gt;&lt;span&gt; i&lt;/span&gt;&lt;span&gt; arbete&lt;/span&gt;&lt;span&gt;t&lt;/span&gt;&lt;span&gt; med att inrätta och utveckla regionala samordnare. Brås stöd till länsstyrelserna ska bidra till utvecklingen av ett kunskapsbaserat regionalt och lokalt hållbart brottsförebyggande arbete. &lt;/span&gt;&lt;span&gt;Projektet&lt;/span&gt;&lt;span&gt; pågår&lt;/span&gt;&lt;span&gt; t.o.m. 2019.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I Brås projekt Stöd till typområden ges ett riktat processtöd till särskilt angelägna utvecklingsområden för det lokala brottsförebyggande arbetet. I typområdena ingår&lt;/span&gt;&lt;span&gt; representanter från bl.a.&lt;/span&gt;&lt;span&gt; polis och kommun.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Stödet ges för att &lt;/span&gt;&lt;span&gt;förbättra förmågan &lt;/span&gt;&lt;span&gt;att ta fram lokala lägesbilder, prioritera mellan problem och sätta mål för det brottsförebyggande arbetet. Erfarenheterna och kunskaperna från typområdena &lt;/span&gt;&lt;span&gt;ska sedan &lt;/span&gt;&lt;span&gt;sprid&lt;/span&gt;&lt;span&gt;a&lt;/span&gt;&lt;span&gt;s till andra kommuner och lokalpolisområden som har liknande utmaningar och förutsättningar.&lt;/span&gt;&lt;span&gt; Brå har valt ut tre typer av utvecklingsområden: fördjupning och utveckling av samverkan mellan polis och kommun, brottsförebyggande arbete som är ny- eller omstart samt brottsförebyggande arbete för mindre kommuner.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Projektet ge&lt;/span&gt;&lt;span&gt;nomförs under 2016–&lt;/span&gt;&lt;span&gt;2018.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Brå bedriver även ett u&lt;/span&gt;&lt;span&gt;tvecklingsprojekt kring brottsförebyggande arbete i socialt utsatta områden&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;Fokus för &lt;/span&gt;&lt;span&gt;projektet ligger särskilt&lt;/span&gt;&lt;span&gt; på att utveckla en metodik för ett konkret samverkansarbete som fungerar i det vardagliga arbetet i dessa områden.&lt;/span&gt;&lt;span&gt; I &lt;/span&gt;&lt;span&gt;projekt&lt;/span&gt;&lt;span&gt;et&lt;/span&gt;&lt;span&gt; arbetar Brå tillsammans med lokal polis, lokala fastighetsägare och kommuner från sju områden med att utveckla ett arbetssätt som omfattar både långsiktigt brottsförebyggande och trygghetsskapande arb&lt;/span&gt;&lt;span&gt;ete och ett mer incidentinriktat&lt;/span&gt;&lt;span&gt; arbete, där man snabbt kan mobilisera gemensamma resurser.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Sedan 2016 bedriver Brå också ett u&lt;/span&gt;&lt;span&gt;tvecklingsprojekt kring situationell prevention&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;som syftar till att höja kunskapsnivån om s&lt;/span&gt;&lt;span&gt;ådant &lt;/span&gt;&lt;span&gt;arbete.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Projektet riktar sig främst till lokala brottsförebyggande aktörer inom kommun och polis&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Uppföljning av det brottsförebyggande programmet&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet har fått information av &lt;/span&gt;&lt;span&gt;Justitiedepar&lt;/span&gt;&lt;span&gt;tementet&lt;/span&gt;&lt;span&gt; om att departementet för närvarande arbetar med en uppföljning av det brottsförebyggande programmet &lt;/span&gt;&lt;span&gt;Tillsammans mot brott&lt;/span&gt;&lt;span&gt;. Det innebär bl.a. att departementet samlar information om hur andra departement och myndigheter arbetar med de målsättningar som framgår av programmet och om vilka åtgärder som har vidtagits. Brå ska även lämna sin å&lt;/span&gt;&lt;span&gt;rsrapport för det brottsförebyggande arbetet &lt;/span&gt;&lt;span&gt;den 31 mars 2018.&lt;/span&gt;&lt;span&gt; Därefter kommer regeringen att ha ett underlag för att bedöma vilka konkreta åtgärder som behöver vidtas.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Av skrivelsen Tillsammans mot brott framgår också att regeringen har för avsikt att återkomma med en ny skrivelse när programmet &lt;/span&gt;&lt;span&gt;har &lt;/span&gt;&lt;span&gt;varit i kraft en tid för att beskriva utvecklingen av det brottsförebyggande arbetet.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Tidigare behandling&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Motioner om lokalt brottsförebyggande arbete&lt;/span&gt;&lt;span&gt; behandlades av utskottet i betänkande 2014/15:KU18. &lt;/span&gt;&lt;span&gt;Utskottet uttryckte&lt;/span&gt;&lt;span&gt; sitt stöd för att kommun&lt;/span&gt;&lt;span&gt;erna deltar aktivt i ett brotts&lt;/span&gt;&lt;span&gt;förebyggande arbete som bedrivs lokalt och i samverkan mellan olika aktörer, som polisen och &lt;/span&gt;&lt;span&gt;kommunerna. Utskottet &lt;/span&gt;&lt;span&gt;betona&lt;/span&gt;&lt;span&gt;de även&lt;/span&gt;&lt;span&gt; vikten av att kommunernas socialnämnder lever upp till sitt ansvar enligt socialtjänstlagen när det gäller brottsoffer. Utskottet&lt;/span&gt;&lt;span&gt;, som utgick&lt;/span&gt;&lt;span&gt; från att denna uppfattning även dela&lt;/span&gt;&lt;span&gt;des av regeringen, föreslog att riksdagen skulle avslå&lt;/span&gt;&lt;span&gt; motionerna&lt;/span&gt;&lt;span&gt; (s. 45).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Motionsyrkanden om lokalt brottsförebyggande arbete&lt;/span&gt;&lt;span&gt; var i betänkande 2016/17:KU17 föremål för förenklad beredning.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Regeringens s&lt;/span&gt;&lt;span&gt;krivelse 2016/17:126&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Tillsammans mo&lt;/span&gt;&lt;span&gt;t brott – ett nationellt brotts&lt;/span&gt;&lt;span&gt;förebyggande program&lt;/span&gt;&lt;span&gt; behandlades av&lt;/span&gt;&lt;span&gt; j&lt;/span&gt;&lt;span&gt;ustitieutskottet i&lt;/span&gt;&lt;span&gt; betänkande 2016/17:JuU15. &lt;/span&gt;&lt;span&gt;Justitie&lt;/span&gt;&lt;span&gt;utskottet föreslog&lt;/span&gt;&lt;span&gt; att riksdagen &lt;/span&gt;&lt;span&gt;skulle lägga&lt;/span&gt;&lt;span&gt; skrivelse&lt;/span&gt;&lt;span&gt;n&lt;/span&gt;&lt;span&gt; till handlingarna.&lt;/span&gt;&lt;span&gt; U&lt;/span&gt;&lt;span&gt;tskottet &lt;/span&gt;&lt;span&gt;föreslog även &lt;/span&gt;&lt;span&gt;ett tillkännagivande till regeringen med anledning av motionsyrkanden om att regeringen dels inte ska tillsätta en nationell samordnare för brottsförebyggande frågor, dels ska återkomma till riksdagen med en redovisning av vilka konkreta&lt;/span&gt;&lt;span&gt; brottsförebyggande åtgärder&lt;/span&gt;&lt;span&gt; regeringen avser att vidta och när man avser att vidta dessa åtgärder&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;I en reservation (S, MP, V) föreslogs att riksdagen inte skulle göra något tillkännagivande. &lt;/span&gt;&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;beslutade i enlighet med utskottets förslag (rskr. 2016/17:321&lt;/span&gt;&lt;span&gt;)&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Motioner om lokalt brottsförebyggande arbete behandlades även av justitie&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;utskottet i samband med behandlingen av budgetpropositionen för 2018&lt;/span&gt;&lt;span&gt; (bet. &lt;/span&gt;&lt;span&gt;2017/18:JuU1&lt;/span&gt;&lt;span&gt; s. 91)&lt;/span&gt;&lt;span&gt;. Justitieu&lt;/span&gt;&lt;span&gt;tskottet uttalade bl.a. att det &lt;/span&gt;&lt;span&gt;är viktigt för människors känsla av trygghet&lt;/span&gt;&lt;span&gt; a&lt;/span&gt;&lt;span&gt;tt polisen känns närvarande i alla delar av landet. Det är därför &lt;/span&gt;&lt;span&gt;enligt justitieutskottet &lt;/span&gt;&lt;span&gt;viktigt att åtgärder vidtas för att åtgärda de brister som redovisats i Statskontorets delrapport när det gäller områdespoliser och kommunpoliser.&lt;/span&gt;&lt;span&gt; Justitieutskottet hänvisade även till ett tidigare tillkännagivande om &lt;/span&gt;&lt;span&gt;områdespoliser och kommunpoliser&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;(&lt;/span&gt;&lt;span&gt;bet. &lt;/span&gt;&lt;span&gt;2016/17:JuU1&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;s. 69&lt;/span&gt;&lt;span&gt;) och konstaterade att r&lt;/span&gt;&lt;span&gt;eger&lt;/span&gt;&lt;span&gt;ingen &lt;/span&gt;&lt;span&gt;anfört att man kommer att avvakta vidare redovisning från Polismyndigheten i årsredovisningen för 2017 och Statskontorets slutrapport hösten 2018 för att därefter ta ställning till eventuella&lt;/span&gt;&lt;span&gt; åtgärder. Mot denna bakgrund fa&lt;/span&gt;&lt;span&gt;nns det enligt utskottet inte&lt;/span&gt;&lt;span&gt; anledning att &lt;/span&gt;&lt;span&gt;föreslå ytterligare &lt;/span&gt;&lt;span&gt;tillkännagivanden om &lt;/span&gt;&lt;span&gt;områdespoliser och kommunpoliser&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; Utskottet såg vidare&lt;/span&gt;&lt;span&gt; positivt på att användningen av medborgarlöften ökar. Dessa kan enligt utskottet bidra till att utveckla kontakterna mellan polisen och medborgarna. &lt;/span&gt;&lt;span&gt;Utskottet hänvisade till att &lt;/span&gt;&lt;span&gt;Brå påbörjat ett flerårigt arbete med att utvärdera metodiken kring medborgar&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;löften&lt;/span&gt;&lt;span&gt; och avslog ett motionsyrkande om att medborgarlöftena &lt;/span&gt;&lt;span&gt;ska utvärderas löpande&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;En reservation lämnades &lt;/span&gt;&lt;span&gt;(M, C, L, &lt;/span&gt;&lt;span&gt;KD&lt;/span&gt;&lt;span&gt;).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets&lt;/span&gt;&lt;span&gt; ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Det brottsförebyggande arbetet behöver långsiktighet och förankring i den lokala miljön där arbetet bedrivs. Därför har kommunerna och andra lokala aktörer en nyckelroll i det brottsförebyggande arbetet.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet anser att l&lt;/span&gt;&lt;span&gt;agen behöver förtydligas så att kommunerna får en uttalad uppgift att arbeta brottsförebyggande inom ramen för sina ansvars&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;områden. I dag finns det bestämmelser i socialtjänstlagen som belyser ansvaret för stöd till brottsoffer, och kommunerna har också ett särskilt ansvar för unga. Däremot finns det skilda uppfattningar inom kommunsektorn om hur långt kommunernas ansvar sträcker sig för de brottsförebyggande insatserna i stort.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;För att skapa och upprätthålla tryggheten lokalt måste det finnas en samverkan där både kommun och polis deltar. Polismyndighetens arbete med lokala samverkans&lt;/span&gt;&lt;span&gt;överenskommelser&lt;/span&gt;&lt;span&gt; och medborgarlöften m.m. bör kompletteras med att kommunernas roll i det brottsförebyggande arbetet får en tydligare reglering i lag.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Utskottet föreslår att riksdagen tillkännager detta för regeringen. Därmed tillstyrker utskottet motion &lt;/span&gt;&lt;span&gt;2017/18:3576 yrkande 20&lt;/span&gt;&lt;span&gt; och tillstyrker delvis motionerna &lt;/span&gt;&lt;span&gt;2017/18:3125&lt;/span&gt;&lt;span&gt; och &lt;/span&gt;&lt;span&gt;2016/17:2659 yrkande 6&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:3bffdd24-8321-45c5-8d70-e2f4b837a2e0/förslagsrutor/1786367098/1515996697375; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc510603154"&gt;&lt;span&gt;Pensionärsråd&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc510603154"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;avslår motioner om kommunala&lt;/span&gt;&lt;span&gt; pensionärsråd&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="Mellanrum"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Motionerna&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Solveig Zander (C) anför i motion 2017/18:243 att det i samtliga kommuner i landet bör finnas ett kommunalt pensionärsråd. För att kunna vidta rätt åtgärder behöv&lt;/span&gt;&lt;span&gt;er politikerna &lt;/span&gt;&lt;span&gt;få vetskap om vad som är angeläget för de äldre. Ett samarbete mellan kommunerna och det civila samhället är &lt;/span&gt;&lt;span&gt;enligt motionären &lt;/span&gt;&lt;span&gt;nödvändigt för att möta de behov som dagens pensionärer ha&lt;/span&gt;&lt;span&gt;r. &lt;/span&gt;&lt;span&gt;Å&lt;/span&gt;&lt;span&gt;tgärder måste &lt;/span&gt;&lt;span&gt;därför &lt;/span&gt;&lt;span&gt;vidtas för att förmå kommunerna att inrätta fungerande kommunala pensionärsråd. En liknande begäran framförs av Åsa Lind&lt;/span&gt;&lt;span&gt;estam (S) i motion 2017/18:2229&lt;/span&gt;&lt;span&gt; yrkande 2. Enligt motionären bör regeringen se över möjligheten att införa en lagstadgad skyldighet för kommuner, landsting och regioner att samverka med pensionärsorganisationer i särskilda pensionärsråd.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Bakgrund&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;I många kommuner finns det pensionärsråd som är organ för samråd och&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;ömsesidig information mellan kommunen och företrädare för pensionärernas&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;organisationer inom kommunen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Socialstyrelsen diskuterade i rapporten Pensionärsråd i Sverige och Norden,&lt;/span&gt;&lt;span&gt; Äldreuppdraget 2000:6, erfarenheter från lokala pensionärsråd både i Sverige och i de övriga nordiska länderna. En enkätundersökning bland pensionärsråden som genomfördes 1997 visade att mindre än hälften av de kommunala pensionärsråden ansåg att de fungerade tillfredsställande. Något fler pensionärsråd uppfattade sig som&lt;/span&gt;&lt;span&gt; en&lt;/span&gt;&lt;span&gt; remissinstans än vid en motsvarande undersökning 1988. De landstingskommunala pensionärsråden tycktes fungera bättre än de kommunala. I rapporten hänvisades till att det i Danmark och Norge sedan början av 1990-talet finns en tvingande lagstiftning om pensionärsråd.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Även i Sverige har det förts en diskussion om lagstiftning. Företrädare&lt;/span&gt;&lt;span&gt; för de fem fria pensionärsförbunden förordade detta. Det var dock osäkert om lagstiftning verkligen skulle leda till ett större inflytande, anförde Socialstyrelsen. Troligare var att när pensionärskollektivet växte, när de stora 40-talskullarna några år senare skulle gå i pension, skulle detta kollektiv ställa andra och &lt;/span&gt;&lt;span&gt;större krav på verkligt inflytande och ha resurser att göra sin röst hörd. För att pensionärsråden i framtiden skulle fungera bättre krävdes enligt styrelsen dels att politiker och tjänstemän tog till vara den resurs som råden kunde utgöra, dels att pensionärsledamöterna var pålästa och väl insatta i de frågor som behandlades och vågade och orkade ställa&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;berättigade krav.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Våren 2001 avstyrkte socialutskottet (bet. 2000/01:SoU9) en motion om&lt;/span&gt;&lt;span&gt; lagstiftning om pensionärsråden. Socialutskottet framhöll att många äldre aktivt deltar i föreningsliv och frivilligverksamheter liksom i politiska organisationer. Socialutskottet ville betona betydelsen av såväl pensionärs&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;organisationernas arbete som pensionärsråden. Socialutskottet delade dock bedömningen att det var osäkert om en lagstiftning om pensionärsråd skulle leda till ett större inflytande för dessa. Det ankom på kommuner och landsting att utveckla pensionärsrådens verksamhet ytterligare&lt;/span&gt;&lt;span&gt; och att bättre ta till vara dessas&lt;/span&gt;&lt;span&gt; kunskap och kompetens. Socialutskottet gjorde samma bedömning under påföljande riksmöte (bet. 2001/02:SoU12).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I regeringens skrivelse 2003/04:110 Demokratipolitik hänvisades till Äldreberedningen Senior 2005:s slutbetänkande Äldrepolitik i framtiden (SOU 2003:91). Äldreberedningen Senior 2005 framhöll i sitt slutbetänkande att människor i alla åldrar måste omfattas av arbetet med att utveckla inflytande och delaktighet i samhället. Med anledning av detta föreslogs bl.a. att pensionärsråden utvecklas så att rådens möjligheter att förmedla äldre människors kunskaper och erfarenheter tas till vara i alla berörda beslutsprocesser. Pensionärsråden kunde däremot inte kompensera bristen på äldre personer i politiskt valda församlingar i kommuner och landsting. Likaså borde andra typer av rådslag och dialoger prövas, t.ex. i forum där grupper med personer i olika åldrar i bostadsområden kan mötas. Skrivelsen behandlades av konstitutionsutskottet (bet. 2003/04:KU19) oc&lt;/span&gt;&lt;span&gt;h ledde i denna del inte till något&lt;/span&gt;&lt;span&gt; uttalande från utskottets sida.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Våren 2009 gjorde utskottet inte någon annan bedömning än den socialutskottet tidigare gjort och som riksdagen ställt sig bakom (bet. 2008/09:KU11). Senast utskottet behandlade motioner om obligatoriska pensionärsråd avstyrktes motionerna med hänvisning till &lt;/span&gt;&lt;span&gt;tidigare ställnings&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;taganden &lt;/span&gt;&lt;span&gt;(bet. &lt;/span&gt;&lt;span&gt;2012/13:KU22&lt;/span&gt;&lt;span&gt; och 2013/14:KU12&lt;/span&gt;&lt;span&gt;)&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Demokratiutredningen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;2014 å&lt;/span&gt;&lt;span&gt;rs demokratiutredning har haft&lt;/span&gt;&lt;span&gt; i uppdrag att utreda hur engagemanget inom den representativa demokratin kan öka och breddas och hur individens möjlig&lt;/span&gt;&lt;span&gt;heter till delaktighet i och in&lt;/span&gt;&lt;span&gt;flytande över det politiska beslutsfattandet mellan de allmänna valen kan stärkas.&lt;/span&gt;&lt;span&gt; I&lt;/span&gt;&lt;span&gt; betänkandet Låt fler forma framtiden! (SOU 2016:5)&lt;/span&gt;&lt;span&gt; föreslår utredningen bl.a.&lt;/span&gt;&lt;span&gt; att det ska framgå av kommunallagen att fullmäktige ska verka för att medlemmarna har förutsättningar att delta och framföra sina synpunkter inför beslut.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Med en sådan bestämmelse motiveras fullmäktige &lt;/span&gt;&lt;span&gt;enligt utredningen till &lt;/span&gt;&lt;span&gt;att stämma av och förankra beslut samtidigt so&lt;/span&gt;&lt;span&gt;m fullmäktige har ansvar för be&lt;/span&gt;&lt;span&gt;redningen och beslutsfattandet.&lt;/span&gt;&lt;span&gt; Den föreslagna b&lt;/span&gt;&lt;span&gt;estämmelsen är en målsättningsparagraf och ska &lt;/span&gt;&lt;span&gt;enligt utred&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;ningen &lt;/span&gt;&lt;span&gt;ses som en demokratisk princip. Det är fullmäktige som beslutar om hur medlemmarna ska kunna delta och framföra sina synpunkter och om vilka beslut som ska beredas med ett medborgerligt deltagande.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utredningen har gjort en&lt;/span&gt;&lt;span&gt; översyn &lt;/span&gt;&lt;span&gt;som &lt;/span&gt;&lt;span&gt;visar att en majoritet av kommunerna har medborgarråd av olika slag. Pen&lt;/span&gt;&lt;span&gt;sionärsråd, ungdomsråd och till&lt;/span&gt;&lt;span&gt;gänglig&lt;/span&gt;&lt;span&gt;&amp;#xad;&lt;/span&gt;&lt;span&gt;hetsråd är de vanligast förekommande. Även i landstingen är råd för sär&lt;/span&gt;&lt;span&gt;skilt utvalda medborgargrupper&lt;/span&gt;&lt;span&gt; vanligt förekommande.&lt;/span&gt;&lt;span&gt; Utredningen &lt;/span&gt;&lt;span&gt;anser att möjligheterna att utveckla råden i riktning mot mer effektiva och representativa organ förutsätter att formerna för medborgarråden regleras.&lt;/span&gt;&lt;span&gt; I utredningen konstateras att &lt;/span&gt;&lt;span&gt;en övervägande majoritet &lt;/span&gt;&lt;span&gt;av kommunerna och landstingen&lt;/span&gt;&lt;span&gt; redan har styrande dokument av det sl&lt;/span&gt;&lt;span&gt;ag som förordas. Utredningen&lt;/span&gt;&lt;span&gt; ser inget beho&lt;/span&gt;&lt;span&gt;v &lt;/span&gt;&lt;span&gt;av lagreglering i dessa frågor, me&lt;/span&gt;&lt;span&gt;n bedömer att fullmäktige i kom&lt;/span&gt;&lt;span&gt;munerna och landstingen själva bör reglera förekomsten, syftet och organiseringen av medborgarråd&lt;/span&gt;&lt;span&gt;en i ett styrdokument. Reglemen&lt;/span&gt;&lt;span&gt;ten bör&lt;/span&gt;&lt;span&gt; enligt utredningen&lt;/span&gt;&lt;span&gt; upprättas för alla typer av medborgarråd&lt;/span&gt;&lt;span&gt; (s. 439 f.)&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Demokratiutredningens förslag bereds &lt;/span&gt;&lt;span&gt;inom Regerings&lt;/span&gt;&lt;span&gt;kansliet.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet anser att de&lt;/span&gt;&lt;span&gt;n pågående beredningen av Demokratiutredningens förslag inte bör föregripas och avstyrker motionsyrkandena.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Avsnittsrubrik"&gt;
				&lt;a name="_Toc510603155"&gt;&lt;span class="tSidrubrikJA"&gt;Reservationer&lt;/span&gt;&lt;/a&gt;
