							&lt;a name="_Toc510603157"&gt;&lt;span style="font-family:'Verdana'; font-size:10.5pt; font-weight:bold"&gt;Representation i styrelsen, nämnder och utskott, punkt 3 (SD, -)&lt;/span&gt;&lt;/a&gt;
						&lt;/p&gt;
