			&lt;p class="Normalutanluftfre" style="margin-left:22pt; page-break-inside:avoid; page-break-after:avoid; -aw-sdt-tag:87da834a-074a-4ac1-8f20-f264520f89bc/reservationer/-713186777/1522238107002; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;av Fredrik Eriksson (SD) och Patrick Reslow (-).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4" style="-aw-sdt-tag:87da834a-074a-4ac1-8f20-f264520f89bc/reservationer/-713186777/1522238107002; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;Förslag till riksdagsbeslut&lt;/span&gt;
			&lt;/p&gt;
			&lt;p style="margin-bottom:3.1pt; -aw-sdt-tag:87da834a-074a-4ac1-8f20-f264520f89bc/reservationer/-713186777/1522238107002; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;Vi anser att förslaget till riksdagsbeslut under punkt 4 borde ha följande lydelse:&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="-aw-sdt-tag:87da834a-074a-4ac1-8f20-f264520f89bc/reservationer/-713186777/1522238107002; -aw-sdt-title:reservationer"&gt;
				&lt;span&gt;Riksdagen ställer sig bakom det som anförs i reservationen och tillkännager detta för regeringen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalutanluftfre" style="text-indent:11.3pt; -aw-sdt-tag:87da834a-074a-4ac1-8f20-f264520f89bc/reservationer/-713186777/1522238107002; -aw-sdt-title:reservationer"&gt;
