&lt;TR&gt;
	&lt;TD class="tr6 td57"&gt;&lt;SPAN class="p3 ft4"&gt;effekt är inte önskvärd.&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr6 td13"&gt;&lt;SPAN class="p3 ft9"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD class="tr4 td57"&gt;&lt;SPAN class="p70 ft4"&gt;Mot bakgrund av det anförda har utredningen kommit fram till att det&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr4 td13"&gt;&lt;SPAN class="p3 ft9"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD class="tr4 td57"&gt;&lt;SPAN class="p3 ft4"&gt;varken behövs eller är lämpligt att införa en obligatorisk&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr4 td13"&gt;&lt;SPAN class="p3 ft9"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
&lt;/TR&gt;
&lt;TR&gt;
	&lt;TD class="tr4 td57"&gt;&lt;SPAN class="p3 ft4"&gt;anmälningsskyldighet.&lt;/SPAN&gt; &lt;/TD&gt;
