	&lt;TD class="tr4 td91"&gt;&lt;SPAN class="p3 ft9"&gt;&amp;nbsp;&lt;/SPAN&gt; &lt;/TD&gt;
	&lt;TD class="tr4 td92"&gt;&lt;SPAN class="p324 ft4"&gt;11 §&lt;/SPAN&gt; &lt;/TD&gt;
