--&gt;&lt;/style&gt;

		&lt;div class="Section1"&gt;
			&lt;table cellspacing="0" cellpadding="0" style="border-collapse:collapse; margin-left:0pt"&gt;
				&lt;tr style="height:79.4pt"&gt;
					&lt;td style="vertical-align:top; width:297.7pt"&gt;
						&lt;p class="Rubrik1Dokumentinformation" style="margin-top:0pt; margin-bottom:0pt; text-align:left; page-break-inside:avoid; page-break-after:avoid; line-height:16pt"&gt;
							&lt;a name="_Hlk50621549"&gt;&lt;span style="font-family:'Verdana'; font-size:16pt; -aw-sdt-tag:ccUtskott; -aw-sdt-title:'utskottsnamn Dokumentegenskap'"&gt;Finansutskottet&lt;/span&gt;&lt;span style="font-family:'Verdana'; font-size:16pt; -aw-sdt-tag:ccS; -aw-sdt-title:s"&gt;s&lt;/span&gt;&lt;span style="font-family:'Verdana'; font-size:16pt; -aw-sdt-tag:ccMellanslag; -aw-sdt-title:Mellanslag"&gt; &lt;/span&gt;&lt;/a&gt;&lt;a name="Utlatande"&gt;&lt;/a&gt;&lt;span style="font-family:'Verdana'; font-size:16pt"&gt;betänkande&lt;/span&gt;
						&lt;/p&gt;
						&lt;p class="Dokumentbeteckning" style="margin-top:0pt; margin-bottom:0pt; text-align:left; page-break-inside:avoid; page-break-after:avoid; line-height:16pt"&gt;
							&lt;span style="font-family:'Verdana'; font-size:16pt; -aw-sdt-tag:ccRiksmote; -aw-sdt-title:'riksmote Dokumentegenskap'"&gt;2020/21&lt;/span&gt;&lt;span style="font-family:'Verdana'; font-size:16pt; -aw-sdt-tag:ccKolon; -aw-sdt-title:Kolon"&gt;:&lt;/span&gt;&lt;a name="Utskottebeteckning"&gt;&lt;/a&gt;&lt;span style="font-family:'Verdana'; font-size:16pt"&gt;FiU7&lt;/span&gt;&lt;span style="font-family:'Verdana'; font-size:16pt"&gt; &lt;/span&gt;
						&lt;/p&gt;
						&lt;p class="Rubrik1Dokumentinformation" style="margin-top:0pt; margin-bottom:0pt; text-align:left; page-break-inside:avoid; page-break-after:avoid; line-height:16pt"&gt;
							&lt;span style="font-family:'Verdana'; font-size:16pt"&gt;&amp;#xa0;&lt;/span&gt;
						&lt;/p&gt;
					&lt;/td&gt;
				&lt;/tr&gt;
			&lt;/table&gt;
			&lt;p class="DokumentRubrik" style="-aw-sdt-tag:ccDokumentrubrik; -aw-sdt-title:'dokumentrubrik Dokumentegenskap'"&gt;
				&lt;span&gt;Ändring i riksbankslagen till stöd för samarbete med internationella organ&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R2"&gt;
				&lt;span&gt;Sammanfattning&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utskottet föreslår att &lt;/span&gt;&lt;span&gt;r&lt;/span&gt;&lt;span&gt;iksdagen antar Riksbankens förslag till ändring i riksbankslagen&lt;/span&gt;&lt;span&gt; (1988:1385)&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;Ändringen ska träda i kraft den 1 november 2020. &lt;/span&gt;&lt;span&gt;Utskottet föreslår också att &lt;/span&gt;&lt;span&gt;r&lt;/span&gt;&lt;span&gt;iksdagen godkänner att Riksbanken under fem år och med högst 30 miljoner kronor per år delfinansierar ett innovationscentrum, en s.k. hubb, som Banken för internationell betalningsutjämning (&lt;/span&gt;&lt;span&gt;Bank for International Settlements, &lt;/span&gt;&lt;span&gt;BIS) avser att etablera i Sverige i samarbete med Riksbanken och centralbankerna i Danmark, Island och Norge.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;För att det ska bli möjligt att inrätta hubben bör riksdagen även tillkännage för regeringen att regeringen bör ingå ett värdlandsavtal med BIS &lt;/span&gt;&lt;span&gt;samt &lt;/span&gt;&lt;span&gt;återkomma till riksdagen med &lt;/span&gt;&lt;span&gt;ett förslag till &lt;/span&gt;&lt;span&gt;ändring i lagen (1976:661) om immunitet och privilegier. &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;BIS har beslutat att etablera sju hubbar runt&lt;/span&gt;&lt;span&gt; om&lt;/span&gt;&lt;span&gt; i världen för att främja internationellt samarbete kring innovativ finansiell teknik, s.k. fintech, som är &lt;/span&gt;&lt;span&gt;av intresse och &lt;/span&gt;&lt;span&gt;relevant för centralbankerna. Utskottet är positivt till att en av hubbarna etableras i Sverige. Utskottet anser dock att Riksbanken och BIS bör bjuda in tillsynsmyndigheterna i respektive land att delta i hubbens arbete för att tillvarata det arbete kring fintech och finansiella innovationer som utförs i myndigheterna och i samarbete mellan myndigheterna.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet föreslår att ärendet avgörs trots att det har varit tillgängligt kortare tid än två vardagar före den dag då det behandlas.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4"&gt;
				&lt;span&gt;Behandlade förslag&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
