				&lt;span&gt;Riksdagen&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;ställer sig&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;bakom det som utskottet anför om att regeringen ska ingå ett värdlandsavtal med Banken för internationell betalningsutjämning (BIS) till följd av att BIS etablerar ett innovationscentrum i Sverige, och&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;detta&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;tillkännager riksdagen för regeringen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalinskjutenindrag" style="text-indent:11.3pt; -aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1471354372/1600766678104'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;Därmed bifaller riksdagen framställning 2019/20:RB3 punkt 3.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1471354372/1600766678104'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;table cellspacing="0" cellpadding="0" style="border-collapse:collapse; margin-left:0pt; width:294.2pt"&gt;
