					&lt;td style="vertical-align:top; width:22pt"&gt;
						&lt;p style="margin-top:11pt; margin-bottom:0pt; text-align:justify; page-break-inside:avoid; page-break-after:avoid; line-height:12.5pt"&gt;
							&lt;span style="font-family:'Verdana'; font-size:10.5pt; font-weight:bold"&gt;4.&lt;/span&gt;
						&lt;/p&gt;
					&lt;/td&gt;
					&lt;td style="vertical-align:top; width:272.2pt"&gt;
						&lt;p style="margin-top:11pt; margin-bottom:0pt; text-align:justify; page-break-inside:avoid; page-break-after:avoid; line-height:12.5pt"&gt;
							&lt;span style="font-family:'Verdana'; font-size:10.5pt; font-weight:bold"&gt;Ändring i lagen (1976:66) om immunitet och privilegier&lt;/span&gt;
						&lt;/p&gt;
					&lt;/td&gt;
				&lt;/tr&gt;
			&lt;/table&gt;
			&lt;p class="Normalinskjuten" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1471354372/1600766678104'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;Riksdagen&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;ställer sig&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;bakom det som utskottet anför om att regeringen ska återkomma till riksdagen med förslag om ändring i lagen (1976:661) om immunitet och privilegier till följd av att Banken för internationell betalningsutjämning (BIS) etablerar ett innovationscentrum i Sverige, och detta&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;&lt;span&gt;tillkännager riksdagen för regeringen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Normalinskjutenindrag" style="text-indent:11.3pt; -aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1471354372/1600766678104'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;Därmed bifaller riksdagen framställning 2019/20:RB3 punkt 4.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1471354372/1600766678104'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p style="margin-top:18pt; margin-bottom:18pt; -aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1471354372/1600766678104'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;Utskottet föreslår att ärendet avgörs trots att det har varit tillgängligt kortare tid än två vardagar före den dag då det behandlas.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="OrtochDatum" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1471354372/1600766678104'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;Stockholm den 22 september 2020&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="PVgnar" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1471354372/1600766678104'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;På finansutskottets vägnar&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Ordfranden" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1471354372/1600766678104'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;Fredrik Olovsson&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Deltagare" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1471354372/1600766678104'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;Följande ledamöter har deltagit i beslutet: Fredrik Olovsson (S), Elisabeth Svantesson (M), Gunilla Carlsson (S), Edward Riedl (M), Oscar Sjöstedt (SD), Adnan Dibrani (S), Ulla Andersson (V), Dennis Dioukarev (SD), Ingela Nylund Watz (S), Jakob Forssmed (KD), Ingemar Nilsson (S), Mats Persson (L), Charlotte Quensel (SD), Karolina Skog (MP), Mattias Karlsson i Luleå (M), Sofia Westergren (M) och Rickard Nordin (C).&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1471354372/1600766678104'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1471354372/1600766678104'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:'dokumentavsnitt/utskottets förslag till riksdagsbeslut/1471354372/1600766678104'; -aw-sdt-title:'utskottets förslag till riksdagsbeslut'"&gt;
				&lt;span style="font-size:9.5pt"&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Avsnittsrubrik"&gt;
				&lt;a name="SlutUtskottsForslag"&gt;&lt;/a&gt;&lt;a name="_Toc50106954"&gt;&lt;span style="-aw-bookmark-end:SlutUtskottsForslag"&gt;&lt;/span&gt;&lt;span class="tSidrubrikJA"&gt;Redogörelse för ärendet&lt;/span&gt;&lt;/a&gt;
			&lt;/p&gt;
			&lt;p class="R2" style="margin-top:0pt"&gt;
				&lt;span&gt;Ärendet&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utvecklingen av tekniska finansiella innovationer går snabbt både internationellt och i Sverige. För att möta de utmaningar detta innebär och upprätthålla allmänna samhällspolitiska mål och bidra till effektiva och säkra finansiella tjänster &lt;/span&gt;&lt;span&gt;finns det behov av öka&lt;/span&gt;&lt;span&gt;t&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;samarbetet mellan centralbankerna runt om i världen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Under 2019 beslutade &lt;/span&gt;&lt;span&gt;Banken för internationell betalningsutjämning &lt;/span&gt;&lt;span&gt;(&lt;/span&gt;&lt;span&gt;BIS) att etablera tre innovationscentrum ‒ i Basel&lt;/span&gt;&lt;span&gt; (som ska fungera som huvudkontor för BIS Innovation Hub)&lt;/span&gt;&lt;span&gt;, Hongkong och Singapore i samarbete med respektive lands centralbank. Innovationscentrumen (eller hubbarna som de betecknas &lt;/span&gt;&lt;span&gt;på&lt;/span&gt;&lt;span&gt; BIS-språk) ska&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;fungera som&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;ett nav för nätverk av&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;experter inom innovation, för forskning om viktiga trender inom finansiell teknik&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;av betydelse för centralbanker och för att främja internationellt samarbete i syfte&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;att förbättra det globala finansiella systemets funktionssätt.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I samband med beslutet 2019 &lt;/span&gt;&lt;span&gt;meddelade&lt;/span&gt;&lt;span&gt; BIS att man inom &lt;/span&gt;&lt;span&gt;en snar framtid &lt;/span&gt;&lt;span&gt;skulle etabler&lt;/span&gt;&lt;span&gt;a&lt;/span&gt;&lt;span&gt; flera &lt;/span&gt;&lt;span&gt;nya &lt;/span&gt;&lt;span&gt;hubbar &lt;/span&gt;&lt;span&gt;på olika platser i världen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I början av mars lämnade Riksbanken en framställning till riksdagen (2019/20:RB3)&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;där man föreslog att &lt;/span&gt;&lt;span&gt;BIS skulle&lt;/span&gt;&lt;span&gt; få&lt;/span&gt;&lt;span&gt; etablera en av de nya hubbarna i Sverige. &lt;/span&gt;&lt;span&gt;E&lt;/span&gt;&lt;span&gt;n hubb i &lt;/span&gt;&lt;span&gt;Sverige i &lt;/span&gt;&lt;span&gt;samarbete &lt;/span&gt;&lt;span&gt;med &lt;/span&gt;&lt;span&gt;BIS kräver delfinansiering av Riksbanken&lt;/span&gt;&lt;span&gt;. I riksbankslagen finns i dagsläget inget stöd för Riksbanken att skjuta till medel eller på annat sätt finansiera andra institutioners drift av verksamhet i Sverige. Riksbanken försl&lt;/span&gt;&lt;span&gt;år&lt;/span&gt;&lt;span&gt; därför i framställningen att riksbankslagen ändra&lt;/span&gt;&lt;span&gt;s&lt;/span&gt;&lt;span&gt; så att det bl&lt;/span&gt;&lt;span&gt;ir&lt;/span&gt;&lt;span&gt; möjligt för Riksbanken att, efter riksdagens godkännande, finansiera &lt;/span&gt;&lt;span&gt;ett &lt;/span&gt;&lt;span&gt;internationell&lt;/span&gt;&lt;span&gt;t&lt;/span&gt;&lt;span&gt; organs verksamhet om denna har anknytning till Riksbanken&lt;/span&gt;&lt;span&gt;s verksamhet&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; Riksbanken för&lt;/span&gt;&lt;span&gt;eslår &lt;/span&gt;&lt;span&gt;även andra lagändringar för att möta BIS krav&lt;/span&gt;&lt;span&gt; på&lt;/span&gt;&lt;span&gt; immunitet och privilegier för personal som ska arbeta i hubben. &lt;/span&gt;&lt;span&gt;Under &lt;/span&gt;&lt;span&gt;Riksbankens &lt;/span&gt;&lt;span&gt;beredning av &lt;/span&gt;&lt;span&gt;ärendet &lt;/span&gt;&lt;span&gt;skickade banken ut ett utkast av framställningen till ett &lt;/span&gt;&lt;span&gt;fyrtio&lt;/span&gt;&lt;span&gt;tal remi&lt;/span&gt;&lt;span&gt;ssinstanser&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; Eventuella synpunkter från remissinstanserna framgår av framställning.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I mitten av mars 2020 skickade Riksbanken in en ansökan till BIS om att etablera en hubb i Stockholm. Ursprungligen var det tänkt att BIS skulle ta beslut om &lt;/span&gt;&lt;span&gt;de &lt;/span&gt;&lt;span&gt;nya hubbar&lt;/span&gt;&lt;span&gt;na&lt;/span&gt;&lt;span&gt; tidigt under våren 2020, men beslutet sköts upp bl.a. till följd av coronapandemin.&lt;/span&gt;&lt;span&gt; I avvaktan på ett beslut från BIS valde &lt;/span&gt;&lt;span&gt;f&lt;/span&gt;&lt;span&gt;inansutskottet att skjuta på beredningen av Riksbankens framställning.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I slutet av juni 2020 meddelade BIS att&lt;/span&gt;&lt;span&gt; man&lt;/span&gt;&lt;span&gt; beslutat att etablera fyra nya innovationscentrum under de kommande två åren, varav ett i S&lt;/span&gt;&lt;span&gt;tockholm&lt;/span&gt;&lt;span&gt; i samarbetet med Riksbanken och centralbankerna i Danmark, Island och Norge. De andra &lt;/span&gt;&lt;span&gt;ska&lt;/span&gt;&lt;span&gt; etableras&lt;/span&gt;&lt;span&gt; i&lt;/span&gt;&lt;span&gt; Toronto, Frankfurt/Paris och London.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;BIS &lt;/span&gt;&lt;span&gt;beslutade &lt;/span&gt;&lt;span&gt;samtidigt &lt;/span&gt;&lt;span&gt;att etablera ett strategiskt partnerskap med&lt;/span&gt;&lt;span&gt; den amerikanska centralbanken (The &lt;/span&gt;&lt;span&gt;Federal Reserve System&lt;/span&gt;&lt;span&gt;)&lt;/span&gt;&lt;span&gt; i New York.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I slutet av augusti 2020 höll utskottet slutna utfrågningar om Riksbankens förslag med bl.a. riksbankschefen Stefan Ingves och Finansinspektionens generaldirektör Erik Thed&lt;/span&gt;&lt;span&gt;éen&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Avsnittsrubrik"&gt;
				&lt;a name="_Toc50106955"&gt;&lt;span class="tSidrubrikJA"&gt;Utskottets överväganden&lt;/span&gt;&lt;/a&gt;
			&lt;/p&gt;
			&lt;h2 style="-aw-sdt-tag:07380d80-ad10-4440-a912-3be42e1cf217/förslagsrutor/-149827604/1597660737504; -aw-sdt-title:förslagsrutor"&gt;
				&lt;a name="_Toc50106956"&gt;&lt;span&gt;Ändring i riksbankslagen till stöd för samarbete med internationella organ&lt;/span&gt;&lt;/a&gt;
			&lt;/h2&gt;
			&lt;div style="border-bottom-color:#000000; border-bottom-style:solid; border-bottom-width:0.75pt; border-left-color:#000000; border-left-style:solid; border-left-width:0.75pt; border-right-color:#000000; border-right-style:solid; border-right-width:0.75pt; border-top-color:#000000; border-top-style:solid; border-top-width:0.75pt; clear:both; margin:3.1pt 0.9pt 0pt"&gt;
				&lt;p class="Normalrutafet" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span style="-aw-bookmark-end:_Toc50106956"&gt;&lt;/span&gt;&lt;span&gt;Utskottets förslag i korthet&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalruta" style="margin:0pt; padding-right:4pt; padding-left:4pt"&gt;
					&lt;span&gt;Riksdagen &lt;/span&gt;&lt;span&gt;antar Riksbankens förslag till ändring i riksbankslagen. Riksdagen godkänner också att Riksbanken under fem år och med högst 30 miljoner kronor per år delfinansierar ett innovationscentrum&lt;/span&gt;&lt;span&gt;, en s.k. hubb,&lt;/span&gt;&lt;span&gt; som Banken för internationell betalningsutjämning (BIS) avser att etablera i Sverige i samarbete med Riksbanken och centralbankerna i Danmark, Island och Norge.&lt;/span&gt;
				&lt;/p&gt;
				&lt;p class="Normalrutaindrag" style="margin:0pt; padding-right:4pt; padding-left:4pt; padding-bottom:4pt"&gt;
					&lt;span&gt;Riksdagen ställer &lt;/span&gt;&lt;span&gt;sig &lt;/span&gt;&lt;span&gt;också bakom &lt;/span&gt;&lt;span&gt;förslaget att regeringen ska ingå ett värdlandsavtal med BIS &lt;/span&gt;&lt;span&gt;samt&lt;/span&gt;&lt;span&gt; återkomma till riksdagen med&lt;/span&gt;&lt;span&gt; ett förslag till &lt;/span&gt;&lt;span&gt;ändring i lagen om immunitet och privilegier för att det ska bli möjligt att etablera hubben. &lt;/span&gt;&lt;span&gt;BIS har beslutat att etablera sju hubbar runt &lt;/span&gt;&lt;span&gt;om &lt;/span&gt;&lt;span&gt;i världen för att främja internationellt samarbete kring innovativ finansiell teknik&lt;/span&gt;&lt;span&gt;, s.k. fintech,&lt;/span&gt;&lt;span&gt; som är relevant för centralbankerna. Utskottet är positivt &lt;/span&gt;&lt;span&gt;till att en av hubbarna etableras i Sverige. Utskottet anser dock att Riksbanken och BIS bör bjuda in &lt;/span&gt;&lt;span&gt;tillsynsmyndigheterna i respektive land att delta i hubbens arbete för att tillvarata och utveckla det arbete kring fintech och finansiella innovatio&lt;/span&gt;&lt;span&gt;n&lt;/span&gt;&lt;span&gt;er som utförs i myndigheterna och i samarbete mellan myndigheterna.&lt;/span&gt;
				&lt;/p&gt;
			&lt;/div&gt;
			&lt;p class="Mellanrum"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;h3 style="margin-top:0pt"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/h3&gt;
			&lt;h3 style="margin-top:0pt"&gt;
				&lt;a name="_Toc50106957"&gt;&lt;span&gt;Sammanfattning av Riksbankens framställning&lt;/span&gt;&lt;/a&gt;
			&lt;/h3&gt;
			&lt;p class="R4" style="margin-top:6pt; margin-bottom:0pt"&gt;
				&lt;span&gt;Riksbanken vill att BIS etablerar &lt;/span&gt;&lt;span&gt;ett innovationscentrum i Sverige&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Utvecklingen av tekniska finansiella innovationer går snabbt både internationellt och i Sverige. Det ökar behovet av samarbete mellan världens centralbanker för att förstå vil&lt;/span&gt;&lt;span&gt;ka&lt;/span&gt;&lt;span&gt; risker och möjligheter teknikskiftet innebär och vilka åtgärder &lt;/span&gt;&lt;span&gt;som eventuellt behöver vidtas &lt;/span&gt;&lt;span&gt;för att &lt;/span&gt;&lt;span&gt;upprätthålla allmänna samhällspolitiska mål och tillhandahålla effektiva och säkra finansiella tjänster.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Ba&lt;/span&gt;&lt;span&gt;nken för internationell betalningsutjämning (BIS) tog under 2019 initiativ till ett globalt samarbete genom att etablera tre regionala innovationscentr&lt;/span&gt;&lt;span&gt;um &lt;/span&gt;&lt;span&gt;(hubbar) &lt;/span&gt;&lt;span&gt;– &lt;/span&gt;&lt;span&gt;i &lt;/span&gt;&lt;span&gt;Basel, Hon&lt;/span&gt;&lt;span&gt;g&lt;/span&gt;&lt;span&gt;kong och Singapore i samarbete med respektive lands centralbank. Samtidig annonserades att &lt;/span&gt;&lt;span&gt;flera nya hubbar &lt;/span&gt;&lt;span&gt;skulle etableras in&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;om en snar framtid.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Riksbanken anger i framställningen att de vill ansöka om att BIS utser Sverige&lt;/span&gt;&lt;span&gt; och Riksbanken&lt;/span&gt;&lt;span&gt; som värd för &lt;/span&gt;&lt;span&gt;en ny &lt;/span&gt;&lt;span&gt;innovations&lt;/span&gt;&lt;span&gt;hubb&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;En etablering av e&lt;/span&gt;&lt;span&gt;n hubb &lt;/span&gt;&lt;span&gt;i Sverige skulle enligt Riksbanken innebära ett stort erkännande av &lt;/span&gt;&lt;span&gt;Sverige som en framstående innovationsnation och ytterligare stärka Sveriges internationella dragningskraft. Det skulle vara värdefullt för svensk ekonomi och i synnerhet för den fortsatta utvecklingen av &lt;/span&gt;&lt;span&gt;den svenska &lt;/span&gt;&lt;span&gt;fintechsektorn. E&lt;/span&gt;&lt;span&gt;n hubb &lt;/span&gt;&lt;span&gt;i Sverige borde&lt;/span&gt;&lt;span&gt; enligt Riksbanken&lt;/span&gt;&lt;span&gt; representera de nordeuropeiska länder&lt;/span&gt;&lt;span&gt;na&lt;/span&gt;&lt;span&gt; vilket&lt;/span&gt;&lt;span&gt; bl.a.&lt;/span&gt;&lt;span&gt; skulle &lt;/span&gt;&lt;span&gt;innebär&lt;/span&gt;&lt;span&gt;a&lt;/span&gt;&lt;span&gt; att &lt;/span&gt;&lt;span&gt;regionen &lt;/span&gt;&lt;span&gt;blir &lt;/span&gt;&lt;span&gt;viktigare för BIS i framtiden.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4" style="margin-top:6pt; margin-bottom:0pt"&gt;
				&lt;span&gt;Vilket uppdrag har &lt;/span&gt;&lt;span&gt;BIS &lt;/span&gt;&lt;span&gt;innovationscentrum?&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;H&lt;/span&gt;&lt;span&gt;ubbarna ska enligt BIS främja internationellt samarbete kring innovativ finansiell teknik som är relevant för centralbankerna. Genom &lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt; fokusering på forskning kan det internationella finansiella systemets funktion och effektivitet och centralbankernas &lt;/span&gt;&lt;span&gt;förmåga&lt;/span&gt;&lt;span&gt; att hantera innovationerna förbättras.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I h&lt;/span&gt;&lt;span&gt;ubbarna&lt;/span&gt;&lt;span&gt;s&lt;/span&gt;&lt;span&gt; uppdrag &lt;/span&gt;&lt;span&gt;ingår &lt;/span&gt;&lt;span&gt;bl.a&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; att&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Punktlistabomb" style="margin-left:14.2pt; margin-bottom:0pt; text-indent:-14.2pt"&gt;
				&lt;span style="font-family:'Verdana'; font-size:10pt"&gt;•&lt;/span&gt;&lt;span style="font:7.0pt 'Verdana'"&gt;&amp;#xa0;&amp;#xa0;&amp;#xa0;&amp;#xa0;&amp;#xa0;&amp;#xa0; &lt;/span&gt;&lt;span&gt;strukturera och systematiskt identifiera kritiska trender inom teknik som påverkar centralbanker och utveckla djupgående analyser och insikter om dessa tekniker&lt;/span&gt;&lt;span&gt;,&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Punktlistabomb" style="margin-top:0pt; margin-left:14.2pt; margin-bottom:0pt; text-indent:-14.2pt"&gt;
				&lt;span style="font-family:'Verdana'; font-size:10pt"&gt;•&lt;/span&gt;&lt;span style="font:7.0pt 'Verdana'"&gt;&amp;#xa0;&amp;#xa0;&amp;#xa0;&amp;#xa0;&amp;#xa0;&amp;#xa0; &lt;/span&gt;&lt;span&gt;utveckla kollektiva nyttigheter utifrån tekn&lt;/span&gt;&lt;span&gt;ik&lt;/span&gt;&lt;span&gt;förändringar inrikta&lt;/span&gt;&lt;span&gt;de&lt;/span&gt;&lt;span&gt; på att förbättra funktionen i det globala finansiella systemet&lt;/span&gt;&lt;span&gt;,&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Punktlistabomb" style="margin-top:0pt; margin-left:14.2pt; text-indent:-14.2pt"&gt;
				&lt;span style="font-family:'Verdana'; font-size:10pt"&gt;•&lt;/span&gt;&lt;span style="font:7.0pt 'Verdana'"&gt;&amp;#xa0;&amp;#xa0;&amp;#xa0;&amp;#xa0;&amp;#xa0;&amp;#xa0; &lt;/span&gt;&lt;span&gt;vara samlingspunkt för ett nätverk av centralbanksexperter på innovation, &lt;/span&gt;&lt;span&gt;med regelbundna evenemang för att främja åsiktsutbyte och kunskapsdelning&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Huvud&lt;/span&gt;&lt;span&gt;sekretariatet&lt;/span&gt;&lt;span&gt; för innovations&lt;/span&gt;&lt;span&gt;hubbarna &lt;/span&gt;&lt;span&gt;är placera&lt;/span&gt;&lt;span&gt;t&lt;/span&gt;&lt;span&gt; i Basel&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; BIS styrelse ansvarar för resurstilldelning till hubbarna och BIS Ekonomiska konsultativa kommitté (ECC) ansvarar för hubbarnas övergripande strategi och prioriteringar. Till det finns det en rådgivande kommitté som granskar och diskuterar hubbarnas arbete. Varje hubb ska ha en verkställande chef.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4" style="margin-top:6pt; margin-bottom:0pt"&gt;
				&lt;span&gt;Vilka frågor skulle ett svenskt innovationscentrum arbeta med?&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;Riksbanken föreslår att en svensk hubb bör arbeta med och analysera frågor om &lt;/span&gt;&lt;span&gt;hur &lt;/span&gt;&lt;span&gt;förtroende&lt;/span&gt;&lt;span&gt;t&lt;/span&gt;&lt;span&gt; för pengar upprätthålls samt hur man kan behålla motståndskraften &lt;/span&gt;&lt;span&gt;och konkurrensen på betalningsmarknaden i den digitala eran.&lt;/span&gt;&lt;span&gt; Riksbankens arbete och analyser av digitala pengar har väckt stor uppmärksamhet internationellt och &lt;/span&gt;&lt;span&gt;det &lt;/span&gt;&lt;span&gt;innebär enligt Riksbanken att banken har en komparativ fördel jämfört med andra centralbanker&lt;/span&gt;&lt;span&gt; i dessa frågor&lt;/span&gt;&lt;span&gt;. Riksbanken förslår att &lt;/span&gt;&lt;span&gt;en &lt;/span&gt;&lt;span&gt;svensk hubb &lt;/span&gt;&lt;span&gt;även &lt;/span&gt;&lt;span&gt;bör arbeta med tekniska lösningar och en färdplan för att möjliggöra realtidsbetalningar över nationsgränser.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I framställningen framhålls dock &lt;/span&gt;&lt;span&gt;att &lt;/span&gt;&lt;span&gt;uppgifterna för en hubb bestäms av BIS. Värdlandet kan inte själv&lt;/span&gt;&lt;span&gt;t&lt;/span&gt;&lt;span&gt; bestämma inriktning, utan endast framföra förslag på vad hubben skulle kunna arbeta med.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4" style="margin-top:6pt; margin-bottom:0pt"&gt;
				&lt;span&gt;Vad skulle ett svenskt innovationscentrum kosta?&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;En svensk hubb skulle för Riksbankens del kosta högst 30 miljoner kronor per år under en femårsperiod. I den summan ingår kostnaden för heltidsanställda, &lt;/span&gt;&lt;span&gt;tillfällig personal&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;och andra kontraktsbaserade anställda samt kostnaden för &lt;/span&gt;&lt;span&gt;lokaler, &lt;/span&gt;&lt;span&gt;it&lt;/span&gt;&lt;span&gt;, säkerhet etc. Beloppet kompletteras med finansiering från BIS. Enligt Riksbanken motsvarar 30 miljoner&lt;/span&gt;&lt;span&gt; kronor&lt;/span&gt;&lt;span&gt; per år ungefär &lt;/span&gt;&lt;span&gt;3&lt;/span&gt;&lt;span&gt; procent av Riksbankens budgeterade förvaltningskostnader eller cirka hälften av den årliga utdelning som Riksbanken normalt får från sitt aktieinnehav i BIS.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R4" style="margin-top:6pt"&gt;
				&lt;span&gt;Ett &lt;/span&gt;&lt;span&gt;svenskt &lt;/span&gt;&lt;span&gt;innovationscentrum i samarbete med BIS kräver bl.a. ändring &lt;/span&gt;&lt;span&gt;i&lt;/span&gt;&lt;span&gt; riksbankslagen&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt; &lt;/span&gt;&lt;span&gt;Riksbanken får endast bedriva eller ta del i sådan verksamhet som enligt lag &lt;/span&gt;&lt;span&gt;är &lt;/span&gt;&lt;span&gt;Riksbanken&lt;/span&gt;&lt;span&gt;s uppgift&lt;/span&gt;&lt;span&gt;. &lt;/span&gt;&lt;span&gt;Det saknas stöd i riksbankslagen&lt;/span&gt;&lt;span&gt; för Riksbanken att skjuta till medel eller på annat sätt finansiera andra institutioners, t.ex. internationella organs, verksamhet i Sverige.&lt;/span&gt;&lt;span&gt; Enligt 8 kap. 2 § riksbankslagen får Riksbanken inom ramen för sina uppgifter förvärva aktier, andelar i ekonomiska föreningar och liknande rättigheter och ta på sig de förpliktelser som är förenade med dessa rättigheter. Paragrafen är tillämplig på förvärvand&lt;/span&gt;&lt;span&gt;et&lt;/span&gt;&lt;span&gt; av &lt;/span&gt;&lt;span&gt;Riksbankens &lt;/span&gt;&lt;span&gt;aktier och ägande i t.ex. BIS&lt;/span&gt;&lt;span&gt;, men omfattar inte &lt;/span&gt;&lt;span&gt;en &lt;/span&gt;&lt;span&gt;särskild finansiering för inrättandet av en innovationshubb i Sverige.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Riksbanken föreslår därför i framställningen att det i riksbankslagen införs en bestämmelse som anger att Riksbanken, efter riksdagens godkännande, får finansiera &lt;/span&gt;&lt;span&gt;ett &lt;/span&gt;&lt;span&gt;internationell&lt;/span&gt;&lt;span&gt;t&lt;/span&gt;&lt;span&gt; organs verksamhet om denna har anknytning till &lt;/span&gt;&lt;span&gt;R&lt;/span&gt;&lt;span&gt;iksbankens verksamhet. Riksbanken anser att den nya bestämmelsen bör vara allmänt formulerad och inte begränsas till enbart inrättandet av BIS innovationshubb i Sverige eftersom det i framtiden kan uppstå behov av samverkan inom andra områden inklusive sådan verksamhet &lt;/span&gt;&lt;span&gt;som är placerad utanför Sverige.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;För att en innovationshubb ska kunna etableras i Sverige eller i en annan region ställer BIS krav på immunitet för personal som arbetar i hubben. För att tillmötesgå BIS krav föreslår Riksbanken att regeringen ingår ett s.k. värdlandsavtal med BIS &lt;/span&gt;&lt;span&gt;samt&lt;/span&gt;&lt;span&gt; att lagen (1976:661) om immunitet och privilegier ändras så att BIS &lt;/span&gt;&lt;span&gt;anges i bilagan över internationella organisationer som åtnjuter immunitet i Sverige.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="R3"&gt;
				&lt;span&gt;Ytterligare information&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;I mitten av mars 2020, omkring två veckor efter att Riksbanken lämnat sin framställning till riksdagen, skickade Riksbanken in en ansökan till BIS om att etablera en av de nya hubbarna i S&lt;/span&gt;&lt;span&gt;verige&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Ursprungligen var det tänkt att BIS skulle ta beslut om nya hubbar tidigt under våren 2020, men beslutet sköts upp bl.a. till följd av effekterna av coronapandemin. I avvaktan på ett beslut från BIS valde finansutskottet att skjuta på beredningen av Riksbankens framställning.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;I slutet av juni 2020 meddelade BIS att man beslutat att etablera fyra nya innovations&lt;/span&gt;&lt;span&gt;hubbar&lt;/span&gt;&lt;span&gt; under de kommande två åren, varav e&lt;/span&gt;&lt;span&gt;n&lt;/span&gt;&lt;span&gt; i Stockholm i samarbetet med Riksbanken och centralbankerna i Danmark, Island och Norge. &lt;/span&gt;&lt;span&gt;Två hubbar ska &lt;/span&gt;&lt;span&gt;etableras&lt;/span&gt;&lt;span&gt; i&lt;/span&gt;&lt;span&gt; Toronto&lt;/span&gt;&lt;span&gt; respektive London i samarbete med respektive lands centralbank och en i &lt;/span&gt;&lt;span&gt;Frankfurt/Paris &lt;/span&gt;&lt;span&gt;i samarbete med &lt;/span&gt;&lt;span&gt;Europeiska centralbanken (ECB). &lt;/span&gt;&lt;span&gt;Dessutom beslutade BIS att etablera ett strategiskt partnerskap med &lt;/span&gt;&lt;span&gt;den amerikanska centralbanken&lt;/span&gt;&lt;span&gt; i New York.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Vilka hubbar som ska etableras under det första året och vilka som ska etableras under det andra året framgår inte av BIS beslut i juni.&lt;/span&gt;
			&lt;/p&gt;
			&lt;h3&gt;
				&lt;a name="_Toc50106958"&gt;&lt;span&gt;Utskottets ställningstagande&lt;/span&gt;&lt;/a&gt;
			&lt;/h3&gt;
			&lt;p&gt;
				&lt;span&gt;Banken för internationell betalningsutjämning (BIS) beslutade i slutet av juni 2020 att etablera en s.k. innovationshubb i Stockholm i samarbete med och delfinansierat av Riksbanken.&lt;/span&gt;&lt;span&gt; Syftet med hubben, som är en av flera hubbar som BIS &lt;/span&gt;&lt;span&gt;nu &lt;/span&gt;&lt;span&gt;etablerar &lt;/span&gt;&lt;span&gt;runt om i &lt;/span&gt;&lt;span&gt;världen,&lt;/span&gt;&lt;span&gt; är att främja internationellt samarbete kring innovativ finansiell teknik (s.k. fintech) som är relevant för centralbankerna för att förbättra det internationella finansiella systemets funktion och effektivitet och centralbankernas förmåga att hantera innovationerna.&lt;/span&gt;&lt;span&gt; Hubben ska etableras i samarbete mellan Riksbanken &lt;/span&gt;&lt;span&gt;och centralbankerna i Danmark, Island och Norge.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;En e&lt;/span&gt;&lt;span&gt;tablering&lt;/span&gt;&lt;span&gt; i Sverige delfinansiera&lt;/span&gt;&lt;span&gt;d&lt;/span&gt;&lt;span&gt; av &lt;/span&gt;&lt;span&gt;R&lt;/span&gt;&lt;span&gt;iksbanken&lt;/span&gt;&lt;span&gt; kräver en ändring &lt;/span&gt;&lt;span&gt;i&lt;/span&gt;&lt;span&gt; riksbankslagen, ett godkännande av riksdagen&lt;/span&gt;&lt;span&gt;, ett värdlandsavtal med BIS&lt;/span&gt;&lt;span&gt; och&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;ändringar i lagen&lt;/span&gt;&lt;span&gt; (1976:661) om immunitet och privilegier i vissa fall.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet är positivt&lt;/span&gt;&lt;span&gt; inställt&lt;/span&gt;&lt;span&gt; till att &lt;/span&gt;&lt;span&gt;det etableras &lt;/span&gt;&lt;span&gt;en innovationshubb i Sverige. De finansiella innovationerna utvecklas snabbt och &lt;/span&gt;&lt;span&gt;det finns &lt;/span&gt;&lt;span&gt;enligt utskottet &lt;/span&gt;&lt;span&gt;ett behov av att &lt;/span&gt;&lt;span&gt;analysera och &lt;/span&gt;&lt;span&gt;förstå &lt;/span&gt;&lt;span&gt;h&lt;/span&gt;&lt;span&gt;ur utvecklingen påverkar de finansiella marknaderna och samhället i stort. &lt;/span&gt;&lt;span&gt;Samtidigt vill utskottet &lt;/span&gt;&lt;span&gt;framhålla att det handlar om en ganska omfattande satsning som s&lt;/span&gt;&lt;span&gt;ka ställas mot andra &lt;/span&gt;&lt;span&gt;viktiga &lt;/span&gt;&lt;span&gt;behov. Riksbanken uppskattar kostnaden&lt;/span&gt;&lt;span&gt; för Riksbanken&lt;/span&gt;&lt;span&gt; till högst 30 miljoner kronor per år i fem år, dvs. totalt högst 150 miljoner kronor under en femårsperiod.&lt;/span&gt;&lt;span&gt; Riksbankens kostnader för verksamheten i hubben ska enligt uppgift från Riksbanken delas mellan Riksbanken och BIS enligt &lt;/span&gt;&lt;span&gt;procentfördelningen &lt;/span&gt;&lt;span&gt;60/40. Övriga centralbanker&lt;/span&gt;&lt;span&gt; i samarbetet&lt;/span&gt;&lt;span&gt; står&lt;/span&gt;&lt;span&gt; ensamma&lt;/span&gt;&lt;span&gt; för kostnaden för den personal de deltar med i hubben&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet &lt;/span&gt;&lt;span&gt;bedömer &lt;/span&gt;&lt;span&gt;att &lt;/span&gt;&lt;span&gt;detta är en befogad satsning&lt;/span&gt;&lt;span&gt; eftersom det handlar om ett område som utveckl&lt;/span&gt;&lt;span&gt;as snabbt&lt;/span&gt;&lt;span&gt; och där &lt;/span&gt;&lt;span&gt;olika &lt;/span&gt;&lt;span&gt;teknik&lt;/span&gt;&lt;span&gt;förändringar &lt;/span&gt;&lt;span&gt;kan &lt;/span&gt;&lt;span&gt;få&lt;/span&gt;&lt;span&gt; stor effekt på betalningssystemen, marknaderna och samhällsekonomin&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;En hubb &lt;/span&gt;&lt;span&gt;i Sverige &lt;/span&gt;&lt;span&gt;kan också bidra till att stärka Sveriges&lt;/span&gt;&lt;span&gt; och den svenska fintech&lt;/span&gt;&lt;span&gt;sektorns&lt;/span&gt;&lt;span&gt; ställning inom området&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Utskottet &lt;/span&gt;&lt;span&gt;konstaterar att den verksamhet som är &lt;/span&gt;&lt;span&gt;tänkt att &lt;/span&gt;&lt;span&gt;bedrivas&lt;/span&gt;&lt;span&gt; inom hubb&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;kommer att &lt;/span&gt;&lt;span&gt;beröra&lt;/span&gt;&lt;span&gt; frågor som rör regelgivning och tillsyn av de finansiella marknaderna&lt;/span&gt;&lt;span&gt; och de finansiella företagen&lt;/span&gt;&lt;span&gt;. Därför är det, enligt utskottet, viktigt och högst befogat att Riksbanken och BIS bjuder &lt;/span&gt;&lt;span&gt;in &lt;/span&gt;&lt;span&gt;tillsynsmyndigheterna&lt;/span&gt;&lt;span&gt; i respektive land att delta i hubbens arbete,&lt;/span&gt;&lt;span&gt; i&lt;/span&gt;&lt;span&gt;nte minst för att tillvarata och utveckla det arbete kring fintech&lt;/span&gt;&lt;span&gt; och finansiella innovationer som utförs i tillsynsmyndigheter och i samarbete mellan &lt;/span&gt;&lt;span&gt;tillsyns&lt;/span&gt;&lt;span&gt;myndigheterna. &lt;/span&gt;&lt;span&gt;Det kan&lt;/span&gt;&lt;span&gt;, enligt utskottet,&lt;/span&gt;&lt;span&gt; också finnas anledning att bjuda in andra viktiga myndigheter inom området att delta i arbetet.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Finansinspektionen &lt;/span&gt;&lt;span&gt;ifrågasätter i sitt remissvar på Riksbankens framställning om finansiering&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt; av hubb&lt;/span&gt;&lt;span&gt;en&lt;/span&gt;&lt;span&gt; är förenlig med EU:s &lt;/span&gt;&lt;span&gt;regler &lt;/span&gt;&lt;span&gt;mot s.k. monetär finansiering.&lt;/span&gt;&lt;span&gt; Reglerna förbjuder centralbankerna i EU att finansiera den offentliga sektorns verksamhet och åtagande gentemot tredje parter&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;såvida inte verksamheten ingår i centralbankens &lt;/span&gt;&lt;span&gt;ordinarie &lt;/span&gt;&lt;span&gt;uppgifter. &lt;/span&gt;&lt;span&gt;Efter en genomgång av regelverket är det u&lt;/span&gt;&lt;span&gt;tskottets uppfattning att &lt;/span&gt;&lt;span&gt;en finansiering av hubben inte strider mot förbudet mot monetär finansiering bl.a. eftersom den verksamhet som &lt;/span&gt;&lt;span&gt;kommer att bedrivas i &lt;/span&gt;&lt;span&gt;hubben ligger inom ramen för Riksbankens uppgifter. Utskottet kan i det&lt;/span&gt;&lt;span&gt;ta &lt;/span&gt;&lt;span&gt;sammanhang även konstatera att ECB inte tar upp frågan om monetär finansiering i sitt remissvar på Riksbankens framställning samt att ECB&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;själva &lt;/span&gt;&lt;span&gt;är en av &lt;/span&gt;&lt;span&gt;de &lt;/span&gt;&lt;span&gt;fyra centralbanker som under de kommande två åren &lt;/span&gt;&lt;span&gt;kommer att etablera en hubb i samarbete med BIS.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Riksbanken föreslår i framställningen att den svenska hubben skulle kunna arbeta med forskning och analyser kring hur man upprätthåller förtroendet för pengar och hur man behåller motståndskraften och konkurrensen på betalningsmarknaden i den digitala eran&lt;/span&gt;&lt;span&gt;, inklusive analyser kring digitala centralbankspengar och lösningar för realtidsbetalningar över nationsgränser. &lt;/span&gt;&lt;span&gt;Ytterst är det BIS som bestämmer vilken inriktning de olika hubbarna ska ha. Utskottet anser att Riksbankens förslag till inriktning är väl genomtänkt&lt;/span&gt;&lt;span&gt; och &lt;/span&gt;&lt;span&gt;relevant &lt;/span&gt;&lt;span&gt;och &lt;/span&gt;&lt;span&gt;att &lt;/span&gt;&lt;span&gt;förslaget ligger &lt;/span&gt;&lt;span&gt;in&lt;/span&gt;&lt;span&gt;om &lt;/span&gt;&lt;span&gt;ett område &lt;/span&gt;&lt;span&gt;där R&lt;/span&gt;&lt;span&gt;iksbanken &lt;/span&gt;&lt;span&gt;har en särskild &lt;/span&gt;&lt;span&gt;kunskap och kompetens&lt;/span&gt;&lt;span&gt;.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;Utskottet utgår därför från att BIS tar fast på detta och att arbetet i hubben i Sverige kommer att ligga i linje med Riksbankens förslag.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span&gt;Med det som sagts tillstyrker utskottet Riksbankens förslag till ändring i riksbankslagen. Utskottet tillstyrker också att riksdagen godkänner att Riksbanken delfinansierar ett innovationscentrum i BIS regi under &lt;/span&gt;&lt;span&gt;fem&lt;/span&gt;&lt;span&gt; år med högst 30 miljoner kronor per år. För att det ska bli möjligt att etablera en BIS-hubb i Sverige bör regeringen ingå ett värdlandsavtal med BIS och återkomma till riksdagen med förslag till ändring i lagen om immunitet och privilegier. Detta bör riksdagen ge regeringen till känna.&lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;  &lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt;  &lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt; &lt;/span&gt;&lt;span&gt; &lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Bilaga"&gt;
				&lt;span class="tBilagaJA"&gt;Bilaga 1&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Bilagerubrik"&gt;
				&lt;a name="_Toc50106959"&gt;&lt;span class="tSidrubrikJA"&gt;Förteckning över behandlade förslag&lt;/span&gt;&lt;/a&gt;
			&lt;/p&gt;
			&lt;p class="Rubrik2bilaga" style="-aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-2119925028/1587738540971'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;a name="_Toc50106960"&gt;&lt;span&gt;Framställningen&lt;/span&gt;&lt;/a&gt;&lt;span&gt; &lt;/span&gt;
			&lt;/p&gt;
			&lt;h4 style="-aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-2119925028/1587738540971'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;Framställning 2019/20:RB3 Förslag till ändring i lagen (1988:1385) om Sveriges riksbank till stöd för samarbete med internationella organ:&lt;/span&gt;
			&lt;/h4&gt;
			&lt;p class="Yrkandelista" style="margin-bottom:0pt; -aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-2119925028/1587738540971'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;1.&lt;/span&gt;&lt;span style="width:21.22pt; text-indent:0pt; display:inline-block"&gt;&lt;/span&gt;&lt;span&gt;Riksdagen antar Riksbankens förslag till lag om ändring i lagen (1988:1385) om Sveriges riksbank.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Yrkandelista" style="margin-top:0pt; margin-bottom:0pt; -aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-2119925028/1587738540971'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;2.&lt;/span&gt;&lt;span style="width:21.22pt; text-indent:0pt; display:inline-block"&gt;&lt;/span&gt;&lt;span&gt;Riksdagen godkänner att Riksbanken, under fem år och med högst 30 miljoner kronor per år, får finansiera sådan verksamhet som Banken för internationell betalningsutjämnings (Bank for International Settlements, BIS) bedriver från en i Sverige inrättad innovationshubb, om BIS väljer att etablera sig i Sverige.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Yrkandelista" style="margin-top:0pt; margin-bottom:0pt; -aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-2119925028/1587738540971'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;3.&lt;/span&gt;&lt;span style="width:21.22pt; text-indent:0pt; display:inline-block"&gt;&lt;/span&gt;&lt;span&gt;Riksdagen ställer sig bakom det som Riksbanken anför om att regeringen bör ingå ett värdlandsavtal med BIS och tillkännager detta för regeringen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Yrkandelista" style="margin-top:0pt; -aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-2119925028/1587738540971'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;4.&lt;/span&gt;&lt;span style="width:21.22pt; text-indent:0pt; display:inline-block"&gt;&lt;/span&gt;&lt;span&gt;Riksdagen ställer sig bakom det som Riksbanken anför om att regeringen ska återkomma till riksdagen med förslag till lag om ändring i lagen (1976:661) om immunitet och privilegier i vissa fall och tillkännager detta för regeringen.&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Mellanrum" style="-aw-sdt-tag:'dokumentavsnitt/förteckning över behandlade förslag/-2119925028/1587738540971'; -aw-sdt-title:'förteckning över behandlade förslag'"&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Bilaga"&gt;
				&lt;span class="tBilagaJA"&gt;Bilaga 2&lt;/span&gt;
			&lt;/p&gt;
			&lt;p class="Bilagerubrik"&gt;
				&lt;a name="_Toc50106961"&gt;&lt;span class="tSidrubrikJA"&gt;R&lt;/span&gt;&lt;span class="tSidrubrikJA"&gt;iksbankens&lt;/span&gt;&lt;span class="tSidrubrikJA"&gt; lagförslag&lt;/span&gt;&lt;/a&gt;
			&lt;/p&gt;
			&lt;p&gt;
				&lt;img src="https://data.riksdagen.se/fil/H801FiU7/Dokument.001.png" width="394" height="560" alt="" style="-aw-left-pos:0pt; -aw-rel-hpos:column; -aw-rel-vpos:paragraph; -aw-top-pos:0pt; -aw-wrap-type:inline" /&gt;
			&lt;/p&gt;
			&lt;p class="NormalIndent"&gt;
				&lt;span style="-aw-bookmark-end:_Hlk50621549"&gt;&lt;/span&gt;&lt;span&gt;&amp;#xa0;&lt;/span&gt;
			&lt;/p&gt;
